// Serialization implementation
impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        use serde::ser::SerializeStruct;
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?;
        state.end()
    }
}

impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::Variant1 { field1 } => {
                use serde::ser::SerializeStruct;
                let mut state = serializer.serialize_struct("Variant1", 1)?;
                state.serialize_field("field1", field1)?;
                state.end()
            }
            B::Variant2 { field2 } => {
                use serde::ser::SerializeStruct;
                let mut state = serializer.serialize_struct("Variant2", 1)?;
                state.serialize_field("field2", field2)?;
                state.end()
            }
        }
    }
