                        Ok(B::Variant1 { field1 })
                    }
                    "Variant2" => {
                        let mut field2: Option<i32> = None;

                        while let Some(key) = map.next_key::<String>()? {
                            match key.as_str() {
                                "field2" => {
                                    if field2.is_some() {
