use std::sync::{Arc, Mutex};

fn main() {
    // Example nested vector with varying inner vector sizes
    let a: Vec<Vec<usize>> = vec![        vec![1, 2, 3, 4],
        vec![5, 6],
        vec![7, 8, 9],
        vec![10],
        vec![11, 12, 13, 14, 15],
    ];

    println!("Original nested vector:");
    for (i, inner) in a.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    // ===========================================
    // Method 1: Elegant nested parallel processing
    // ===========================================
    println!("\nMethod 1: Nested parallel processing");
    let processed_1 = process_nested_parallel(&a, |x| x * 2);

    for (i, inner) in processed_1.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    // ===========================================
    // Method 2: Flatten-process-reshape approach
    // ===========================================
    println!("\nMethod 2: Flatten-process-reshape");
    let processed_2 = process_flatten_reshape(&a, |x| x * 3);

    for (i, inner) in processed_2.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    // ===========================================
    // Method 3: More complex example with strings
    // ===========================================
    println!("\nMethod 3: Complex transformation to strings");
    let processed_3 = process_nested_parallel(&a, |x| format!("Value: {}", x * x));

    for (i, inner) in processed_3.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }
}

/// Method 1: Apply function to each element while preserving nested structure
/// Uses nested parallel iterators for optimal parallelization
fn process_nested_parallel<F, T, R>(nested_vec: &Vec<Vec<T>>, func: F) -> Vec<Vec<R>>
where
    F: Fn(&T) -> R + Sync + Send,
    T: Send + Sync,
    R: Send,
{
    nested_vec
        .par_iter()  // Process outer vector in parallel
        .map(|inner_vec| {
            inner_vec
                .par_iter()  // Process inner vector in parallel
                .map(&func)
                .collect()
        })
        .collect()
}

/// Method 2: Flatten, process, then reshape back to original structure
/// Can be more efficient for certain operations
fn process_flatten_reshape<F, T, R>(nested_vec: &Vec<Vec<T>>, func: F) -> Vec<Vec<R>>
where
    F: Fn(&T) -> R + Sync + Send,
    T: Send + Sync,
    R: Send,
{
    // 1. Collect lengths of inner vectors to remember structure
    let lengths: Vec<usize> = nested_vec
        .par_iter()
        .map(|inner| inner.len())
        .collect();

    // 2. Flatten and process in parallel
    let flat_processed: Vec<R> = nested_vec
        .par_iter()
        .flat_map(|inner_vec| inner_vec.par_iter().map(&func))
        .collect();

    // 3. Reshape back to original structure
    let mut result: Vec<Vec<R>> = Vec::with_capacity(lengths.len());
    let mut index = 0;

    for &len in &lengths {
        let end = index + len;
        result.push(flat_processed[index..end].to_vec());
        index = end;
    }

    result
}

/// Bonus: Alternative implementation using indices for more control
/// This version gives you access to both value and its position
fn process_with_indices<F, R>(nested_vec: &Vec<Vec<usize>>, func: F) -> Vec<Vec<R>>
where
    F: Fn(usize, usize, &usize) -> R + Sync + Send,
    R: Send,
{
    nested_vec
        .par_iter()
        .enumerate()
        .map(|(i, inner_vec)| {
            inner_vec
                .par_iter()
                .enumerate()
                .map(|(j, val)| func(i, j, val))
                .collect()
        })
        .collect()
}

/// Example of a more complex parallel operation
/// This shows how to use Rayon's parallel folds or other operations
fn sum_all_elements_parallel(nested_vec: &Vec<Vec<usize>>) -> usize {
    nested_vec
        .par_iter()
        .map(|inner_vec| {
            inner_vec
                .par_iter()
                .map(|&x| x)
                .sum::<usize>()
        })
        .sum()
}"
}
