                // Check if line ends with continuation pattern (e.g., backslash)
                if line.trim_end().ends_with('\\') {
                    // Start multiline input collection
                    let mut multiline_input = line.clone();

                    loop {
                        // Read continuation lines with ".. " prompt
                        let continuation = rl.readline_with_initial(".. ", ("", ""));

                        match continuation {
                            Ok(cont_line) => {
                                multiline_input.push_str(&cont_line);

                                // Check if continuation line also ends with backslash
                                if cont_line.trim_end().ends_with('\\') {
