// Custom operator that calculates sqrt(|x|) + 1
struct SqrtPlusOne;

impl Operator for SqrtPlusOne {
    fn operate(&self, args: &[f32]) -> f32 {
        // Takes one argument, but we'll handle edge cases
        if args.is_empty() {
            return 1.0; // Default value if no arguments
        }
        (args[0].abs().sqrt()) + 1.0
    }

    fn display(&self) -> String {
        "sqrtplusone".to_string()
    }

    fn clone_box(&self) -> Box<dyn Operator> {
        Box::new(SqrtPlusOne)
    }
}

// Another custom operator: custom sine with amplification
struct CustomSine(f32); // Parameterized operator

impl CustomSine {
    fn new(amplitude: f32) -> Self {
        CustomSine(amplitude)
    }
}

impl Operator for CustomSine {
    fn operate(&self, args: &[f32]) -> f32 {
        if args.is_empty() {
            return 0.0;
        }
        (self.0 * args[0]).sin()
    }

    fn display(&self) -> String {
        format!("sin_{}x", self.0)
    }

    fn clone_box(&self) -> Box<dyn Operator> {
        Box::new(CustomSine(self.0))
    }
}

