fn resolve_json_pointer(value: &Value, pointer: &str) -> Option<&Value> {
    if pointer.is_empty() || pointer == "/" {
        return Some(value);
    }

    let parts: Vec<&str> = pointer.split('/').skip(1).collect();
    let mut current = value;

    for part in parts {
        let decoded_part = part.replace("~1", "/").replace("~0", "~");

        match current {
            Value::Object(map) => {
                current = map.get(&decoded_part)?;
            }
            Value::Array(arr) => {
                let index: usize = decoded_part.parse().ok()?;
                current = arr.get(index)?;
            }
            _ => return None,
        }
    }

    Some(current)
}

fn resolve_reference(
