    let parts: Vec<&str> = reference.split('#').collect();
    let (file_part, pointer_part) = match parts.as_slice() {
        [file, pointer] => (*file, *pointer),
        [file] => (*file, "/"),
        _ => return Err("Invalid $ref format".into()),
    };

    // Resolve file path relative to base path
    let ref_path = if file_part.is_empty() {
        base_path.to_path_buf()
    } else {
