            .unwrap_or_else(|| Path::new("."))
            .join(file_part)
    };

    // Read and parse the referenced JSON file
    let ref_content = fs::read_to_string(&ref_path)?;
    let ref_value: Value = serde_json::from_str(&ref_content)?;

    // Resolve JSON pointer
    let resolved_value = resolve_json_pointer(&ref_value, pointer_part)
        .ok_or_else(|| format!("Failed to resolve JSON pointer: {}", pointer_part))?;

    // Convert the resolved value to Vec<PathBuf>
    match resolved_value {
        Value::Array(arr) => {
            let paths: Result<Vec<PathBuf>, _> = arr
                .iter()
                .map(|v| match v {
                    Value::String(s) => Ok(PathBuf::from(s)),
                    _ => Err("Expected string in array".into()),
                })
                .collect();
            paths.map_err(|e| e.into())
        }
        Value::String(s) => Ok(vec![PathBuf::from(s)]),
        _ => Err("Expected array or string in referenced value".into()),
    }
