//! This is for RP2040/Cortex-M0+ which lacks atomic instructions

#![no_std]
#![no_main]

use core::sync::atomic::{AtomicUsize, Ordering};

// Custom Atomic type that uses critical sections for all operations
// This ensures all accesses are properly synchronized
struct Channel {
    index: AtomicUsize,
}

impl Channel {
    const fn new() -> Self {
        Self {
            index: AtomicUsize::new(0),
        }
    }

    // Correct implementation using critical section with proper ordering
    fn get_next_index(&self) -> usize {
        critical_section::with(|_| {
            // Use Ordering::SeqCst inside critical section to maintain
            // sequential consistency with other atomic operations
            // This is important because:
            // 1. Ordering::Relaxed would allow reordering within the critical section
            // 2. We need visibility guarantees across both cores on RP2040
            // 3. SeqCst ensures all threads/cores see operations in the same order
            let old_val = self.index.load(Ordering::SeqCst);
            self.index.store(old_val + 1, Ordering::SeqCst);
            old_val
        })
    }

    // Alternative implementation using fetch_update pattern
    fn get_next_index_alt(&self) -> usize {
        critical_section::with(|_| {
            // Load with SeqCst for proper synchronization
            let current = self.index.load(Ordering::SeqCst);
            // Store with SeqCst to ensure the update is visible
            self.index.store(current.wrapping_add(1), Ordering::SeqCst);
            current
        })
    }

    // If you need to read the value without incrementing
    fn load_index(&self) -> usize {
        // Still need critical section for reading to ensure
        // we get a consistent value across cores
        critical_section::with(|_| {
            self.index.load(Ordering::SeqCst)
        })
    }
}

// Example usage demonstrating the pattern
static CHANNEL: Channel = Channel::new();

#[no_mangle]
extern "C" fn main() -> ! {
    // Simulate accessing from different contexts (cores, interrupts)

    // Get next index - this is safe across both M0+ cores
    let idx1 = CHANNEL.get_next_index(); // Returns 0
    let idx2 = CHANNEL.get_next_index(); // Returns 1
    let idx3 = CHANNEL.get_next_index(); // Returns 2

    // Current value should be 3
    let current = CHANNEL.load_index();

    // In a real application, you would use these indices...
    // For this example, we just loop forever
    loop {
        cortex_m::asm::nop();
    }
}

// Panic handler for no_std environment
#[panic_handler]
fn panic(_info: &core::panic::PanicInfo) -> ! {
    loop {}
}

// Provide a critical section implementation
// In a real RP2040 project, you'd use `critical-section-impl` from rp-pico
// For this example, we provide a minimal implementation
struct DummyCriticalSection;
critical_section::set_impl!(DummyCriticalSection);

unsafe impl critical_section::Impl for DummyCriticalSection {
    unsafe fn acquire() -> u8 {
        // In real RP2040 code, this would disable interrupts
        // and possibly acquire a spinlock for multi-core
        0
    }

    unsafe fn release(_token: u8) {
        // In real RP2040 code, this would re-enable interrupts
        // and release the spinlock
    }
}

// Note for RP2040 specific implementation:
// In a real RP2040 project using rp-pico or rp2040-hal,
// you would use the provided critical section implementation
// from `critical-section-impl` crate with `custom-section-asm` feature.
//
// The key points are:
// 1. Always use Ordering::SeqCst inside critical sections
// 2. Critical sections protect against both interrupts and other cores
// 3. All atomic operations on the same variable must use critical sections
// 4. This pattern works for both single-core and dual-core scenarios"
