  "main.rs": "use crossbeam_channel::{bounded, Receiver, Sender};
use expectrl::{spawn, stream::Stream, Session, WaitStatus};
use std::io::{Read, Write};
use std::sync::Arc;
use std::thread;
use std::time::Duration;

/// PTY session with separate reader/writer handles to avoid mutex deadlock
struct PTYHandle {
    writer_tx: Sender<Vec<u8>>,
    output_rx: Receiver<Vec<u8>>,
    process_handle: thread::JoinHandle<()>,
}

impl PTYHandle {
    /// Spawn a process in a PTY with non-blocking I/O
    fn spawn(command: &str) -> Result<Self, Box<dyn std::error::Error>> {
        // Spawn the process
        let mut session = spawn(command)?
            .echo(false)
            .pty_stream()
            .set_raw_mode(true)?;

        // Split into reader/writer
        let mut stream = session.try_clone()?;

        // Channels for communication between threads
        let (writer_tx, writer_rx) = bounded(100);
        let (output_tx, output_rx) = bounded(100);

        // Thread 1: Non-blocking read loop
        let read_thread = {
            let output_tx = output_tx.clone();

            thread::spawn(move || {
                let mut buf = [0u8; 4096];

                loop {
                    // Use non-blocking read with timeout
                    match stream.read_timeout(&mut buf, Duration::from_millis(100)) {
                        Ok(n) if n > 0 => {
                            if output_tx.send(buf[..n].to_vec()).is_err() {
                                break; // Channel closed
                            }
                        }
                        Ok(_) => { /* No data available */ }
                        Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                            // Non-blocking timeout, continue
                            thread::sleep(Duration::from_millis(10));
                            continue;
                        }
                        Err(_) => {
                            // EOF or error
                            break;
                        }
                    }

                    // Check if process exited
                    if let Ok(Some(_)) = session.wait_timeout(Duration::from_millis(0)) {
                        break;
                    }
                }

                // Send termination signal
                let _ = output_tx.send(vec![]);
            })
        };

        // Thread 2: Writer thread
        let write_thread = {
            let mut session = session;

            thread::spawn(move || {
                while let Ok(data) = writer_rx.recv() {
                    if data.is_empty() {
                        break;
                    }

                    // Write to PTY
                    if let Err(e) = session.write_all(&data) {
                        eprintln!("Write error: {}", e);
                        break;
                    }

                    // Flush to ensure data is sent
                    let _ = session.flush();
                }
            })
        };

        // Combined thread handle
        let process_handle = thread::spawn(move || {
            read_thread.join().unwrap();
            write_thread.join().unwrap();
        });

        Ok(Self {
            writer_tx,
            output_rx,
            process_handle,
        })
    }

    /// Send data to the PTY process
    fn send(&self, data: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
        self.writer_tx.send(data.to_vec())
            .map_err(|e| Box::new(e) as Box<dyn std::error::Error>)
    }

    /// Read available output (non-blocking)
    fn try_recv(&self) -> Option<Vec<u8>> {
        self.output_rx.try_recv().ok()
    }

    /// Read output with timeout
    fn recv_timeout(&self, timeout: Duration) -> Result<Vec<u8>, Box<dyn std::error::Error>> {
        self.output_rx.recv_timeout(timeout)
            .map_err(|e| Box::new(e) as Box<dyn std::error::Error>)
    }
}

