            .set_raw_mode(true)?;

        Ok(Self { session })
    }

    /// Process I/O in an event loop (good for Tauri async context)
    async fn process_io_async<F, G>(
        &mut self,
        mut on_output: F,
        mut get_input: G,
    ) -> Result<(), Box<dyn std::error::Error>>
    where
        F: FnMut(&[u8]) -> (),
        G: FnMut() -> Option<Vec<u8>>,
    {
        use tokio::io::{AsyncReadExt, AsyncWriteExt};

        // Convert to tokio handles
        let stream = self.session.try_clone()?;
        let mut async_stream = tokio::net::unix::pipe::PipeStream::from_std(stream)?;

        let mut buf = [0u8; 4096];

        loop {
            // Check for output
            match tokio::time::timeout(
                Duration::from_millis(100),
                async_stream.read(&mut buf)
