impl rustyline::EventHandler for DotCommaHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Check if there's whitespace immediately before cursor
        if pos > 0 {
            let char_before = line.chars().nth(pos - 1);

            if char_before.map_or(false, |c| c.is_whitespace()) {
