fn main() -> io::Result<()> {
    // Enable raw mode for direct terminal control
    crossterm::terminal::enable_raw_mode()?;

    // Setup terminal for cleaner output
    let mut stdout = io::stdout();
    crossterm::execute!(
        stdout,
        crossterm::cursor::Hide,
        crossterm::terminal::Clear(crossterm::terminal::ClearType::All),
        crossterm::cursor::MoveTo(0, 0)
    )?;

    println!("TUI Event Loop Demo");
    println!("===================");
    println!("Instructions:");
    println!("- Press 'q' to quit");
    println!("- Press 'p' to toggle pause");
    println!("- Press any other key to see events");
    println!("\nStatus will update in real-time:\n");

    let tick_rate = Duration::from_millis(100);  // UI updates every 100ms
    let mut last_tick = Instant::now();
    let mut paused = false;
    let mut event_count = 0;
    let mut tick_count = 0;
    let mut last_key = "None".to_string();

    // Main event loop
    loop {
        // Calculate time until next tick
        let timeout = tick_rate
            .checked_sub(last_tick.elapsed())
            .unwrap_or(Duration::from_secs(0));

        // Poll for events with timeout
        if event::poll(timeout)? {
            // Event is available, read it (non-blocking)
            let event = event::read()?;
            event_count += 1;

            match event {
                Event::Key(key_event) => {
                    // Only process key presses (not releases) to avoid double counting
                    if key_event.kind == KeyEventKind::Press {
                        match key_event.code {
