use std::pin::Pin;
use std::sync::Arc;
use tokio::sync::mpsc::{self, Sender};
use tokio::task;

pub struct Context(i32);

// Trait similar to the unstable AsyncFnOnce
pub trait AsyncContextFn: Send + Sync + 'static {
    type Fut: Future<Output = ()> + Send;

    fn call(self: Arc<Self>, ctx: &mut Context) -> Self::Fut;
}

// Implement AsyncContextFn for closures
impl<F, Fut> AsyncContextFn for F
where
    F: FnOnce(&mut Context) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    type Fut = Fut;

    fn call(self: Arc<Self>, ctx: &mut Context) -> Self::Fut {
        let f = match Arc::try_unwrap(self) {
            Ok(f) => f,
            Err(arc_f) => {
                // Clone the Arc and call the closure
                // This means the closure might be called multiple times if the Arc is shared,
                // but that's acceptable for our use case where we guarantee single use
                let f_ref = arc_f.as_ref();
                // We need to reconstruct the closure from the reference
                // Since we can't call FnOnce through a reference, we'll use a workaround
                panic!("Closure was shared unexpectedly. This should not happen with our wrapper.");
            }
        };
        f(ctx)
    }
}

// Wrapper that ensures single use
pub struct AsyncContextFnOnceWrapper<F: AsyncContextFn> {
    inner: Option<Arc<F>>,
}

impl<F: AsyncContextFn> AsyncContextFnOnceWrapper<F> {
    pub fn new(f: F) -> Self {
        Self {
            inner: Some(Arc::new(f)),
        }
    }

    pub fn call_once(mut self, ctx: &mut Context) -> F::Fut {
        let arc_f = self.inner.take().expect("Already called");
        arc_f.call(ctx)
    }
}

// Our event enum
pub enum InnerAsyncEvent {
    DoWithContext {
        block: AsyncContextFnOnceWrapper<Box<dyn AsyncContextFn<Fut = Pin<Box<dyn Future<Output = ()> + Send>>>>>,
    },
}

// Helper to create AsyncContextFnOnceWrapper from async closures
pub fn wrap_async_fn_once<F, Fut>(f: F) -> AsyncContextFnOnceWrapper<Box<dyn AsyncContextFn<Fut = Pin<Box<dyn Future<Output = ()> + Send>>>>>
where
    F: FnOnce(&mut Context) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    // Double-box to get the right types
    let boxed_fn = Box::new(move |ctx: &mut Context| {
        Box::pin(f(ctx)) as Pin<Box<dyn Future<Output = ()> + Send>>
    });

    AsyncContextFnOnceWrapper::new(boxed_fn)
}

// Nice wrapper function
pub fn with_context_async(
    work_sender: &Sender<InnerAsyncEvent>, 
    block: impl FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>> + Send + Sync + 'static
) -> Result<(), mpsc::error::SendError<InnerAsyncEvent>> {
    let wrapper = wrap_async_fn_once(move |ctx| block(ctx));

    work_sender.blocking_send(InnerAsyncEvent::DoWithContext { block: wrapper })
}

// Even nicer version for async closures using a macro
#[macro_export]
macro_rules! async_work {
    ($block:expr) => {{
        $crate::wrap_async_fn_once(move |ctx: &mut $crate::Context| {
            Box::pin(async move { $block(ctx).await })
        })
    }};
}

#[tokio::main]
async fn main() {
    println!("Starting example...");

    let (tx, mut rx) = mpsc::channel::<InnerAsyncEvent>(10);

    // Spawn worker thread
    let worker = task::spawn(async move {
        let mut ctx = Context(0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    let fut = block.call_once(&mut ctx);
                    fut.await;
                    println!("Context value after work: {}", ctx.0);
                }
            }
        }
    });

    // Example 1: Using the macro for clean syntax
    let event1 = InnerAsyncEvent::DoWithContext {
        block: async_work!(|ctx: &mut Context| {
            println!("Task 1: Starting");
            ctx.0 += 1;
            println!("Task 1: Added 1");
        }),
    };

    tx.send(event1).await.unwrap();

    // Example 2: Using the helper function
    let _ = with_context_async(&tx, |ctx: &mut Context| {
        Box::pin(async move {
            println!("Task 2: Starting");
            ctx.0 += 2;
            println!("Task 2: Added 2");
        })
    });

    // Example 3: More complex async work
    let event3 = InnerAsyncEvent::DoWithContext {
        block: async_work!(|ctx: &mut Context| {
            println!("Task 3: Starting complex work");
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            ctx.0 *= 2;
            println!("Task 3: Doubled value");
        }),
    };

    tx.send(event3).await.unwrap();

    // Give time for tasks to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(200)).await;

    // Signal completion
    drop(tx);

    // Wait for worker
    let _ = worker.await;

    println!("Example completed!");
}

