/// Method 2: Center columns by repeating the mean vector
fn center_columns(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    let nrows = matrix.nrows();
    let column_means = matrix.column_mean(); // DVector (column vector)

    // Create a matrix where each row is the column means
    let means_matrix = RowDVector::from(column_means.transpose()) // Convert to RowDVector
        .repeat(nrows, 1); // Repeat vertically nrows times

    // Subtract: matrix (n x k) - means_matrix (n x k)
    matrix - means_matrix
}

/// Method 3: Center columns using zip_apply (elementwise operation)
fn center_columns_zip(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    let nrows = matrix.nrows();
    let ncols = matrix.ncols();
    let column_means = matrix.column_mean();

    let mut result = matrix.clone();

    // For each element, subtract the corresponding column mean
    for col in 0..ncols {
        let mean = column_means[col];
        for row in 0..nrows {
            result[(row, col)] -= mean;
        }
    }

    result
}

/// Method 4: Center columns using componentwise subtraction with broadcasting
fn center_columns_broadcast(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    let nrows = matrix.nrows();
    let column_means = matrix.column_mean();

    // Alternative: create a matrix of means by componentwise multiplication with ones
    let ones = DVector::from_element(nrows, 1.0);
    let means_matrix = ones * column_means.transpose();

    matrix - means_matrix
}

/// Compute the covariance matrix (1/(n-1) * X^T * X) where X is column-centered
fn compute_covariance(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    let n = matrix.nrows() as f64;
    let centered = center_columns(matrix);

    // Covariance = (1/(n-1)) * (centered^T * centered)
    (centered.transpose() * centered) / (n - 1.0)
}

/// Example with integer matrix, converting to f64 for centering
fn center_columns_int<T>(matrix: &DMatrix<T>) -> DMatrix<f64> 
where
    T: Scalar + Into<f64>,
{
    let nrows = matrix.nrows();

    // Convert to f64 and compute column means
    let matrix_f64: DMatrix<f64> = matrix.map(|x| x.into());
    let column_means = matrix_f64.column_mean();

    // Create means matrix by repeating
    let means_matrix = RowDVector::from(column_means.transpose())
        .repeat(nrows, 1);

    matrix_f64 - means_matrix
}

