            /// Set up MDC (Mapped Diagnostic Context) with caller information
            #[track_caller]
            pub fn setup_caller_context() {
                let loc = Location::caller();
                // Extract module from file path
                let module = if let Some((path, _)) = loc.file().rsplit_once('/') {
                    if let Some((crate_name, module_path)) = path.rsplit_once('/') {
