fn custom_formatter(buf: &mut env_logger::fmt::Formatter, record: &log::Record) -> std::io::Result<()> {
    use std::io::Write;

    let timestamp = buf.timestamp_millis();
    let level = record.level();

    // Try to get module from MDC first
    let module = log_mdc::get("caller_module")
