fn shell_tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut escaping = false;

    for c in input.chars() {
        match c {
            '\\' => {
                if escaping {
                    // Escaped backslash
                    current_token.push('\\');
                    escaping = false;
                } else if in_single_quote {
                    // Single quotes don't allow escaping (except for single quote itself)
                    current_token.push('\\');
                } else {
                    // Start escaping
                    escaping = true;
                }
            },
            '\'' => {
                if escaping {
                    // Escaped single quote (only possible outside single quotes)
                    current_token.push('\'');
                    escaping = false;
                } else if in_single_quote {
                    // End single quote
                    in_single_quote = false;
                } else if !in_double_quote {
                    // Start single quote
                    in_single_quote = true;
                } else {
                    // Single quote inside double quotes is literal
                    current_token.push('\'');
                }
            },
            '"' => {
                if escaping {
                    // Escaped double quote (only possible outside single quotes)
                    current_token.push('"');
                    escaping = false;
                } else if in_double_quote {
                    // End double quote
                    in_double_quote = false;
                } else if !in_single_quote {
                    // Start double quote
                    in_double_quote = true;
                } else {
                    // Double quote inside single quotes is literal
                    current_token.push('"');
                }
            },
            c if c.is_whitespace() => {
                if escaping {
                    // Escaped whitespace - add to token
                    current_token.push('\\');
                    current_token.push(c);
                    escaping = false;
                } else if in_single_quote || in_double_quote {
                    // Whitespace inside quotes is part of token
                    current_token.push(c);
                } else {
                    // Whitespace outside quotes separates tokens
                    if !current_token.is_empty() {
                        tokens.push(std::mem::take(&mut current_token));
                    }
                }
            },
            other => {
                if escaping {
                    // Handle escaped character
                    current_token.push('\\');
                    current_token.push(other);
                    escaping = false;
                } else {
                    // Regular character
                    current_token.push(other);
                }
            }
        }
    }

    // Handle any remaining escape sequence
    if escaping {
        current_token.push('\\');
    }

    // Add the last token if there is one
    if !current_token.is_empty() {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    // Test cases
    let test_cases = vec![
        (" one  ' two  'three    four", vec!["one", " two  three", "four"]),
        ("echo 'hello world' foo", vec!["echo", "hello world", "foo"]),
        ("ls -la | grep 'test file'", vec!["ls", "-la", "|", "grep", "test file"]),
        ("a\\ b 'c d' e", vec!["a b", "c d", "e"]),
        ("'quoted'notquoted", vec!["quotednotquoted"]),
        ("'mixed\\'quote'", vec!["mixed'quote"]),
        ("\"double quoted\" 'single quoted'", vec!["double quoted", "single quoted"]),
        ("empty\"\"quotes", vec!["emptyquotes"]),
        ("escaped\\ space", vec!["escaped space"]),
        ("normal trailing spaces   ", vec!["normal", "trailing", "spaces"]),
    ];

    for (input, expected) in test_cases {
        let result = shell_tokenize(input);
        println!("Input: '{}'", input);
        println!("Expected: {:?}", expected);
        println!("Got:      {:?}", result);
        println!("Match:    {}\n", result == expected);
    }

    // Interactive demo
    println!("\n=== Interactive Demo ===");
    println!("Enter shell command to tokenize (or 'quit' to exit):");

    use std::io::{self, Write};
    loop {
