use std::pin::Pin;
use std::task::{Context, Poll, Waker, RawWaker, RawWakerVTable};
use std::sync::Arc;
use tokio::runtime::Runtime;
use tokio::task;

/// Result of trying to poll a future synchronously
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// A waker that does nothing - used for one-off polling
static NOOP_WAKER_VTABLE: RawWakerVTable = RawWakerVTable::new(
    |_| RawWaker::new(std::ptr::null(), &NOOP_WAKER_VTABLE), // clone
    |_| {}, // wake
    |_| {}, // wake_by_ref
    |_| {}, // drop
);

fn noop_waker() -> Waker {
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &NOOP_WAKER_VTABLE)) }
}

/// Try to poll a future synchronously
fn try_poll<F, X>(future: &mut Pin<&mut F>) -> TryPollResult<X>
where
    F: Future<Output = X> + Unpin,
{
    let waker = noop_waker();
    let mut context = Context::from_waker(&waker);

    match Future::poll(future.as_mut(), &mut context) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Example future that simulates async work
async fn delayed_value(value: u32, delay_ms: u64) -> u32 {
    tokio::time::sleep(tokio::time::Duration::from_millis(delay_ms)).await;
    value
}

/// Process a future - either completes it synchronously or spawns a task
fn process_future<F, X>(rt: &Runtime, mut future: F) -> Option<X>
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static,
{
    let mut pinned = Pin::new(&mut future);

    match try_poll(&mut pinned) {
        TryPollResult::Ready(result) => {
            println!("Future completed synchronously!");
            Some(result)
        }
        TryPollResult::Pending => {
            println!("Future is pending, spawning async task...");

            // Spawn a task to await the future
            rt.spawn(async move {
                let result = future.await;
                println!("Task completed with result: {}", result);
                result
            });

            None
        }
    }
}

/// Another example: Process a future that might be ready or not
fn process_future_with_callback<F, X, C>(mut future: F, callback: C)
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static,
    C: FnOnce(Option<X>) + Send + 'static,
{
    let mut pinned = Pin::new(&mut future);

    match try_poll(&mut pinned) {
        TryPollResult::Ready(result) => {
            println!("Future completed synchronously, calling callback");
            callback(Some(result));
        }
        TryPollResult::Pending => {
            println!("Future is pending, spawning task with callback");

            // Box the future to ensure it's Sized
            let boxed_future = Box::pin(future);

            task::spawn(async move {
                let result = boxed_future.await;
                println!("Task completed, calling callback");
                callback(Some(result));
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Example 1: Immediately ready future ===");
    let immediate_future = async { 42 };
    let rt = tokio::runtime::Handle::current();

    if let Some(result) = process_future(rt, immediate_future) {
        println!("Got immediate result: {}", result);
    }

    // Give any spawned tasks time to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("\n=== Example 2: Delayed future ===");
    let delayed_future = delayed_value(99, 50);
    let rt = tokio::runtime::Handle::current();

    if let Some(result) = process_future(rt, delayed_future) {
        println!("Got delayed result: {}", result);
    }

    // Wait for the spawned task to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("\n=== Example 3: Using callback ===");
    let another_future = delayed_value(777, 30);

    process_future_with_callback(another_future, |result| {
        match result {
            Some(value) => println!("Callback received: {}", value),
            None => println!("Callback received None"),
        }
    });

    // Wait for the callback task
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("\n=== Example 4: Manual polling demonstration ===");

    // Create a custom future that yields once
    let mut counter = 0;
    let yielding_future = std::future::poll_fn(|cx| {
        if counter < 2 {
            counter += 1;
            cx.waker().wake_by_ref();
            Poll::Pending
        } else {
            Poll::Ready("Done!")
        }
    });

    let mut pinned = Box::pin(yielding_future);

    // First poll - should be pending
    match try_poll(&mut pinned) {
        TryPollResult::Ready(_) => println!("First poll: Ready (unexpected)"),
        TryPollResult::Pending => println!("First poll: Pending (expected)"),
    }

    // Poll again in the async context to make progress
    let handle = task::spawn(async move {
        let result = pinned.await;
        println!("Async await completed: {}", result);
    });

    handle.await.unwrap();

    println!("\nAll examples completed!");
}"
}
