  "main.rs": "use std::collections::HashMap;
use serde_json::Value;

// Define the property value types for Notion API
type PropertyValues = PropertyValue;

#[derive(Debug, Clone)]
pub enum PropertyValue {
    Title(Vec<RichTextObject>),
    Url(String),
    MultiSelect(Vec<SelectObject>),
}

#[derive(Debug, Clone)]
pub struct RichTextObject {
    pub text: TextObject,
}

#[derive(Debug, Clone)]
pub struct TextObject {
    pub content: String,
}

#[derive(Debug, Clone)]
pub struct SelectObject {
    pub name: String,
