// The custom derive macro - simplified implementation for the example
// In a real implementation, this would be in a separate proc-macro crate
use quote::quote;
use syn::{parse_macro_input, DeriveInput, Data, Fields, Type};

#[proc_macro_derive(NotionProperties, attributes(notion_property))]
pub fn derive_notion_properties(input: proc_macro::TokenStream) -> proc_macro::TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let struct_name = &input.ident;

    let fields = match input.data {
        Data::Struct(data) => match data.fields {
            Fields::Named(fields) => fields.named,
            _ => panic!("Only structs with named fields are supported"),
        },
        _ => panic!("Only structs are supported"),
    };

    let mut insert_statements = Vec::new();

    for field in fields {
        let field_name = field.ident.as_ref().unwrap();
        let field_type = &field.ty;

        // Extract attributes
        let mut property_type = None;
        let mut property_name = None;

        for attr in &field.attrs {
            if attr.path().is_ident("notion_property") {
                let tokens = attr.meta.require_list().unwrap().tokens.clone();
                let attr_str = tokens.to_string();

                // Simple parsing of attribute values
                for part in attr_str.split(',') {
                    let part = part.trim();
                    if part.starts_with("type = ") {
                        let value = part.trim_start_matches("type = \"")
                            .trim_end_matches('\"');
                        property_type = Some(value.to_string());
                    } else if part.starts_with("name = ") {
                        let value = part.trim_start_matches("name = \"")
                            .trim_end_matches('\"');
                        property_name = Some(value.to_string());
                    }
                }
            }
        }

        let property_type = property_type.expect(&format!("Missing 'type' attribute for field {}", field_name));
        let property_name = property_name.expect(&format!("Missing 'name' attribute for field {}", field_name));

        // Generate the appropriate insert statement based on property type
        let insert_stmt = match property_type.as_str() {
            "title" => {
                quote! {
                    map.insert(
                        #property_name.to_string(),
                        PropertyValues::Title(
                            vec![RichTextObject {
                                text: TextObject {
                                    content: self.#field_name.clone(),
                                },
                            }]
                        ),
                    );
                }
            }
            "url" => {
                // Handle Option<String> for url
                if let Type::Path(type_path) = field_type {
                    if type_path.path.segments.last().unwrap().ident == "Option" {
                        quote! {
                            if let Some(value) = &self.#field_name {
                                map.insert(
                                    #property_name.to_string(),
                                    PropertyValues::Url(value.clone()),
                                );
                            }
                        }
                    } else {
                        quote! {
                            map.insert(
                                #property_name.to_string(),
                                PropertyValues::Url(self.#field_name.clone()),
                            );
                        }
                    }
                } else {
                    quote! {
                        map.insert(
                            #property_name.to_string(),
                            PropertyValues::Url(self.#field_name.clone()),
                        );
                    }
                }
            }
            "MultiSelect" => {
                // Handle Option<Vec<serde_json::Value>> for MultiSelect
                quote! {
                    if let Some(values) = &self.#field_name {
                        let select_objects: Vec<SelectObject> = values
                            .iter()
                            .map(|v| SelectObject {
                                name: v.to_string(),
                            })
                            .collect();
                        map.insert(
                            #property_name.to_string(),
                            PropertyValues::MultiSelect(select_objects),
                        );
                    }
                }
            }
            _ => panic!("Unsupported property type: {}", property_type),
        };

        insert_statements.push(insert_stmt);
    }

    let expanded = quote! {
        impl ToNotionProperties for #struct_name {
            fn to_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut map = HashMap::new();
                #(#insert_statements)*
                map
            }
        }
    };

    proc_macro::TokenStream::from(expanded)
}

// Example usage
#[derive(NotionProperties)]
struct MyUnit {
    #[notion_property(type = "title", name = "Name")]
    pub name: String,

    #[notion_property(type = "url", name = "Icon url")]
    pub icon_url: Option<String>,

    #[notion_property(type = "MultiSelect", name = "Roles")]
    pub categories: Option<Vec<serde_json::Value>>,
}

fn main() {
    // Example struct instance
    let unit = MyUnit {
        name: "Example Unit".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![serde_json::json!("Admin"), serde_json::json!("User")]),
    };

    // Convert to Notion properties
    let properties = unit.to_notion_properties();

    // Print the result
    println!("Generated {} properties:", properties.len());
    for (key, value) in &properties {
        match value {
            PropertyValue::Title(title_vec) => {
                println!("  {}: Title (first text: {})", 
                    key, 
                    title_vec.first().map(|rt| rt.text.content.as_str()).unwrap_or("")
                );
            }
            PropertyValue::Url(url) => {
                println!("  {}: Url (value: {})", key, url);
            }
            PropertyValue::MultiSelect(options) => {
                let option_names: Vec<String> = options.iter().map(|o| o.name.clone()).collect();
                println!("  {}: MultiSelect (options: {:?})", key, option_names);
            }
        }
    }

    // Verify the conversion
    assert_eq!(properties.len(), 3);
    assert!(properties.contains_key("Name"));
    assert!(properties.contains_key("Icon url"));
    assert!(properties.contains_key("Roles"));

    match properties.get("Name") {
        Some(PropertyValue::Title(title_vec)) => {
            assert_eq!(title_vec[0].text.content, "Example Unit");
        }
        _ => panic!("Name should be a Title property"),
    }

    match properties.get("Icon url") {
        Some(PropertyValue::Url(url)) => {
            assert_eq!(url, "https://example.com/icon.png");
        }
        _ => panic!("Icon url should be a Url property"),
