// Main lazy loader struct
pub struct LazyArchiveLoader<F: ArchiveFormat> {
    archive_format: F,
    loaded_archives: HashMap<String, Arc<F::Reader>>,
}

impl<F: ArchiveFormat> LazyArchiveLoader<F> {
    pub fn new(archive_format: F) -> Self {
        Self {
            archive_format,
            loaded_archives: HashMap::new(),
        }
    }

    pub fn load_archive(
        &mut self,
        path: &str,
        data: Vec<u8>,
    ) -> Result<Arc<F::Reader>, CustomAssetError> {
        let reader = self.archive_format.open(data)?;
        let arc_reader = Arc::new(reader);
        self.loaded_archives.insert(path.to_string(), arc_reader.clone());
        Ok(arc_reader)
    }

    pub fn get_archive(&self, path: &str) -> Option<Arc<F::Reader>> {
        self.loaded_archives.get(path).cloned()
    }

    pub fn list_files_in_archive(&self, archive_path: &str) -> Option<Vec<String>> {
        self.loaded_archives.get(archive_path).map(|r| r.list_files())
    }

    pub fn read_file_from_archive(
        &self,
        archive_path: &str,
        file_path: &str,
    ) -> Result<Vec<u8>, CustomAssetError> {
        self.loaded_archives
            .get(archive_path)
            .ok_or_else(|| CustomAssetError::AssetNotFound(archive_path.to_string()))?
            .read_file(file_path)
