impl<F: ArchiveFormat> AssetLoader for ArchiveFileAssetLoader<F> {
    type Asset = ArchiveFileAsset;
    type Settings = ();
    type Error = CustomAssetError;

    fn extensions(&self) -> &[&str] {
        &self.supported_extensions
    }

    fn load<'a>(
        &'a self,
        reader: &'a mut dyn bevy::asset::io::Reader,
        _settings: &'a (),
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // Read the "virtual path" which contains both archive and file
            let mut path_data = Vec::new();
            reader.read_to_end(&mut path_data).await?;
            let path_str = String::from_utf8_lossy(&path_data);

            // Format: "archive.zip::internal/file.png"
            let parts: Vec<&str> = path_str.split("::").collect();
            if parts.len() != 2 {
                return Err(CustomAssetError::Parse(
                    "Path must be in format: archive::file".to_string(),
                ));
            }

            let archive_path = parts[0];
            let file_path = parts[1];

            // Get the data from our lazy loader
            let loader = self.loader.lock().unwrap();
            let data = loader.read_file_from_archive(archive_path, file_path)?;

            Ok(ArchiveFileAsset {
                data,
                file_name: file_path.to_string(),
            })
        })
    }
