fn ray_aabb_intersection(ray_origin: Vec3, ray_dir: Vec3, aabb: &Aabb) -> Option<RayHit> {
    let inv_dir = Vec3::new(1.0 / ray_dir.x, 1.0 / ray_dir.y, 1.0 / ray_dir.z);

    let t1 = (aabb.min.x - ray_origin.x) * inv_dir.x;
    let t2 = (aabb.max.x - ray_origin.x) * inv_dir.x;
    let t3 = (aabb.min.y - ray_origin.y) * inv_dir.y;
    let t4 = (aabb.max.y - ray_origin.y) * inv_dir.y;
    let t5 = (aabb.min.z - ray_origin.z) * inv_dir.z;
    let t6 = (aabb.max.z - ray_origin.z) * inv_dir.z;

    let tmin = t1.min(t2).max(t3.min(t4)).max(t5.min(t6));
    let tmax = t1.max(t2).min(t3.max(t4)).min(t5.max(t6));

    if tmax < 0.0 || tmin > tmax {
        return None;
    }

    let t = if tmin < 0.0 { tmax } else { tmin };
    let hit_point = ray_origin + ray_dir * t;

    // Calculate normal by finding which face was hit
    let epsilon = 0.001;
    let normal = if (hit_point.x - aabb.min.x).abs() < epsilon {
        Vec3::NEG_X
    } else if (hit_point.x - aabb.max.x).abs() < epsilon {
        Vec3::X
    } else if (hit_point.y - aabb.min.y).abs() < epsilon {
        Vec3::NEG_Y
    } else if (hit_point.y - aabb.max.y).abs() < epsilon {
        Vec3::Y
    } else if (hit_point.z - aabb.min.z).abs() < epsilon {
        Vec3::NEG_Z
    } else {
        Vec3::Z
    };

    Some(RayHit {
        position: hit_point,
        normal,
        distance: t,
    })
}

