// A wrapper that holds both the original String and the deserialized struct
// with borrowed references pointing into the String.
// This can be safely sent across thread boundaries because:
// 1. It owns the String (so the data lives as long as the wrapper)
// 2. The borrowed references point into the owned String
// 3. The wrapper is Send + Sync when T is Send + Sync
#[derive(Debug)]
struct BorrowedDeserialized<'a, T> {
    // Owns the raw JSON string
    raw_data: String,
    // Contains references that point into raw_data
    parsed: T,
    // PhantomData to tie the lifetime
    _marker: PhantomData<&'a ()>,
}

impl<'a, T> BorrowedDeserialized<'a, T>
where
    T: Deserialize<'a>,
{
    // Deserialize once and create the wrapper
    fn new(raw_data: String) -> Result<Self, serde_json::Error> {
        // SAFETY: The parsed struct's references will point into raw_data.
        // Since we never mutate or drop raw_data while parsed exists,
        // the references remain valid.
        let parsed: T = serde_json::from_str(&raw_data)?;

        Ok(Self {
            raw_data,
            parsed,
            _marker: PhantomData,
        })
    }

    // Get a reference to the parsed data
    fn get(&self) -> &T {
        &self.parsed
    }
