// Solution 1: Arc-wrapped sender for shared ownership
#[derive(Debug, Clone)]
pub struct SharedEventSender {
    tx: Arc<Sender<Event>>,
}

impl SharedEventSender {
    pub fn new(tx: Sender<Event>) -> Self {
        Self { tx: Arc::new(tx) }
    }

    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }

