    pub fn create_weak(&self) -> WeakEventSender {
        WeakEventSender {
            tx: Arc::downgrade(&self.tx),
        }
    }
}

// Weak sender reference for checking if channel is alive
pub struct WeakEventSender {
    tx: std::sync::Weak<Sender<Event>>,
}

impl WeakEventSender {
    pub fn is_alive(&self) -> bool {
        self.tx.upgrade().is_some()
    }
}

// Solution 2: Event manager that holds the original sender
pub struct EventManager {
    original_tx: Sender<Event>,
    shared_sender: SharedEventSender,
}

impl EventManager {
    pub fn new(capacity: usize) -> Self {
        let (tx, _) = broadcast::channel(capacity);
        let shared_sender = SharedEventSender::new(tx.clone());
        Self {
            original_tx: tx,
            shared_sender,
        }
    }

    pub fn sender(&self) -> SharedEventSender {
        self.shared_sender.clone()
    }

    pub fn create_stream(&self) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send + '_ {
        BroadcastStream::new(self.original_tx.subscribe())
    }

    // Dropping the EventManager drops the original sender
    // This will close all streams when the manager is dropped
    pub fn shutdown(self) {
        // Explicit drop of original_tx (happens automatically when struct is dropped)
        drop(self);
    }

    // Alternative: explicit shutdown method
    pub fn shutdown_explicit(&mut self) {
        // By dropping the original_tx, all streams will receive RecvError::Closed
        drop(std::mem::take(&mut self.original_tx));
    }
}

// Solution 3: Using shutdown signal
pub struct ShutdownSender {
    tx: Sender<Event>,
    shutdown_tx: tokio::sync::broadcast::Sender<()>,
}

impl ShutdownSender {
    pub fn new(capacity: usize) -> (Self, ShutdownReceiver) {
        let (tx, _) = broadcast::channel(capacity);
        let (shutdown_tx, shutdown_rx) = tokio::sync::broadcast::channel(1);
        (
            Self { tx, shutdown_tx },
            ShutdownReceiver { shutdown_rx },
