use tokio::sync::mpsc::{unbounded_channel, UnboundedReceiver, UnboundedSender};
use tokio_util::io::ReaderStream;

#[derive(Clone)]
struct ChildOutputHelper {
    tx: UnboundedSender<String>,
}

impl Helper for ChildOutputHelper {}

struct ChildProcess {
    stdin: ChildStdin,
    stdout_rx: UnboundedReceiver<String>,
}

impl ChildProcess {
    async fn new(mut command: Command) -> Result<Self, Box<dyn std::error::Error>> {
        command.stdin(Stdio::piped());
        command.stdout(Stdio::piped());
        command.stderr(Stdio::piped());

        let mut child = command.spawn()?;

        let stdin = child.stdin.take().expect("Failed to open stdin");
        let stdout = child.stdout.take().expect("Failed to open stdout");
        let stderr = child.stderr.take().expect("Failed to open stderr");

        let (tx, stdout_rx) = unbounded_channel();

        // Handle stdout
        let tx_stdout = tx.clone();
        tokio::spawn(async move {
            let stdout_reader = BufReader::new(stdout);
            let mut stdout_lines = stdout_reader.lines();

            while let Some(line) = stdout_lines.next_line().await.transpose() {
                if let Ok(line) = line {
                    let _ = tx_stdout.send(line);
                }
            }
        });

        // Handle stderr
        tokio::spawn(async move {
            let stderr_reader = BufReader::new(stderr);
            let mut stderr_lines = stderr_reader.lines();

            while let Some(line) = stderr_lines.next_line().await.transpose() {
                if let Ok(line) = line {
                    let _ = tx.send(line);
                }
            }
        });

        Ok(Self { stdin, stdout_rx })
    }

    async fn send_command(&mut self, command: String) -> Result<(), Box<dyn std::error::Error>> {
        self.stdin.write_all(command.as_bytes()).await?;
        self.stdin.write_all(b"\n").await?;
        self.stdin.flush().await?;
        Ok(())
    }

    async fn read_output(&mut self) -> Option<String> {
        self.stdout_rx.recv().await
    }
}

async fn run_repl() -> Result<(), Box<dyn std::error::Error>> {
    // Create a child process (using python REPL as example)
    let mut child = ChildProcess::new(Command::new("python3")).await?;

    // Create rustyline editor with helper
    let (tx, _) = unbounded_channel();
    let helper = ChildOutputHelper { tx };
    let mut rl = Editor::with_config(rustyline::Config::builder()
        .auto_add_history(true)
        .build())?;

    println!("Connected to child process. Type 'exit' to quit.");

    loop {
        // Check for child output without blocking
        while let Some(output) = child.read_output().await {
            println!("\x1b[2K\r{}\n", output);
        }

        // Read user input with rustyline
        let readline = rl.readline(">>> ");
        match readline {
            Ok(line) => {
                if line.trim() == "exit" {
                    break;
                }

                // Send command to child
                if let Err(e) = child.send_command(line.clone()).await {
                    eprintln!("Failed to send command: {}", e);
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let rt = Runtime::new()?;
    rt.block_on(run_repl())
}
