    let result2 = parallel_map_flatten_reshape(&a, |x| format!("Value: {}", x));
    println!("\nMethod 2 - Flatten/reshape (to strings):");
    for (i, inner) in result2.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    // Method 3: In-place parallel mutation (if you own the data)
    let mut a_clone = a.clone();
    parallel_mutate_in_place(&mut a_clone, |x| *x += 10);
    println!("\nMethod 3 - In-place mutation (add 10):");
    for (i, inner) in a_clone.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }
}

/// Method 1: Direct parallel mapping while preserving the nested structure
/// This processes outer and inner vectors in parallel
fn parallel_map_preserve_structure<F, T>(nested: &Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    F: Fn(usize) -> T + Send + Sync,
    T: Send,
{
    nested
        .par_iter() // Parallel iteration over outer vector
        .map(|inner_vec| {
            inner_vec
                .par_iter() // Parallel iteration over inner vector
                .map(|&x| f(x))
                .collect()
        })
        .collect()
}

/// Method 2: Flatten, process in parallel, then reshape
/// This is useful when you need to process all elements with maximum parallelism
fn parallel_map_flatten_reshape<F, T>(nested: &Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    F: Fn(usize) -> T + Send + Sync,
    T: Send,
{
    // Step 1: Collect metadata about the original structure
    let offsets: Vec<usize> = nested
        .iter()
        .scan(0, |acc, inner| {
            let current_offset = *acc;
            *acc += inner.len();
            Some(current_offset)
        })
        .collect();

    let lengths: Vec<usize> = nested.iter().map(|inner| inner.len()).collect();

    // Step 2: Flatten the nested structure
    let flat: Vec<usize> = nested.iter().flat_map(|inner| inner.iter().copied()).collect();

    // Step 3: Apply function in parallel to all elements
    let transformed: Vec<T> = flat.par_iter().map(|&x| f(x)).collect();

    // Step 4: Reshape back to original structure
    offsets
        .into_iter()
        .zip(lengths.into_iter())
        .map(|(offset, length)| {
            transformed[offset..offset + length].to_vec()
        })
        .collect()
}

/// Method 3: Mutate in place (requires mutable ownership)
fn parallel_mutate_in_place<F>(nested: &mut Vec<Vec<usize>>, f: F)
where
    F: Fn(&mut usize) + Send + Sync,
{
    nested
        .par_iter_mut() // Parallel mutable iteration over outer vector
        .for_each(|inner_vec| {
            inner_vec
                .par_iter_mut() // Parallel mutable iteration over inner vector
                .for_each(f);
        });
}

/// Additional example: Process with index information
fn parallel_map_with_indices<F, T>(nested: &Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    F: Fn(usize, usize, usize) -> T + Send + Sync, // (outer_idx, inner_idx, value) -> T
    T: Send,
{
    nested
        .par_iter()
        .enumerate() // Get outer index
        .map(|(i, inner_vec)| {
            inner_vec
                .par_iter()
                .enumerate() // Get inner index
                .map(|(j, &value)| f(i, j, value))
                .collect()
        })
        .collect()
}

