        let result = parallel_map_preserve_structure(&input, |x| x * 2);
        assert_eq!(result, vec![vec![2, 4], vec![6, 8, 10]]);
    }

    #[test]
    fn test_parallel_map_flatten_reshape() {
        let input = vec![vec![1, 2], vec![3, 4, 5]];
        let result = parallel_map_flatten_reshape(&input, |x| x.to_string());
        assert_eq!(
            result,
            vec![vec!["1".to_string(), "2".to_string()], vec!["3".to_string(), "4".to_string(), "5".to_string()]]
        );
    }

    #[test]
    fn test_parallel_mutate_in_place() {
        let mut input = vec![vec![1, 2], vec![3, 4, 5]];
        parallel_mutate_in_place(&mut input, |x| *x += 1);
        assert_eq!(input, vec![vec![2, 3], vec![4, 5, 6]]);
    }

    #[test]
