            }
        });

        // Now we need to ensure symmetric updates are complete
        // Each thread only added j to i's list when i < j
        // We need to add i to j's list for all pairs
        // We can do this in a second parallel pass
        self.elems.par_iter_mut().enumerate().for_each(|(i, elem_i)| {
            // For each neighbor j in elem_i's list where j > i,
            // we need to add i to elem_j's list
            let mut neighbors_to_update = Vec::new();

            for &j in &elem_i.nb {
                if j > i {
                    neighbors_to_update.push(j);
                }
            }

            // Update the neighbor lists of the other elements
            for &j in &neighbors_to_update {
                // Get mutable access to element j
                let elem_j = unsafe { &mut *(&mut self.elems[j] as *mut B) };
                elem_j.nb.push(i);
            }
        });
    }

    // Alternative parallel version using index-based approach (more efficient)
    pub fn build_lists_parallel_alt(&mut self) {
        let nelems = self.get_nelems();
        let cutoff_sq = self.cutoff * self.cutoff;

        // Clear all neighbor lists in parallel
        self.elems.par_iter_mut().for_each(|elem| {
            elem.nb.clear();
        });

        // Precompute positions for distance checking
        let positions: Vec<[f64; 3]> = self.elems
            .iter()
            .map(|b| [b.r[0], b.r[1], b.r[2]])
            .collect();

        // Create adjacency matrix in parallel
        let mut adjacency = vec![vec![false; nelems]; nelems];

        // Parallel computation of adjacency matrix
        adjacency.par_iter_mut().enumerate().for_each(|(i, row)| {
            let pos_i = positions[i];
            for j in (i + 1)..nelems {
                let pos_j = positions[j];
                let dx = pos_i[0] - pos_j[0];
                let dy = pos_i[1] - pos_j[1];
                let dz = pos_i[2] - pos_j[2];
                let dist_sq = dx * dx + dy * dy + dz * dz;

                if dist_sq < cutoff_sq {
                    row[j] = true;
                }
            }
        });

        // Build neighbor lists from adjacency matrix in parallel
        self.elems.par_iter_mut().enumerate().for_each(|(i, elem)| {
            for j in 0..nelems {
                if i == j {
                    continue;
                }

                let is_neighbor = if i < j {
                    adjacency[i][j]
                } else {
                    adjacency[j][i]
                };

                if is_neighbor {
                    elem.nb.push(j);
                }
            }
        });
    }
