use std::path::{Path, PathBuf};
use serde::{Deserialize, Deserializer};
use serde_json::{Value, from_str};
use serde_path_to_error::{deserialize as deserialize_with_path, Error as PathError};

#[derive(Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

fn resolve_ref(ref_str: &str, base_path: &Path) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
    let parts: Vec<&str> = ref_str.split('#').collect();

    if parts.len() != 2 {
        return Err("Invalid $ref format".into());
    }

    let (file_path, json_path) = (parts[0].trim(), parts[1].trim());

    let ref_file_path = if file_path.starts_with("./") || file_path.starts_with("../") {
        base_path.parent()
            .unwrap_or_else(|| Path::new("./"))
            .join(file_path)
    } else {
        Path::new(file_path).to_path_buf()
    };

    let content = fs::read_to_string(&ref_file_path)
        .map_err(|e| format!("Failed to read {}: {}", ref_file_path.display(), e))?;

    let json_value: Value = from_str(&content)
        .map_err(|e| format!("Failed to parse JSON: {}", e))?;

    let pointer_value = json_value.pointer(json_path)
        .ok_or_else(|| format!("JSON path {} not found", json_path))?;

    let paths: Vec<PathBuf> = pointer_value.as_array()
        .ok_or_else(|| "Expected array at JSON path")?
        .iter()
        .map(|v| v.as_str().map(PathBuf::from))
        .collect::<Option<Vec<_>>>()
        .ok_or_else(|| "All elements must be strings")?;

    Ok(paths)
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        let value = Value::deserialize(deserializer)?;

        match value {
            Value::Object(map) => {
                if let Some(Value::String(ref_str)) = map.get("$ref") {
                    let current_file = std::env::current_dir()
                        .unwrap_or_else(|_| PathBuf::from("./"));

                    let paths = resolve_ref(ref_str, &current_file)
                        .map_err(serde::de::Error::custom)?;

                    Ok(A { path_list: paths })
                } else {
                    Err(serde::de::Error::custom("Expected $ref field"))
                }
            },
            Value::Array(arr) => {
                let paths: Vec<PathBuf> = arr.iter()
                    .map(|v| v.as_str().map(PathBuf::from))
                    .collect::<Option<Vec<_>>>()
                    .ok_or_else(|| serde::de::Error::custom("All elements must be strings"))?;

                Ok(A { path_list: paths })
            },
            _ => Err(serde::de::Error::custom("Expected object with $ref or array"))
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let json_data = fs::read_to_string("b.json")?;

    match deserialize_with_path::<_, A>(&json_data) {
        Ok(a_obj) => {
            for p in &a_obj.path_list {
                println!("{}", p.display());
            }
            Ok(())
        },
        Err(e) => {
            let path_error: &PathError = e.as_ref();
            eprintln!("Deserialization error at path: {}", path_error.path());
            eprintln!("Error: {}", path_error.inner());
            Err("Deserialization failed".into())
        }
    }
}
"
}
