fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut chars = input.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            // Handle single quotes
            '\'' if !in_double_quote => {
                in_single_quote = !in_single_quote;
                // Add quote character to token
                current_token.push(ch);
            }
            // Handle double quotes
            '"' if !in_single_quote => {
                in_double_quote = !in_double_quote;
                // Add quote character to token
                current_token.push(ch);
            }
            // Handle backslash escaping (simplified - only escapes next character)
            '\\' => {
                if let Some(next_ch) = chars.peek() {
                    match next_ch {
                        '\'' | '"' | '\\' | ' ' | '\t' | '\n' => {
                            // Consume the escaped character
                            let escaped = chars.next().unwrap();
                            current_token.push(escaped);
                        }
                        _ => {
                            // Keep backslash if it doesn't escape anything special
                            current_token.push(ch);
                        }
                    }
                } else {
                    // Backslash at end of input
                    current_token.push(ch);
                }
            }
            // Handle whitespace outside quotes
            ' ' | '\t' | '\n' if !in_single_quote && !in_double_quote => {
                if !current_token.is_empty() {
                    tokens.push(current_token.clone());
                    current_token.clear();
                }
            }
            // Any other character
            _ => {
                current_token.push(ch);
            }
        }
    }

    // Don't forget the last token
    if !current_token.is_empty() {
        tokens.push(current_token);
    }

    tokens
}

// Helper function to strip quotes from tokens
fn strip_quotes(token: &str) -> String {
    let mut result = String::new();
    let mut chars = token.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            '\\' => {
                if let Some(next_ch) = chars.peek() {
                    match next_ch {
                        '\'' | '"' | '\\' => {
                            // Skip backslash, add escaped character
                            chars.next();
                            result.push(*next_ch);
                        }
                        _ => {
                            result.push(ch);
                        }
                    }
                } else {
                    result.push(ch);
                }
            }
            '\'' | '"' => {
                // Skip quote characters
            }
            _ => {
                result.push(ch);
            }
        }
    }

    result
}

