// Helper trait to make async closures work nicely
pub trait AsyncContextFnOnce: Send + 'static {
    fn call(
        self: Box<Self>,
        ctx: &mut Context,
    ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>>;
}

