pub fn rewrite_imports(root: &SyntaxNode) -> SyntaxNode {
    let mut rewriter = SyntaxRewriter::default();

    // Find all use items and rewrite them
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(tree) = use_item.use_tree() {
            if let Some((new_tree, should_remove)) = process_use_tree(&tree) {
