    rewriter.rewrite_root(root)
}

fn process_use_tree(tree: &ast::UseTree) -> Option<(ast::UseTree, bool)> {
    let mut rewriter = SyntaxRewriter::default();
    let mut should_remove = false;

    // Handle nested trees by processing recursively
    if let Some(use_tree_list) = tree.use_tree_list() {
        let mut new_trees = Vec::new();

        for child_tree in use_tree_list.use_trees() {
            if let Some((processed_tree, child_should_remove)) = process_use_tree(&child_tree) {
                if !child_should_remove {
                    new_trees.push(processed_tree);
                }
            }
        }

        if new_trees.is_empty() {
            // If no children remain, this tree should be removed
            should_remove = true;
        } else {
            // Create a new use tree list with the processed children
            let new_list = make::use_tree_list(new_trees);
            rewriter = rewriter.replace(&use_tree_list.syntax().clone(), new_list.syntax().clone());
        }
    }

    // Process the path itself
    if let Some(path) = tree.path() {
        let segments: Vec<_> = path.segments().collect();

        // Look for vexide::devices pattern
        let new_segments: Vec<_> = segments
            .iter()
            .enumerate()
            .filter_map(|(i, seg)| {
                if i > 0 && segments.get(i - 1).and_then(|s| s.name_ref()).map(|n| n.text()) == Some("vexide")
                    && seg.name_ref().map(|n| n.text()) == Some("devices")
                {
                    // Skip the "devices" segment
                    None
                } else {
                    Some(seg.clone())
                }
            })
            .collect();

        if new_segments.is_empty() {
            // If the entire path became empty, this tree should be removed
            should_remove = true;
        } else if new_segments.len() != segments.len() {
            // Rebuild the path if it changed
            let mut new_path = make::path_from_text(&new_segments[0].syntax().text().to_string());

            for seg in new_segments.iter().skip(1) {
                new_path = make::path(new_path, seg.clone());
            }

            // Handle asterisk separately
            if tree.star_token().is_some() {
                let new_tree = make::use_tree_path(new_path, None).with_star_token();
                rewriter = rewriter.replace(&tree.syntax().clone(), new_tree.syntax().clone());
            } else if tree.use_tree_list().is_some() {
                // If there's a use tree list, we already handled it above
                // We need to create a tree with the new path and the already-processed list
                if let Some(use_tree_list) = tree.use_tree_list() {
                    let new_tree = make::use_tree_path(new_path, Some(use_tree_list.clone()));
                    rewriter = rewriter.replace(&tree.syntax().clone(), new_tree.syntax().clone());
                }
            } else {
                // Simple path without list or star
                let new_tree = make::use_tree_path(new_path, None);
                rewriter = rewriter.replace(&tree.syntax().clone(), new_tree.syntax().clone());
            }
        }
    }

    if rewriter.has_changes() {
        let new_tree = rewriter.rewrite(tree.syntax());
        Some((ast::UseTree::cast(new_tree)?, should_remove))
    } else {
        Some((tree.clone(), should_remove))
    }
}

fn main() {
    // Example usage
    let code = r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};
"#;

    let parsed = ra_ap_syntax::SourceFile::parse(code);
    let syntax = parsed.tree().syntax().clone();

    let rewritten = rewrite_imports(&syntax);

    println!("Original:\n{}", syntax);
    println!("\nRewritten:\n{}", rewritten);
}
"
