// Type-erased container that can hold any Rest implementer
pub struct RestContainer {
    inner: Box<dyn Rest>,
}

impl RestContainer {
    pub fn new<T: Rest + 'static>(item: T) -> Self {
        Self {
            inner: Box::new(item),
        }
    }

    pub fn get_id(&self) -> u32 {
        self.inner.get_id()
    }

    pub fn get_name(&self) -> &str {
        self.inner.get_name()
    }

    // Downcast to specific type if it matches
    pub fn downcast_ref<T: 'static>(&self) -> Option<&T> {
        self.inner.as_any().downcast_ref::<T>()
    }

    // Check if container holds a specific type
    pub fn is_type<T: 'static>(&self) -> bool {
        self.inner.as_any().type_id() == TypeId::of::<T>()
    }
}

// Alternative: Dynamic dispatch wrapper with optional static dispatch optimization
pub enum OptimizedRest {
    Static(RestDispatch),  // Use enum_dispatch when types are known at compile time
    Dynamic(Box<dyn Rest>), // Fallback for dynamic cases
