    pub fn new_static<T: Into<RestDispatch>>(item: T) -> Self {
        Self::Static(item.into())
    }

    pub fn new_dynamic<T: Rest + 'static>(item: T) -> Self {
        Self::Dynamic(Box::new(item))
    }

    pub fn get_id(&self) -> u32 {
        match self {
            OptimizedRest::Static(disp) => disp.get_id(),
            OptimizedRest::Dynamic(dyn_disp) => dyn_disp.get_id(),
        }
    }

    pub fn get_name(&self) -> &str {
        match self {
            OptimizedRest::Static(disp) => disp.get_name(),
            OptimizedRest::Dynamic(dyn_disp) => dyn_disp.get_name(),
        }
    }
