    pub fn set_module_path_override(module_path: &'static str) -> ModulePathGuard {
        OVERRIDE_MODULE_PATH.with(|cell| {
            *cell.borrow_mut() = Some(module_path);
        });
        ModulePathGuard
    }

    pub struct ModulePathGuard;

    impl Drop for ModulePathGuard {
        fn drop(&mut self) {
            OVERRIDE_MODULE_PATH.with(|cell| {
                *cell.borrow_mut() = None;
            });
        }
    }

    /// Get the current module path override
    pub fn get_module_path_override() -> Option<&'static str> {
        OVERRIDE_MODULE_PATH.with(|cell| cell.borrow().as_ref().copied())
    }

