    type R = Result<T, actix_web::error::Error>;

    /// Logs the error and replaces it with an internal server error without details
    #[track_caller]
    fn log_hide_res(self) -> Self::R {
        match self {
            Ok(ok) => Ok(ok),
            Err(err) => {
                let location = std::panic::Location::caller();
                warn_with_caller!(
                    "Internal error at {}:{}: {err:?}",
                    location.file(),
                    location.line()
                );
                Err(actix_web::error::ErrorInternalServerError(
                    "Unexpected error occurred",
                ))
            }
        }
    }

    /// Logs the client error and returns the error to the client
    #[track_caller]
    fn log_and_explain_400(self) -> Self::R {
        match self {
            Ok(ok) => Ok(ok),
            Err(err) => {
                let location = std::panic::Location::caller();
                info_with_caller!(
                    "Client error at {}:{}: {err:?}",
                    location.file(),
                    location.line()
                );
                Err(actix_web::error::ErrorBadRequest(err))
            }
        }
    }
}

