async fn handle_request(req: Request<hyper::body::Incoming>) -> Result<Response<BoxBody<Bytes, hyper::Error>>, Infallible> {
    // Get the path from the request URI
    let path = req.uri().path();

    // Remove leading slash
    let file_path = if path.starts_with('/') && path.len() > 1 {
        &path[1..]
    } else if path == "/" {
        // Default to index.html for root
        "index.html"
    } else {
        // Return 404 for empty path
        return Ok(not_found());
    };

    // Try to open the file
    let file_path = Path::new(file_path);
    match tokio::fs::File::open(file_path).await {
        Ok(file) => {
            // Get file metadata for Content-Length header (optional but good practice)
            if let Ok(metadata) = file.metadata().await {
                let stream = ReaderStream::new(file);
                let body = BodyExt::boxed(http_body_util::StreamBody::new(stream));

                let response = Response::builder()
                    .status(StatusCode::OK)
                    .header("Content-Type", guess_mime_type(file_path))
                    .header("Content-Length", metadata.len().to_string())
                    .body(body)
                    .unwrap();

                Ok(response)
            } else {
                // If we can't get metadata, still serve the file without Content-Length
                let file = tokio::fs::File::open(file_path).await.unwrap();
                let stream = ReaderStream::new(file);
                let body = BodyExt::boxed(http_body_util::StreamBody::new(stream));

                let response = Response::builder()
                    .status(StatusCode::OK)
                    .header("Content-Type", guess_mime_type(file_path))
                    .body(body)
                    .unwrap();

                Ok(response)
            }
        }
        Err(_) => {
            // File not found
            Ok(not_found())
        }
    }
}

fn not_found() -> Response<BoxBody<Bytes, hyper::Error>> {
    let body = Full::new(Bytes::from("404 Not Found\r\n"))
        .map_err(|never| match never {})
        .boxed();

    Response::builder()
        .status(StatusCode::NOT_FOUND)
        .body(body)
        .unwrap()
}

fn guess_mime_type(path: &Path) -> &'static str {
    match path.extension().and_then(|ext| ext.to_str()) {
        Some("html") | Some("htm") => "text/html; charset=utf-8",
        Some("css") => "text/css; charset=utf-8",
        Some("js") => "application/javascript; charset=utf-8",
        Some("json") => "application/json; charset=utf-8",
        Some("png") => "image/png",
        Some("jpg") | Some("jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("svg") => "image/svg+xml",
        Some("txt") => "text/plain; charset=utf-8",
        Some("pdf") => "application/pdf",
        _ => "application/octet-stream",
    }
}

