fn center_columns(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    // Get column means as a row vector (1 x k)
    let column_means = matrix.column_mean(); // Returns a RowDVector (1 x k)

    // Subtract column means from each row using broadcasting
    // We need to create a matrix with the same shape as the input
    // where each row is the column_means vector
    let n_rows = matrix.nrows();
    let n_cols = matrix.ncols();

    // Create a matrix by repeating the row vector n_rows times
    // Method 1: Using from_row_slice with repeated data
    let means_repeated = DMatrix::from_row_slice(
        n_rows,
        n_cols,
        &column_means.as_slice().repeat(n_rows).flatten().collect::<Vec<f64>>(),
    );

    matrix - means_repeated
}

fn center_columns_alternative(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    // Alternative method: create column-centered matrix manually
    let mut centered = matrix.clone();

    // Get column means
    let column_means = matrix.column_mean();

    // Subtract each column's mean from all elements in that column
    for col in 0..matrix.ncols() {
        let col_mean = column_means[col];
        for row in 0..matrix.nrows() {
            centered[(row, col)] -= col_mean;
        }
    }

    centered
}

fn center_columns_broadcast(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    // Using broadcasting approach with from_fn
    let column_means = matrix.column_mean();
    let n_rows = matrix.nrows();
    let n_cols = matrix.ncols();

    DMatrix::from_fn(n_rows, n_cols, |row, col| {
        matrix[(row, col)] - column_means[col]
    })
}

