use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, Waker};
use std::sync::Arc;
use std::sync::atomic::{AtomicBool, Ordering};

// Result type for try_poll
#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// Simple waker that does nothing
struct NoopWaker;

impl NoopWaker {
    fn new() -> Waker {
        // SAFETY: The waker does nothing when woken, which is safe
        unsafe { Waker::from_raw(std::task::RawWaker::new(std::ptr::null(), &NOOP_VTABLE)) }
    }
}

static NOOP_VTABLE: std::task::RawWakerVTable = std::task::RawWakerVTable::new(
    // clone
    |_| std::task::RawWaker::new(std::ptr::null(), &NOOP_VTABLE),
    // wake
    |_| {},
    // wake_by_ref
    |_| {},
    // drop
    |_| {},
);

/// Attempts to poll a future synchronously using a no-op waker
/// Returns Ready if the future is immediately ready, Pending otherwise
/// Note: This uses a no-op waker, so the future won't be woken by this poll
fn try_poll<F: Future + Unpin>(future: &mut F) -> TryPollResult<F::Output> {
    let noop_waker = NoopWaker::new();
    let mut cx = Context::from_waker(&noop_waker);

    // SAFETY: We're pinning the future locally and it's Unpin
    let mut pinned = Pin::new(future);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Spawns a task to await the future and process its result
/// This is what you'd call if try_poll returns Pending
async fn spawn_future_task<F, T, H>(future: F, on_complete: H)
where
    F: Future<Output = T> + Send + 'static,
    T: Send + 'static,
    H: FnOnce(T) + Send + 'static,
{
    tokio::spawn(async move {
        let result = future.await;
        on_complete(result);
    });
}

// Example implementation with a custom future that tracks completion
struct TrackableFuture<T> {
    data: Option<T>,
    woken: Arc<AtomicBool>,
    waker: Option<Waker>,
}

impl<T> TrackableFuture<T> {
    fn new(data: T) -> Self {
        Self {
            data: Some(data),
            woken: Arc::new(AtomicBool::new(false)),
            waker: None,
        }
    }
}

impl<T: Unpin> Future for TrackableFuture<T> {
    type Output = T;

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        // Store the waker so we can wake it later
        self.waker = Some(cx.waker().clone());

        if self.woken.load(Ordering::Acquire) {
            // Return the data if we've been woken
            Poll::Ready(self.data.take().expect("Data should be present"))
        } else {
            Poll::Pending
        }
    }
}

// Example usage in an async context
async fn example_usage() {
    println!("=== Example 1: Ready Future ===");

    // Create a future that's immediately ready
    let ready_future = async { 42 };

    // Use try_poll on it
    let mut boxed_future = Box::pin(ready_future);
    match try_poll(boxed_future.as_mut()) {
        TryPollResult::Ready(val) => {
            println!("Future was immediately ready: {}", val);
        }
        TryPollResult::Pending => {
            println!("Future is pending, spawning task...");
            spawn_future_task(boxed_future, |val| {
                println!("Future completed in spawned task: {}", val);
            }).await;
        }
    }

    println!("\n=== Example 2: Pending Future ===");

    // Create a trackable future that starts pending
    let trackable_future = TrackableFuture::new(100);
    let woken_clone = trackable_future.woken.clone();

    let mut boxed_future2 = Box::pin(trackable_future);

    // First poll should return Pending
    match try_poll(boxed_future2.as_mut()) {
        TryPollResult::Ready(val) => {
            println!("Unexpected: Future was immediately ready: {}", val);
        }
        TryPollResult::Pending => {
            println!("Future is pending as expected, spawning task...");

            // Spawn a task that will wake the future after a delay
            let future_to_spawn = Box::pin(async move {
                // Simulate some async work
                tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

                // Wake the future
                woken_clone.store(true, Ordering::Release);

                // Poll it again (this would be done by the executor normally)
                // In real usage, you'd store the waker and wake it
                100
            });

            spawn_future_task(future_to_spawn, |val| {
                println!("Future completed in spawned task: {}", val);
            }).await;
        }
    }

    println!("\n=== Example 3: Async Block Future ===");

    // Another example with an async block that yields
    let mut counter = 0;
    let yielding_future = async {
        counter += 1;
        tokio::task::yield_now().await;
        counter += 1;
        counter
    };

    let mut boxed_future3 = Box::pin(yielding_future);

    // First poll might return Pending because of yield_now
