pub fn parse_lancedb_date(date_str: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // Clean the string - remove quotes if present
    let cleaned = date_str.trim_matches('"');

    // Try multiple parsing strategies in order of specificity

    // 1. Try parsing with timezone (if present)
    if let Ok(dt) = DateTime::parse_from_rfc3339(cleaned) {
