// Solution 1: Using HRTB (Higher-Ranked Trait Bounds) with boxed futures
// This is the most straightforward solution that maintains the simple calling syntax
async fn harness<T, Fut>(test: T)
where
    T: for<'a> Fn(&'a mut String) -> Fut,
    Fut: Future<Output = ()> + 'static,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

// Solution 2: Alternative using Pin<Box<dyn Future>> for more flexibility
// This can handle more complex cases where the future isn't 'static
async fn harness_boxed<T>(test: T)
where
    T: for<'a> Fn(&'a mut String) -> Pin<Box<dyn Future<Output = ()> + 'a>>,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

// Helper to convert an async function to return a boxed future
fn boxed_test<F, Fut>(f: F) -> impl for<'a> Fn(&'a mut String) -> Pin<Box<dyn Future<Output = ()> + 'a>>
where
    F: Fn(&mut String) -> Fut + Copy + 'static,
    Fut: Future<Output = ()> + 'static,
{
    move |s: &mut String| Box::pin(f(s))
}

#[tokio::main]
async fn main() {
    // Solution 1: Works because we added + 'static to Fut
    harness(simple_test).await;

    // Solution 2: Using boxed version
    harness_boxed(boxed_test(simple_test)).await;

    // Alternative with inline closure
    harness_boxed(|s: &mut String| Box::pin(simple_test(s))).await;
}
"
