// Middleware function that checks WebSocket origin for upgrade requests
async fn check_websocket_origin(
    request: axum::extract::Request,
    next: axum::middleware::Next,
) -> Result<axum::response::Response, StatusCode> {
    // Only check WebSocket upgrade requests
    if is_websocket_upgrade(&request) {
        let origin = request
            .headers()
            .get(header::ORIGIN)
            .and_then(|v| v.to_str().ok());

        // Define allowed origins - you can make this configurable
        let allowed_origins = vec![
            "https://www.example.com",
            "http://localhost:8080", // For local testing
        ];

        match origin {
            Some(origin) if allowed_origins.contains(&origin) => {
                tracing::debug!(origin, "WebSocket origin allowed");
                Ok(next.run(request).await)
            }
            Some(origin) => {
                tracing::warn!(origin, "WebSocket origin rejected");
                Err(StatusCode::FORBIDDEN)
            }
            None => {
                tracing::warn!("WebSocket request missing origin header");
                Err(StatusCode::BAD_REQUEST)
            }
        }
    } else {
        // Not a WebSocket upgrade request, proceed normally
        Ok(next.run(request).await)
    }
}

// Helper to check if this is a WebSocket upgrade request
fn is_websocket_upgrade(request: &axum::extract::Request) -> bool {
    request.headers()
        .get(header::CONNECTION)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.to_lowercase().contains("upgrade"))
        .unwrap_or(false)
        && request.headers()
            .get(header::UPGRADE)
            .and_then(|v| v.to_str().ok())
            .map(|v| v.to_lowercase() == "websocket")
            .unwrap_or(false)
