use std::sync::Arc;

// A struct with borrowed references
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// Wrapper that owns the underlying String and provides access to parsed data
struct OwnedMyData {
    // Owns the raw JSON string
    raw_json: Arc<str>,
    // Stores the parsed data - the borrows are valid as long as raw_json exists
    parsed: MyData<'static>,
}

// SAFETY: We ensure that the parsed MyData only references data within raw_json,
// and raw_json is kept alive alongside the parsed data.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

impl OwnedMyData {
    // Parse once and create the owned wrapper
    fn parse_once(json: String) -> Result<Self, serde_json::Error> {
        // Convert to Arc<str> to share ownership efficiently
        let arc_json = Arc::from(json.into_boxed_str());

        // Get a reference to the Arc's data
        let json_ref: &str = &arc_json;

        // Parse the JSON - the resulting MyData borrows from json_ref
        let parsed: MyData = serde_json::from_str(json_ref)?;

        // Transmute the lifetime to 'static because we guarantee the data lives as long as Self
        // SAFETY: The parsed data only references the arc_json which we store alongside it
        let parsed_static: MyData<'static> = unsafe { std::mem::transmute(parsed) };

        Ok(OwnedMyData {
            raw_json: arc_json,
            parsed: parsed_static,
        })
    }

    // Get access to the parsed data
    fn get(&self) -> &MyData {
        &self.parsed
    }
}

// Alternative approach using a trait object (slightly safer)
struct TraitObjectWrapper {
    raw_json: Arc<str>,
    parsed: Box<dyn std::fmt::Debug + Send + Sync>,
}

impl TraitObjectWrapper {
    fn parse_once(json: String) -> Result<Self, serde_json::Error> {
        let arc_json = Arc::from(json.into_boxed_str());
        let json_ref: &str = &arc_json;

        let parsed: MyData = serde_json::from_str(json_ref)?;

        Ok(TraitObjectWrapper {
            raw_json: arc_json,
            parsed: Box::new(parsed),
        })
    }

    fn get_my_data(&self) -> &dyn std::fmt::Debug {
        &*self.parsed
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Example JSON data
    let json_data = r#"{"data": "hello", "more_data": "world"}"#.to_string();

    println!("=== Approach 1: Using OwnedMyData (with lifetime transmutation) ===");

    // Parse once
    let owned_data = OwnedMyData::parse_once(json_data.clone())?;

    // Create a channel to send data between tasks
    let (tx, mut rx) = mpsc::channel::<Arc<OwnedMyData>>(10);

    // Clone the Arc to share ownership
    let data_arc = Arc::new(owned_data);

    // Send to channel from main task
    tx.send(data_arc.clone()).await?;

    // Spawn a task that receives and processes the data
    let task1 = tokio::spawn(async move {
        if let Some(received) = rx.recv().await {
            let parsed = received.get();
            println!("Task 1 received: {:?}", parsed);
            println!("Data field: {}, More data: {}", parsed.data, parsed.more_data);
        }
    });

    // Spawn another task using the same Arc
    let task2_data = data_arc.clone();
    let task2 = tokio::spawn(async move {
        let parsed = task2_data.get();
        println!("Task 2 received: {:?}", parsed);
    });

    // Wait for tasks to complete
    task1.await?;
    task2.await?;

    println!("\n=== Approach 2: Using TraitObjectWrapper (safer) ===");

    let trait_wrapper = TraitObjectWrapper::parse_once(json_data)?;
    let trait_arc = Arc::new(trait_wrapper);

    // Spawn a task with the trait object
    let trait_task = tokio::spawn(async move {
        let data = trait_arc.get_my_data();
        println!("Task with trait object received: {:?}", data);
    });

    trait_task.await?;

    println!("\n=== All tasks completed successfully ===");

