use rustyline::validate::Validator;
use rustyline::{Cmd, ConditionalEventHandler, Editor, Event, EventContext, EventHandler, KeyEvent, Modifiers, Movement, RepeatCount};
use std::borrow::Cow::{self, Borrowed, Owned};

struct MyCompleter;

impl Completer for MyCompleter {
    type Candidate = Pair;

    fn complete(&self, line: &str, pos: usize, _ctx: &rustyline::Context<'_>) -> rustyline::Result<(usize, Vec<Pair>)> {
        // Simple completer that recognizes table names
        let words = vec!["book", "author"];
        let line_before_cursor = &line[..pos];
        let word_start = line_before_cursor
            .rfind(|c: char| !c.is_alphanumeric() && c != '_')
            .map(|i| i + 1)
            .unwrap_or(0);

        let current_word = &line_before_cursor[word_start..];

        let mut candidates = Vec::new();
        for word in words {
            if word.starts_with(current_word) && !current_word.is_empty() {
                candidates.push(Pair {
                    display: word.to_string(),
                    replacement: format!("{} ", word), // Add space after completion
                });
            }
        }

