    fn validate(&self, _ctx: &mut rustyline::validate::ValidationContext) -> rustyline::validate::ValidationResult {
        Ok(rustyline::validate::ValidationResult::Valid(None))
    }
}

struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        let insert = String::from(insert);
        MyEventHandler { insert }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Only handle if we're at the end of the line
        if pos < line.len() {
            return None;
        }

        let line_before_cursor = &line[..pos];

        // Find last non-whitespace character
        if let Some(index) = line_before_cursor.rfind(|c| !char::is_whitespace(c)) {
            let whitespace_count = pos - (index + 1);

            if whitespace_count > 0 {
