  "main.rs": "use futures::stream::StreamExt;
use std::sync::Arc;
use tokio::sync::broadcast;
use tokio::sync::{broadcast::error::RecvError, RwLock};
use tokio_stream::wrappers::BroadcastStream;
use tokio_stream::StreamExt as TokioStreamExt;

type Event = String;

// Main shutdown controller that wraps the original sender
#[derive(Debug)]
pub struct EventSystem {
    sender: broadcast::Sender<Event>,
    shutdown_flag: Arc<RwLock<bool>>,
}

impl EventSystem {
    pub fn new(capacity: usize) -> Self {
        let (sender, _) = broadcast::channel(capacity);
        Self {
            sender,
            shutdown_flag: Arc::new(RwLock::new(false)),
        }
    }

    pub fn create_sender(&self) -> EventSender {
        EventSender {
            tx: self.sender.clone(),
            shutdown_flag: self.shutdown_flag.clone(),
        }
    }

    pub fn create_stream_factory(&self) -> EventStreamFactory {
        EventStreamFactory {
            tx: self.sender.clone(),
            shutdown_flag: self.shutdown_flag.clone(),
        }
    }

    // Initiate shutdown by setting the flag and dropping the original sender
    pub async fn shutdown(&self) {
        // Set the shutdown flag first
        *self.shutdown_flag.write().await = true;

        // Send a shutdown event to wake up all receivers
        let _ = self.sender.send("SHUTDOWN".to_string());

        // Drop the original sender - this will close the channel
        // when all cloned senders are dropped
        drop(self.sender.clone());
    }

    // Check if shutdown has been initiated
    pub async fn is_shutdown(&self) -> bool {
        *self.shutdown_flag.read().await
    }
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: broadcast::Sender<Event>,
    shutdown_flag: Arc<RwLock<bool>>,
}

impl EventSender {
    pub fn send(&self, event: Event) -> Result<usize, broadcast::error::SendError<Event>> {
        // Check if shutdown has been initiated
        if let Ok(flag) = self.shutdown_flag.try_read() {
            if *flag {
                return Err(broadcast::error::SendError(event));
            }
        }
        self.tx.send(event)
    }
}

pub struct EventStreamFactory {
    tx: broadcast::Sender<Event>,
    shutdown_flag: Arc<RwLock<bool>>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send + 'static {
        let rx = self.tx.subscribe();
        let shutdown_flag = self.shutdown_flag.clone();

        BroadcastStream::new(rx)
            .take_while(move |result| {
                let shutdown_flag = shutdown_flag.clone();
                async move {
                    match result {
                        Ok(event) if event == "SHUTDOWN" => {
                            // Stop the stream when we receive a SHUTDOWN event
                            false
                        }
                        Err(RecvError::Closed) => {
                            // Stop when the channel is closed
                            false
                        }
                        Err(RecvError::Lagged(_)) => {
                            // Continue if we lagged
                            true
                        }
                        _ => {
                            // Check shutdown flag
                            if let Ok(flag) = shutdown_flag.read().await {
                                !*flag
                            } else {
                                true
                            }
                        }
                    }
                }
            })
            .filter_map(|result| async move {
                match result {
                    Ok(event) if event == "SHUTDOWN" => None,
                    Ok(event) => Some(Ok(event)),
                    Err(RecvError::Closed) => None,
                    Err(RecvError::Lagged(skipped)) => {
                        tracing::warn!("Lagging, skipped {} messages", skipped);
                        None
                    }
                }
            })
    }
}

async fn example_subscriber(name: &str, factory: EventStreamFactory) {
    let mut stream = factory.all_events();

    tracing::info!("{}: Starting to listen for events", name);

    while let Some(result) = stream.next().await {
