use cms::{
    content_info::ContentInfo,
    signed_data::{SignedData, SignerInfos},
    cert_choice::CertChoices,
    signed_data::EncapsulatedContentInfo,
};
use der::{Decode, Encode};
use x509::Certificate;
use anyhow::{Result, Context};
use hex;

fn main() -> Result<()> {
    // Read binary SCEP data from stdin
    let mut buffer = Vec::new();
    std::io::stdin()
        .read_to_end(&mut buffer)
        .context("Failed to read from stdin")?;

    println!("Read {} bytes of SCEP data", buffer.len());

    // Try to decode as DER-encoded ContentInfo
    decode_scep_data(&buffer)?;

    Ok(())
}

fn decode_scep_data(data: &[u8]) -> Result<()> {
    // 1. Decode as ContentInfo (outer PKCS#7 structure)
    let ci = ContentInfo::from_der(data)
        .context("Failed to decode ContentInfo from DER")?;

    println!("Content Type OID: {}", ci.content_type);

    // 2. Decode the SignedData
    // The issue might be with certificate parsing, so let's handle it differently
    let raw_content = ci.content.to_bytes();

    // First, let's try to parse SignedData manually to debug
    let sd = match SignedData::from_der(raw_content) {
        Ok(sd) => sd,
        Err(e) => {
            println!("Error parsing SignedData: {:?}", e);
            println!("Raw content length: {}", raw_content.len());

            // Try alternative approach: parse certificates separately
            return parse_signed_data_with_workaround(raw_content);
        }
    };

    // If we get here, parsing succeeded
    print_signed_data_info(&sd);

    // 3. Access the encapsulated content (the actual SCEP message)
    if let Some(econtent) = sd.encap_content_info.econtent.as_ref() {
        println!("\nEncapsulated content ({} bytes):", econtent.len());
        println!("Hex: {}", hex::encode(&econtent[..std::cmp::min(econtent.len(), 100)]));

        // The eContent contains another PKCS#7 EnvelopedData structure
        // This is the actual SCEP PKI message
        if let Ok(inner_ci) = ContentInfo::from_der(econtent) {
            println!("\nInner ContentInfo type: {}", inner_ci.content_type);
        }
    }

    Ok(())
}

fn parse_signed_data_with_workaround(data: &[u8]) -> Result<()> {
    println!("\nTrying alternative parsing approach...");

    // Create a reader to manually parse the SignedData
    let mut reader = der::Reader::new(data);

    // Read the SEQUENCE tag and length
    reader.sequence(|reader| {
        // Read version (INTEGER)
        let version = reader.decode::<u32>()?;
        println!("SignedData version: {}", version);

        // Read digestAlgorithms (SET OF)
        let digest_algorithms = reader.decode::<cms::digest_algorithms::DigestAlgorithms>()?;
        println!("Number of digest algorithms: {}", digest_algorithms.len());

        // Read encapsulatedContentInfo
        let encap_content_info = reader.decode::<EncapsulatedContentInfo>()?;
        println!("eContent Type: {}", encap_content_info.econtent_type);

        if let Some(econtent) = encap_content_info.econtent {
            println!("eContent length: {} bytes", econtent.len());

            // This contains the actual SCEP PKI message
            // Try to parse it as another ContentInfo
            if let Ok(inner_ci) = ContentInfo::from_der(&econtent) {
                println!("Inner ContentInfo type: {}", inner_ci.content_type);
            }
        }

        // Skip certificates (the problematic part)
        // Certificates are OPTIONAL [0] IMPLICIT
        let certificates = if reader.peek_tag(der::Tag::context_specific(0))? {
            Some(reader.context_specific(der::Tag::context_specific(0), |reader| {
                // Parse as SET OF CertificateChoices
                let certs = CertChoices::decode(reader)?;
                println!("Number of certificates: {}", certs.len());
                Ok(certs)
            })?)
        } else {
            None
        };

        // Skip CRLs (OPTIONAL [1] IMPLICIT)
        let _crls = if reader.peek_tag(der::Tag::context_specific(1))? {
            Some(reader.context_specific(der::Tag::context_specific(1), |_| {
                // We'll just skip this for now
                Ok(())
            })?)
        } else {
            None
        };

        // Read signerInfos (SET OF)
        let signer_infos = reader.decode::<SignerInfos>()?;
        println!("Number of signers: {}", signer_infos.len());

        for (i, signer) in signer_infos.iter().enumerate() {
            println!("Signer {} version: {}", i + 1, signer.version);
            println!("Signer {} digest algorithm: {}", i + 1, signer.digest_alg.oid);
            println!("Signer {} signature algorithm: {}", i + 1, signer.signature_alg.oid);
        }

        Ok(())
    })?;

    Ok(())
}

fn print_signed_data_info(sd: &SignedData) {
    println!("SignedData version: {}", sd.version);
    println!("Number of digest algorithms: {}", sd.digest_algorithms.len());

    println!("eContent Type: {}", sd.encap_content_info.econtent_type);

    if let Some(ref econtent) = sd.encap_content_info.econtent {
        println!("eContent length: {} bytes", econtent.len());
    }

    if let Some(ref certs) = sd.certificates {
        println!("Number of certificates: {}", certs.len());
        for (i, cert_choice) in certs.iter().enumerate() {
            match cert_choice {
                cms::cert_choice::CertChoice::Certificate(cert) => {
                    println!("Certificate {}: Subject: {:?}", i + 1, cert.tbs_certificate.subject);
                    println!("  Issuer: {:?}", cert.tbs_certificate.issuer);
                    println!("  Serial: {}", cert.tbs_certificate.serial_number);
                }
                _ => println!("Certificate {}: Other type", i + 1),
            }
        }
    }

    println!("Number of signers: {}", sd.signer_infos.len());
    for (i, signer) in sd.signer_infos.iter().enumerate() {
        println!("Signer {} version: {}", i + 1, signer.version);
        println!("  Digest algorithm: {}", signer.digest_alg.oid);
        println!("  Signature algorithm: {}", signer.signature_alg.oid);

        // Print signed attributes if present
        if let Some(ref attrs) = signer.signed_attrs {
            println!("  Number of signed attributes: {}", attrs.len());
            for attr in attrs.iter() {
                println!("    Attribute OID: {}", attr.oid);
            }
        }
    }
}
```

This solution includes:

1. **Main parsing function** that handles the ContentInfo parsing
2. **Workaround function** for when certificate parsing fails - it manually parses the SignedData structure and skips problematic parts
3. **Proper error handling** with `anyhow` for better error messages
4. **Debug output** to understand the structure of the SCEP data

## Usage:
```bash
# Save your SCEP binary data to a file
cat scep_data.bin | cargo run

# Or if you have the data in a variable
echo "$SCEP_DATA" | base64 -d | cargo run
```

The key insights:
1. The issue is likely in the certificates field parsing
2. SCEP PKIOperation typically contains a SignedData with an encapsulated EnvelopedData
3. The workaround function manually parses the SignedData structure, which can help bypass parsing issues with certain certificate encodings
4. The actual SCEP message is in the `eContent` field of the SignedData

The code will print detailed information about the structure, which should help you understand what's in your SCEP data and debug any remaining issues.

