    let s2_state = Rc::new(RefCell::new(false));
    let r2_state = Rc::new(RefCell::new(false));

    // Create subjects that will proxy the state
    let mut s2_proxy = Local::subject::<bool, Infallible>();
    let mut r2_proxy = Local::subject::<bool, Infallible>();

    // Clone references for move into closures
    let s2_state_clone = Rc::clone(&s2_state);
    let r2_state_clone = Rc::clone(&r2_state);
    let mut s2_proxy_clone = s2_proxy.clone();
    let mut r2_proxy_clone = r2_proxy.clone();

    // Create observables that read from the state
    let s2_obs = s2_proxy.clone().start_with(vec![false]).box_it_clone();
    let r2_obs = r2_proxy.clone().start_with(vec![false]).box_it_clone();

    let q1 = nand("s", s, s2_obs);
    let q2 = nand("r", r, r2_obs);

    // Subscribe to q1 and update both state and proxy
    q1.clone().subscribe(move |a| {
        // Update the state
        let mut r2_state = r2_state_clone.borrow_mut();
        if *r2_state != a {
            *r2_state = a;
            // Emit through proxy
            r2_proxy_clone.next(a);
        }
    });

    // Subscribe to q2 and update both state and proxy
    q2.clone().subscribe(move |a| {
        // Update the state
        let mut s2_state = s2_state_clone.borrow_mut();
        if *s2_state != a {
            *s2_state = a;
            // Emit through proxy
            s2_proxy_clone.next(a);
        }
    });

    (q1.box_it_clone(), q2.box_it_clone())
}

fn main() {
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    q1.combine_latest(q2, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("Output: ({q1:?}, {q2:?})"));

    println!("\nTest sequence:");
    println!("(s: true, r: true) -> (q1: x, q2: x)");
    s.next(false); // (s: false, r: true) -> (q1: true, q2: false)
    s.next(true);  // (s: true, r: true) -> (q1: true, q2: false)
    r.next(false); // (s: true, r: false) -> (q1: false, q2: true)
    r.next(true);  // (s: true, r: true) -> (q1: false, q2: true)

    // Add a small delay to ensure all events are processed
    std::thread::sleep(std::time::Duration::from_millis(10));
}
