use core::sync::atomic::{AtomicUsize, Ordering};
use cortex_m::interrupt;

// Critical section implementation for single-core Cortex-M
struct CriticalSectionToken;

impl critical_section::CriticalSection for CriticalSectionToken {
    fn with<R>(f: impl FnOnce(&critical_section::RawRestoreState) -> R) -> R {
        interrupt::free(|_| f(&()))
    }
}

