    fn allocate_channel(&self) -> Option<usize> {
        // CORRECTED VERSION:
        // Using Ordering::SeqCst for both load and store inside the critical section
        // Why SeqCst?
        // 1. On thumbv6m, atomic operations are emulated via critical sections
        // 2. SeqCst ensures total ordering with respect to other atomic operations
        // 3. This is important for synchronization with interrupt handlers or other cores
        // 4. Relaxed ordering could allow reordering that breaks correctness
        let index = critical_section::with(|_| {
            // Use SeqCst to ensure proper synchronization
            let old_val = self.channel_index.load(Ordering::SeqCst);

            // Check bounds (wrap around)
            let new_val = if old_val + 1 >= Self::MAX_CHANNELS {
                0
            } else {
                old_val + 1
            };

            // Use SeqCst for store as well
            self.channel_index.store(new_val, Ordering::SeqCst);
            old_val
        });

        // Return the allocated channel index
        Some(index % Self::MAX_CHANNELS)
    }

    /// Get current channel index (for demonstration)
    fn get_current_index(&self) -> usize {
        // Even for reads, we need proper ordering if accessed from interrupts
        self.channel_index.load(Ordering::SeqCst)
    }
