fn draw_placement_indicator(
    mut hit_info: ResMut<HitInfo>,
    camera_query: Query<(&Camera, &GlobalTransform)>, 
    block_query: Query<(Entity, &GlobalTransform), With<Block>>,
    mut gizmos: Gizmos,
    windows: Query<&Window>,
    indicator_query: Query<Entity, With<PlacementIndicator>>,
    mut commands: Commands,
) {
    // Get camera info
    let (camera, camera_transform) = camera_query.single();
    let window = windows.single();

    // Reset hit info
    *hit_info = HitInfo {
        entity: None,
        normal: Vec3::ZERO,
        point: Vec3::ZERO,
    };

    // Get cursor position
    if let Some(cursor_pos) = window.cursor_position() {
        // Compute a ray from the camera through the cursor
        let ray = camera.viewport_to_world(camera_transform, cursor_pos);

        if let Some(ray) = ray {
            let mut closest_hit: Option<(Entity, Vec3, Vec3, f32)> = None;

            // Check intersection with all blocks
            for (entity, block_transform) in &block_query {
                // Transform ray to block's local space
                let inverse_transform = block_transform.compute_transform().inverse();
                let ray_origin_local = inverse_transform.transform_point(ray.origin);
                let ray_dir_local = inverse_transform.transform_vector(ray.direction);

                // Simple AABB intersection (unit cube centered at origin)
                let min = Vec3::new(-0.5, -0.5, -0.5);
                let max = Vec3::new(0.5, 0.5, 0.5);

                let t1 = (min - ray_origin_local) / ray_dir_local;
                let t2 = (max - ray_origin_local) / ray_dir_local;

                let tmin = Vec3::min(t1, t2);
                let tmax = Vec3::max(t1, t2);

                let t_entry = tmin.max_element();
                let t_exit = tmax.min_element();

                if t_entry < t_exit && t_exit > 0.0 {
                    let hit_distance = if t_entry > 0.0 { t_entry } else { t_exit };

                    // Calculate hit point in local space
                    let hit_point_local = ray_origin_local + ray_dir_local * hit_distance;

                    // Calculate normal in local space
                    let epsilon = 0.001;
                    let mut normal_local = Vec3::ZERO;

                    if (hit_point_local.x - min.x).abs() < epsilon {
                        normal_local = Vec3::new(-1.0, 0.0, 0.0);
                    } else if (hit_point_local.x - max.x).abs() < epsilon {
                        normal_local = Vec3::new(1.0, 0.0, 0.0);
                    } else if (hit_point_local.y - min.y).abs() < epsilon {
                        normal_local = Vec3::new(0.0, -1.0, 0.0);
                    } else if (hit_point_local.y - max.y).abs() < epsilon {
                        normal_local = Vec3::new(0.0, 1.0, 0.0);
                    } else if (hit_point_local.z - min.z).abs() < epsilon {
                        normal_local = Vec3::new(0.0, 0.0, -1.0);
                    } else if (hit_point_local.z - max.z).abs() < epsilon {
                        normal_local = Vec3::new(0.0, 0.0, 1.0);
                    }

                    // Transform to world space
                    let hit_point_world = block_transform.transform_point(hit_point_local);
                    let normal_world = block_transform.rotation * normal_local;

                    // Check if this is the closest hit
                    let distance = camera_transform.translation().distance(hit_point_world);

                    if closest_hit.map_or(true, |(_, _, _, d)| distance < d) {
                        closest_hit = Some((entity, hit_point_world, normal_world, distance));
                    }
                }
            }

            if let Some((entity, hit_point, normal, _)) = closest_hit {
                hit_info.entity = Some(entity);
                hit_info.normal = normal;
                hit_info.point = hit_point;

                // Get the block's transform
                if let Ok((_, block_transform)) = block_query.get(entity) {
                    let block_transform_mat = block_transform.compute_transform();

                    // Calculate face center
                    let face_center = block_transform_mat.translation + (normal * 0.5);

                    // Calculate the correct rotation for the placement indicator
                    // Method 1: Align Z axis with normal
                    let align_z_to_normal = Quat::from_rotation_arc(Vec3::Z, normal.normalize());

                    // Method 2: Get rotation that matches the block's face
                    // We need to find which axis of the block's local space aligns with the normal
                    let block_rotation = block_transform_mat.rotation;

                    // Transform normal to block's local space
                    let normal_local = block_rotation.inverse() * normal;

                    // Find which face we're hitting (largest component of normal_local)
                    let abs_normal = normal_local.abs();
                    let dominant_axis = if abs_normal.x > abs_normal.y && abs_normal.x > abs_normal.z {
                        Vec3::X
                    } else if abs_normal.y > abs_normal.z {
                        Vec3::Y
                    } else {
                        Vec3::Z
                    };

                    // Get the sign of the dominant axis
                    let sign = if normal_local.dot(dominant_axis) >= 0.0 { 1.0 } else { -1.0 };
                    let dominant_axis_with_sign = dominant_axis * sign;

                    // Create a rotation that aligns Z with the dominant axis in block's local space
                    let align_z_to_block_face = Quat::from_rotation_arc(Vec3::Z, dominant_axis_with_sign);

                    // Combine rotations: first align with block's face, then apply block's rotation
                    let final_rotation = block_rotation * align_z_to_block_face;

                    // Draw the placement indicator
                    let indicator_entity = indicator_query.single();
                    commands.entity(indicator_entity).insert(Visibility::Visible);

                    // Update transform of the placement indicator
                    commands.entity(indicator_entity).insert(Transform {
                        translation: face_center + normal * 0.01,
                        rotation: final_rotation,
                        scale: Vec3::splat(0.95),
                    });

                    // Also draw a gizmo for visualization
                    gizmos.cuboid(
                        Transform::from_translation(face_center + normal * 0.01)
                            .with_rotation(final_rotation)
                            .with_scale(Vec3::splat(0.95)),
                        Color::rgba(1.0, 1.0, 1.0, 0.5),
                    );

                    // Draw the normal
                    gizmos.ray(face_center, face_center + normal * 0.5, Color::RED);
                }
            } else {
                // Hide the placement indicator if no hit
                let indicator_entity = indicator_query.single();
                commands.entity(indicator_entity).insert(Visibility::Hidden);
            }
        }
    }
}"
