  "main.rs": "use serde::{Deserialize, Deserializer, Serialize, Serializer};
use serde::de::{self, Visitor, MapAccess, SeqAccess};
use std::fmt;

#[derive(Debug, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, PartialEq)]
enum B {
    Variant1 { y: i32 },
    Variant2 { z: String },
}

// Manual Serialize implementation for A
impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?;
        state.end()
    }
}

// Manual Deserialize implementation for A
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Define the visitor for struct A
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x = None;
                let mut b = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        "x" => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            b = Some(map.next_value()?);
                        }
                        _ => {
                            // Ignore unknown fields
                            let _: de::IgnoredAny = map.next_value()?;
                        }
                    }
                }

                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| de::Error::missing_field("b"))?;
                Ok(A { x, b })
            }
        }

        deserializer.deserialize_map(AVisitor)
    }
}

// Manual Serialize implementation for B
impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::Variant1 { y } => {
                let mut state = serializer.serialize_struct("Variant1", 1)?;
                state.serialize_field("y", y)?;
                state.end()
            }
            B::Variant2 { z } => {
                let mut state = serializer.serialize_struct("Variant2", 1)?;
                state.serialize_field("z", z)?;
                state.end()
            }
        }
    }
}

// Manual Deserialize implementation for B
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Define the visitor for enum B
        enum Field {
            Variant1,
            Variant2,
        }

        impl<'de> Deserialize<'de> for Field {
            fn deserialize<D>(deserializer: D) -> Result<Field, D::Error>
            where
                D: Deserializer<'de>,
            {
                struct FieldVisitor;

                impl<'de> Visitor<'de> for FieldVisitor {
                    type Value = Field;

                    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                        formatter.write_str("`Variant1` or `Variant2`")
                    }

                    fn visit_str<E>(self, value: &str) -> Result<Field, E>
                    where
                        E: de::Error,
                    {
                        match value {
                            "Variant1" => Ok(Field::Variant1),
                            "Variant2" => Ok(Field::Variant2),
                            _ => Err(de::Error::unknown_variant(value, VARIANTS)),
                        }
                    }
                }

                deserializer.deserialize_identifier(FieldVisitor)
            }
        }

        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("enum B")
            }

            fn visit_enum<A>(self, data: A) -> Result<B, A::Error>
            where
                A: de::EnumAccess<'de>,
            {
                match data.variant()? {
                    (Field::Variant1, variant) => {
                        // Deserialize the struct Variant1
                        let (y,) = variant.struct_variant(&["y"], Variant1Visitor)?;
                        Ok(B::Variant1 { y })
                    }
                    (Field::Variant2, variant) => {
                        // Deserialize the struct Variant2
                        let (z,) = variant.struct_variant(&["z"], Variant2Visitor)?;
                        Ok(B::Variant2 { z })
                    }
                }
            }
        }

        // Visitors for each variant's struct
        struct Variant1Visitor;
        impl<'de> Visitor<'de> for Variant1Visitor {
            type Value = (i32,);

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct Variant1 with field `y`")
            }

            fn visit_seq<V>(self, mut seq: V) -> Result<(i32,), V::Error>
            where
                V: SeqAccess<'de>,
            {
                let y = seq
                    .next_element()?
                    .ok_or_else(|| de::Error::invalid_length(0, &self))?;
                Ok((y,))
            }

            fn visit_map<V>(self, mut map: V) -> Result<(i32,), V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut y = None;
                while let Some(key) = map.next_key()? {
                    match key {
                        "y" => {
                            if y.is_some() {
                                return Err(de::Error::duplicate_field("y"));
                            }
                            y = Some(map.next_value()?);
                        }
                        _ => {
                            return Err(de::Error::unknown_field(key, &["y"]));
                        }
                    }
                }
                let y = y.ok_or_else(|| de::Error::missing_field("y"))?;
                Ok((y,))
            }
        }

        struct Variant2Visitor;
        impl<'de> Visitor<'de> for Variant2Visitor {
            type Value = (String,);

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct Variant2 with field `z`")
            }

            fn visit_seq<V>(self, mut seq: V) -> Result<(String,), V::Error>
            where
                V: SeqAccess<'de>,
            {
                let z = seq
                    .next_element()?
                    .ok_or_else(|| de::Error::invalid_length(0, &self))?;
                Ok((z,))
            }

            fn visit_map<V>(self, mut map: V) -> Result<(String,), V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut z = None;
                while let Some(key) = map.next_key()? {
                    match key {
                        "z" => {
                            if z.is_some() {
                                return Err(de::Error::duplicate_field("z"));
                            }
                            z = Some(map.next_value()?);
                        }
                        _ => {
                            return Err(de::Error::unknown_field(key, &["z"]));
                        }
                    }
                }
                let z = z.ok_or_else(|| de::Error::missing_field("z"))?;
                Ok((z,))
            }
        }

        const VARIANTS: &[&str] = &["Variant1", "Variant2"];
        deserializer.deserialize_enum("B", VARIANTS, BVisitor)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Example usage
    let a = A {
        x: 42,
        b: vec![B::Variant1 { y: 10 }, B::Variant2 { z: "hello".to_string() }],
    };

    // Serialize to JSON
    let json = serde_json::to_string(&a)?;
    println!("Serialized A: {}", json);

    // Deserialize from JSON
    let deserialized_a: A = serde_json::from_str(&json)?;
    println!("Deserialized A: {:?}", deserialized_a);

    // Verify round-trip
    assert_eq!(a, deserialized_a);
    println!("Round-trip successful!");
    Ok(())
}
