use dioxus::prelude::*;
use dioxus::signals::Signal;

// Custom event system using channels
use std::sync::Arc;

#[derive(Debug, Clone)]
struct DragEvent {
    pub x: f64,
    pub y: f64,
    pub event_type: DragEventType,
}

#[derive(Debug, Clone, PartialEq)]
enum DragEventType {
    Start,
    Move,
    End,
}

// Custom event emitter
#[derive(Clone)]
struct DragEventHandler {
    sender: Arc<corroded_channel::Sender<DragEvent>>,
}

impl DragEventHandler {
    fn new() -> (Self, corroded_channel::Receiver<DragEvent>) {
        let (sender, receiver) = corroded_channel::unbounded();
        (
            Self {
                sender: Arc::new(sender),
            },
            receiver,
        )
    }

    fn emit_start(&self, x: f64, y: f64) {
        let _ = self.sender.send(DragEvent {
            x,
            y,
            event_type: DragEventType::Start,
        });
    }

    fn emit_move(&self, x: f64, y: f64) {
        let _ = self.sender.send(DragEvent {
            x,
            y,
            event_type: DragEventType::Move,
        });
    }

    fn emit_end(&self, x: f64, y: f64) {
        let _ = self.sender.send(DragEvent {
            x,
            y,
            event_type: DragEventType::End,
        });
    }
}

// Context provider
#[derive(Clone)]
struct DragContext {
    pub handler: DragEventHandler,
    pub is_dragging: Signal<bool>,
    pub current_pos: Signal<(f64, f64)>,
}

impl DragContext {
    fn new() -> (Self, corroded_channel::Receiver<DragEvent>) {
        let (handler, receiver) = DragEventHandler::new();
        (
            Self {
                handler,
                is_dragging: Signal::new(false),
                current_pos: Signal::new((0.0, 0.0)),
            },
            receiver,
        )
    }
}

#[component]
fn DragProvider(children: Element) -> Element {
    let (drag_context, mut receiver) = DragContext::new();

    // Process drag events
    use_future(move || async move {
        while let Some(event) = receiver.next().await {
            match event.event_type {
                DragEventType::Start => {
                    drag_context.is_dragging.set(true);
                    drag_context.current_pos.set((event.x, event.y));
                }
                DragEventType::Move => {
                    if *drag_context.is_dragging.read() {
                        drag_context.current_pos.set((event.x, event.y));
                    }
                }
                DragEventType::End => {
                    drag_context.is_dragging.set(false);
                }
            }
        }
    });

    rsx! {
        div {
            // Capture drag events on the entire area
            onmousedown: move |e| {
                drag_context.handler.emit_start(
                    e.element_coordinates().x as f64,
                    e.element_coordinates().y as f64,
                );
            },
            onmousemove: move |e| {
                if *drag_context.is_dragging.read() {
                    drag_context.handler.emit_move(
                        e.element_coordinates().x as f64,
                        e.element_coordinates().y as f64,
                    );
                }
            },
            onmouseup: move |e| {
                drag_context.handler.emit_end(
                    e.element_coordinates().x as f64,
                    e.element_coordinates().y as f64,
                );
            },
            onmouseleave: move |e| {
                drag_context.handler.emit_end(
                    e.element_coordinates().x as f64,
                    e.element_coordinates().y as f64,
                );
            },

            // Provide context to children
            ContextProvider {
                value: drag_context,
                children: [children]
            }
        }
    }
}

#[component]
fn DraggablePoint(
    initial_x: f64,
    initial_y: f64,
    on_position_change: Option<EventHandler<(f64, f64)>>,
) -> Element {
    let mut position = use_signal(|| (initial_x, initial_y));
    let drag_context = use_context::<DragContext>();

    // Subscribe to drag events
    let mut subscription = use_signal(|| None);

    use_effect(move || {
        // Subscribe to drag events
        let mut receiver = drag_context.handler.sender.subscribe();

        subscription.set(Some(use_coroutine(|mut rx: UnboundedReceiver<DragEvent>| async move {
            while let Some(event) = rx.next().await {
                if *drag_context.is_dragging.read() {
                    match event.event_type {
                        DragEventType::Move => {
                            // Update position
                            position.set((event.x, event.y));

                            // Call callback if provided
                            if let Some(callback) = &on_position_change {
                                callback.call((event.x, event.y));
                            }
                        }
                        _ => {}
                    }
                }
            }
        })));
    });

    rsx! {
        circle {
            class: "point",
            cx: "{position().0}",
            cy: "{position().1}",
            r: "5",
            fill: "red",

            // Start dragging when clicking on the point
            onmousedown: move |e| {
                e.stop_propagation();
                drag_context.handler.emit_start(
                    e.element_coordinates().x as f64,
                    e.element_coordinates().y as f64,
                );
            },
        }
    }
}

#[component]
fn App() -> Element {
    let mut positions = use_signal(|| vec![(100.0, 100.0), (200.0, 200.0), (300.0, 100.0)]);

    rsx! {
        div {
            h1 { "Custom Events with Draggable Points" }
            p { "Drag the red points around. The drag continues even when mouse leaves the element." }

            DragProvider {
                svg {
                    width: "500",
                    height: "300",
                    style: "border: 1px solid black",

                    for (i, (x, y)) in positions.iter().enumerate() {
                        DraggablePoint {
                            initial_x: *x,
                            initial_y: *y,
                            on_position_change: move |new_pos| {
                                let mut pos = positions.write();
                                pos[i] = new_pos;
                            }
                        }
                    }
                }
            }

            div {
                style: "margin-top: 20px",
                "Current positions:"
                ul {
                    for (i, (x, y)) in positions.iter().enumerate() {
                        li { "Point {i}: ({x:.1}, {y:.1})" }
                    }
                }
            }
        }
    }
}

fn main() {
    launch(App);
}"
