    pub fn new(array: &'a mut Array<T>) -> Self {
        Self {
            data: &mut array.store,
            index: 0,
            dims: array.dims.clone(),
        }
    }

    // Convert linear index to cartesian index
    fn linear_to_cartesian(&self, idx: usize) -> Vec<usize> {
        let mut result = vec![0; self.dims.len()];
        let mut remaining = idx;
        let mut stride = 1;

        for i in 1..self.dims.len() {
            stride *= self.dims[i];
        }

        for i in 0..self.dims.len() {
            if stride > 0 {
                result[i] = remaining / stride;
                remaining %= stride;
            }
            if i + 1 < self.dims.len() {
                stride /= self.dims[i + 1];
            }
        }
        result
