## main.rs

```rust
use anyhow::{Context, Result};
use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use futures::stream::{FuturesUnordered, StreamExt};
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use tokio::sync::Semaphore;
use tracing::{debug, error, info, instrument, Level};

#[derive(Debug, Deserialize, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct TradeData {
    // Replace with your actual TradeData fields
    // Example:
    // pub id: String,
    // pub timestamp: i64,
    // pub price: f64,
    // pub quantity: f64,
    #[serde(flatten)]
    pub data: serde_json::Value,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

struct AzureBlobService {
    container_client: ContainerClient,
    max_concurrent_downloads: usize,
}

impl AzureBlobService {
    async fn new() -> Result<Self> {
        let tenant_id = env::var("AZURE_TENANT_ID")
            .context("Missing AZURE_TENANT_ID environment variable")?;
        let client_id = env::var("AZURE_CLIENT_ID")
            .context("Missing AZURE_CLIENT_ID environment variable")?;
        let client_secret = env::var("AZURE_CLIENT_SECRET")
            .context("Missing AZURE_CLIENT_SECRET environment variable")?;
        let storage_account = env::var("AZURE_ACCOUNT_NAME")
            .context("Missing AZURE_ACCOUNT_NAME environment variable")?;
        let container_name = env::var("AZURE_CONTAINER_NAME")
            .context("Missing AZURE_CONTAINER_NAME environment variable")?;

        info!("Authenticating to Azure Blob Storage...");
        let token = get_oauth_token(&tenant_id, &client_id, &client_secret)
            .await
            .context("Failed to get OAuth token")?;

        let credentials = StorageCredentials::bearer_token(token);
        let blob_service = BlobServiceClient::new(storage_account, credentials);
        let container_client = blob_service.container_client(container_name);

        // Use number of CPU cores for concurrency
        let max_concurrent_downloads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(8);

        info!("Max concurrent downloads: {}", max_concurrent_downloads);

        Ok(Self {
            container_client,
            max_concurrent_downloads,
        })
    }

    #[instrument(skip(self))]
    async fn list_blobs(&self, prefix: &str) -> Result<Vec<String>> {
        info!("Listing blobs with prefix: {}", prefix);
        let mut blob_names = Vec::new();
        let mut stream = self.container_client.list_blobs().prefix(prefix).into_stream();

        while let Some(response) = stream.next().await {
            let response = response.context("Failed to list blobs")?;
            for blob in response.blobs.blobs() {
                if blob.name.ends_with(".json") {
                    blob_names.push(blob.name.clone());
                }
            }
        }

        info!("Found {} blobs", blob_names.len());
        Ok(blob_names)
    }

    #[instrument(skip(self))]
    async fn download_and_parse_blob(&self, blob_name: &str) -> Result<TradeData> {
        debug!("Downloading blob: {}", blob_name);
        let blob_client = self.container_client.blob_client(blob_name);

        let response = blob_client
            .get_content()
            .await
            .with_context(|| format!("Failed to download blob: {}", blob_name))?;

        let trade_data = serde_json::from_slice(&response)
            .with_context(|| format!("Failed to parse JSON from blob: {}", blob_name))?;

        Ok(trade_data)
    }

    #[instrument(skip(self))]
    async fn load_trades_from_prefix(&self, prefix: &str) -> Result<Vec<TradeData>> {
        info!("Loading trades from prefix: {}", prefix);
        let start = std::time::Instant::now();

        let blob_names = self.list_blobs(prefix).await?;

        if blob_names.is_empty() {
            info!("No blobs found for prefix: {}", prefix);
            return Ok(Vec::new());
        }

        // Create a semaphore to limit concurrent downloads
        let semaphore = Arc::new(Semaphore::new(self.max_concurrent_downloads));

        // Create all download tasks
        let tasks: FuturesUnordered<_> = blob_names
            .into_iter()
            .map(|blob_name| {
                let container_client = self.container_client.clone();
                let semaphore = Arc::clone(&semaphore);

                tokio::spawn(async move {
                    // Acquire permit before downloading
                    let _permit = semaphore.acquire().await.expect("Semaphore closed");

                    let result = async {
                        let blob_client = container_client.blob_client(&blob_name);
                        let response = blob_client
                            .get_content()
                            .await
                            .with_context(|| format!("Failed to download: {}", blob_name))?;

                        let trade_data = serde_json::from_slice(&response)
                            .with_context(|| format!("Failed to parse JSON: {}", blob_name))?;

                        Ok::<TradeData, anyhow::Error>(trade_data)
                    }.await;

                    (blob_name, result)
                })
            })
            .collect();

        // Collect results
        let mut trades = Vec::new();
        let mut successful = 0;
        let mut failed = 0;

        for task in tasks {
            match task.await {
                Ok((blob_name, Ok(trade))) => {
                    trades.push(trade);
                    successful += 1;
                    debug!("Successfully processed: {}", blob_name);
                }
                Ok((blob_name, Err(e))) => {
                    error!("Failed to process {}: {}", blob_name, e);
                    failed += 1;
                }
                Err(join_err) => {
                    error!("Task panicked: {}", join_err);
                    failed += 1;
                }
            }
        }

        let duration = start.elapsed();
        info!(
            "Processed prefix {}: {} successful, {} failed, took {:.2}s",
            prefix,
            successful,
            failed,
            duration.as_secs_f32()
        );

        Ok(trades)
    }

    #[instrument(skip(self))]
    async fn fetch_all_trades(&self, prefixes: &[&str]) -> Result<Vec<TradeData>> {
        info!("Fetching trades from {} prefixes", prefixes.len());
        let start = std::time::Instant::now();

        let mut tasks = Vec::new();
        for &prefix in prefixes {
            let service = self;
            tasks.push(async move { service.load_trades_from_prefix(prefix).await });
        }

        let results = futures::future::join_all(tasks).await;

        let mut all_trades = Vec::new();
        for (prefix, result) in prefixes.iter().zip(results) {
            match result {
                Ok(trades) => {
                    info!("Prefix {}: {} trades", prefix, trades.len());
                    all_trades.extend(trades);
                }
                Err(e) => error!("Failed to process prefix {}: {}", prefix, e),
            }
        }

        let duration = start.elapsed();
        info!(
            "Total: {} trades in {:.2}s",
            all_trades.len(),
            duration.as_secs_f32()
        );

        Ok(all_trades)
    }
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String> {
    debug!("Getting OAuth token");
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );

    let params = [
        ("grant_type", "client_credentials"),
        ("client_id", client_id),
        ("client_secret", client_secret),
        ("scope", "https://storage.azure.com/.default"),
    ];

    let client = reqwest::Client::new();
    let response = client
        .post(&token_url)
        .form(&params)
        .send()
        .await
        .context("Failed to send token request")?;

    if !response.status().is_success() {
        let status = response.status();
        let body = response.text().await.unwrap_or_default();
        return Err(anyhow::anyhow!(
            "Token endpoint returned {}: {}",
            status,
            body
        ));
    }

    let token_response: TokenResponse = response
        .json()
        .await
        .context("Failed to parse token response")?;

    Ok(token_response.access_token)
}

#[tokio::main]
async fn main() -> Result<()> {
    // Initialize logging
    tracing_subscriber::fmt()
        .with_max_level(Level::INFO)
        .init();

    info!("Starting Azure Blob downloader");

    // Load prefixes from environment (or use defaults)
    let prefixes: Vec<String> = env::var("AZURE_PREFIXES")
        .map(|s| s.split(',').map(|p| p.trim().to_string()).collect())
        .unwrap_or_else(|_| vec![
            "options/".to_string(),
            "futures/".to_string(),
        ]);

    let prefix_strs: Vec<&str> = prefixes.iter().map(|s| s.as_str()).collect();

    // Create the service
    let service = AzureBlobService::new().await?;

    // Fetch all trades
    let trades = service.fetch_all_trades(&prefix_strs).await?;

    info!("Successfully downloaded {} trades", trades.len());

    // Do something with the trades...
    // Example: print first trade if any
    if let Some(first_trade) = trades.first() {
        debug!("First trade: {:?}", first_trade);
    }

    Ok(())
}
```

## Key Optimizations:

1. **Proper Concurrency**: Uses `tokio::spawn` with a semaphore to limit concurrent downloads to CPU core count, similar to C#'s `MaxDegreeOfParallelism`.

2. **Clone Container Client**: The `ContainerClient` is cloned for each task (it's cheap - just an `Arc` internally) to avoid lifetime issues.

3. **Efficient Error Handling**: Uses `anyhow` for better error context without losing performance.

4. **Streaming Parsing**: Processes blobs as they complete rather than waiting for entire pages.

5. **Tracing**: Better logging to identify bottlenecks.

6. **Clean Architecture**: Separates concerns into methods similar to the C# version.

## To use:

1. Copy both files into a new Rust project
2. Set environment variables:
   ```
   AZURE_TENANT_ID=your_tenant_id
   AZURE_CLIENT_ID=your_client_id
   AZURE_CLIENT_SECRET=your_client_secret
   AZURE_ACCOUNT_NAME=your_account_name
   AZURE_CONTAINER_NAME=your_container_name
   AZURE_PREFIXES=prefix1/,prefix2/  # optional, comma-separated
   ```
3. Update the `TradeData` struct with your actual fields
4. Run with `cargo run --release`

This should give you performance comparable to or better than the C# version, as it properly parallelizes downloads across all blobs rather than processing them in page-sized batches.

