  "main.rs": "use std::iter::Peekable;

/// Tokenizes a string according to shell rules, respecting single quotes.
/// This handles whitespace as delimiters except inside quotes.
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut chars = input.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            // Whitespace outside quotes - skip it
            ' ' | '\t' | '\n' => {
                // Just skip leading/trailing whitespace
                continue;
            }

            // Single quote - start quoted segment
            '\'' => {
                let mut token = String::new();

                // Collect everything until the closing quote
                while let Some(ch) = chars.next() {
                    if ch == '\'' {
                        break;  // End of quoted segment
                    }
                    token.push(ch);
                }

                // Handle the special case where quoted segment is immediately
                // followed by non-whitespace (like 'two  'three)
                handle_concatenation(&mut tokens, &mut chars, token);
            }

            // Regular character - start a regular token
            _ => {
                let mut token = String::new();
                token.push(ch);

                // Collect until whitespace or quote
                while let Some(&next_ch) = chars.peek() {
                    if next_ch == ' ' || next_ch == '\t' || next_ch == '\n' || next_ch == '\'' {
                        break;
                    }
                    token.push(chars.next().unwrap());
                }

                // If we hit a quote after this token, handle concatenation
                if let Some(&'\'') = chars.peek() {
                    chars.next(); // Consume the quote
                    let mut quoted_part = String::new();

                    // Collect quoted part
                    while let Some(ch) = chars.next() {
                        if ch == '\'' {
                            break;
                        }
                        quoted_part.push(ch);
                    }

                    // Concatenate with previous token
                    token.push_str(&quoted_part);
                    handle_concatenation(&mut tokens, &mut chars, token);
                } else {
                    tokens.push(token);
                }
            }
        }
    }

    tokens
}

/// Helper function to handle concatenation of tokens when a quoted segment
/// is immediately followed by non-whitespace characters.
fn handle_concatenation<I: Iterator<Item = char>>(
    tokens: &mut Vec<String>,
    chars: &mut Peekable<I>,
    mut current_token: String,
) {
    // Skip whitespace after the quoted segment
    while let Some(&ch) = chars.peek() {
        if ch == ' ' || ch == '\t' || ch == '\n' {
            chars.next(); // Skip whitespace
            tokens.push(current_token);
            return;
        }
        break;
    }

    // If next character is not whitespace, collect it into current token
    if let Some(&ch) = chars.peek() {
        if ch != '\'' {  // Not starting a new quote
            // Collect all non-whitespace characters
            while let Some(&next_ch) = chars.peek() {
                if next_ch == ' ' || next_ch == '\t' || next_ch == '\n' || next_ch == '\'' {
                    break;
                }
                current_token.push(chars.next().unwrap());
            }
        }
    }

    tokens.push(current_token);
}

fn main() {
    // Test cases
    let test_cases = vec![
        (" one  ' two  'three    four", vec!["one", " two  three", "four"]),
        ("'one'  ' two  'three    four", vec!["one", " two  three", "four"]),
        ("echo 'hello world'", vec!["echo", "hello world"]),
        ("ls -la | grep 'some file'", vec!["ls", "-la", "|", "grep", "some file"]),
        ("foo bar'baz'qux", vec!["foo", "barbazqux"]),
        ("a'b'c d", vec!["abc", "d"]),
        ("'', '', '',", vec!["", "", "", ""]),
        ("", vec![]),
        ("    ", vec![]),
        ("'single token'", vec!["single token"]),
    ];

    for (input, expected) in test_cases {
        let result = tokenize(input);
        println!("Input:    '{}'", input);
        println!("Expected: {:?}", expected);
        println!("Got:      {:?}", result);
        println!("Match:    {}\n", result == expected);
    }
}
