/// Creates a DateTime<Utc> with millisecond precision without using deprecated methods.
/// This is the recommended approach in newer versions of chrono.
fn create_datetime_with_millis(
    year: i32,
    month: u32,
    day: u32,
    hour: u32,
    minute: u32,
    second: u32,
    millis: u32,
) -> Option<DateTime<Utc>> {
    // Step 1: Create a NaiveDate (year-month-day)
    let date = NaiveDate::from_ymd_opt(year, month, day)?;

    // Step 2: Create a NaiveTime with milliseconds
    // Note: nanoseconds = milliseconds * 1_000_000
    let time = NaiveTime::from_hms_milli_opt(hour, minute, second, millis)?;

    // Step 3: Combine them into a NaiveDateTime
    let naive_datetime = NaiveDateTime::new(date, time);

    // Step 4: Convert to DateTime<Utc>
    Some(Utc.from_utc_datetime(&naive_datetime))
}

/// Alternative approach using the `with_ymd_and_hms` method and then adding milliseconds
fn create_datetime_with_and_then_millis(
    year: i32,
    month: u32,
    day: u32,
    hour: u32,
    minute: u32,
    second: u32,
    millis: u32,
) -> Option<DateTime<Utc>> {
    // First create with second precision
    let datetime = Utc.with_ymd_and_hms(year, month, day, hour, minute, second).single()?;

    // Then add milliseconds
    // We need to be careful with overflow, but milliseconds are safe within 0-999
    Some(datetime + chrono::Duration::milliseconds(millis as i64))
}

/// Example of parsing from a string with known format
fn parse_from_string() -> Option<DateTime<Utc>> {
    let dt_str = "2024-01-15T14:30:45.123Z";
    DateTime::parse_from_rfc3339(dt_str)
        .ok()
        .map(|dt| dt.with_timezone(&Utc))
}

fn main() {
    // Example 1: Using the recommended approach
    println!("=== Example 1: Recommended approach ===");
    if let Some(dt) = create_datetime_with_millis(2024, 1, 15, 14, 30, 45, 123) {
        println!("Created: {}", dt);
        println!("  Year: {}, Month: {}, Day: {}", 
                 dt.year(), dt.month(), dt.day());
        println!("  Hour: {}, Minute: {}, Second: {}, Millisecond: {}",
                 dt.hour(), dt.minute(), dt.second(), dt.timestamp_subsec_millis());
    } else {
        println!("Failed to create datetime (invalid parameters)");
    }

    // Example 2: Alternative approach
    println!("\n=== Example 2: Alternative approach ===");
    if let Some(dt) = create_datetime_with_and_then_millis(2024, 1, 15, 14, 30, 45, 123) {
        println!("Created: {}", dt);
        println!("  Milliseconds: {}", dt.timestamp_subsec_millis());
    } else {
        println!("Failed to create datetime (invalid parameters)");
    }

    // Example 3: From RFC 3339 string
    println!("\n=== Example 3: From RFC 3339 string ===");
    if let Some(dt) = parse_from_string() {
        println!("Parsed: {}", dt);
        println!("  Milliseconds: {}", dt.timestamp_subsec_millis());
    } else {
        println!("Failed to parse datetime");
    }

    // Example 4: What happens with invalid dates
    println!("\n=== Example 4: Invalid date handling ===");
    match create_datetime_with_millis(2024, 2, 30, 25, 61, 61, 9999) {
