  "main.rs": "use std::collections::HashMap;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::Duration;

use anyhow::{anyhow, Context, Result};
expectrl::{ControlCode, Pty, PtySession, Session, WaitStatus};
nix::libc;
use serde::{Deserialize, Serialize};
tauri::Manager;
tokio::sync::{mpsc, Mutex, RwLock};

// State to manage multiple PTY sessions
struct PtyManager {
    sessions: RwLock<HashMap<u32, Arc<PtySessionData>>>,
    next_id: Mutex<u32>,
}

struct PtySessionData {
    id: u32,
    // Split reader/writer to avoid mutex deadlock
    reader: Mutex<expectrl::Reader>,
    writer: Mutex<expectrl::Writer>,
    process: Mutex<expectrl::Pty>, // Keep for process management
    window: tauri::Window,
    running: AtomicBool,
}

#[derive(Clone, Serialize)]
struct PtyOutput {
    id: u32,
    data: String,
}

#[derive(Clone, Serialize)]
struct PtyExit {
    id: u32,
    status: i32,
}

#[derive(Deserialize)]
struct PtyInput {
    id: u32,
    data: String,
}

#[tauri::command]
async fn spawn_pty(
    command: String,
    args: Vec<String>,
    window: tauri::Window,
    state: tauri::State<'_, PtyManager>,
) -> Result<u32, String> {
    let id = {
        let mut next_id = state.next_id.lock().await;
        let id = *next_id;
        *next_id += 1;
        id
    };

    // Spawn process with PTY
    let mut session = Session::spawn(command, args)
        .map_err(|e| format!("Failed to spawn PTY: {}", e))?;

    // Set terminal environment for better compatibility
    session.set_env("TERM", "xterm-256color");

    // Split into separate reader/writer
    let (reader, writer) = session.split();
    let pty = session.into_pty().ok_or("Failed to get PTY")?;

    let session_data = Arc::new(PtySessionData {
        id,
        reader: Mutex::new(reader),
        writer: Mutex::new(writer),
        process: Mutex::new(pty),
        window: window.clone(),
        running: AtomicBool::new(true),
    });

    // Store session
    state.sessions.write().await.insert(id, session_data.clone());

    // Spawn reader thread (non-blocking)
    let session_clone = session_data.clone();
    thread::spawn(move || {
        read_loop(session_clone);
    });

    Ok(id)
}

fn read_loop(session: Arc<PtySessionData>) {
    let mut buf = [0u8; 8192];

    while session.running.load(Ordering::SeqCst) {
        // Use non-blocking read with timeout
        match session.reader.try_lock() {
            Ok(mut reader) => {
                // Try to read with a short timeout
                if let Ok(Some(bytes_read)) = reader.read_timeout(&mut buf, Duration::from_millis(100)) {
                    if bytes_read > 0 {
                        let output = String::from_utf8_lossy(&buf[..bytes_read]).to_string();

                        // Emit to frontend
                        let _ = session.window.emit(
                            "pty-output",
                            PtyOutput {
                                id: session.id,
                                data: output,
                            },
                        );
                    }
                }
                // Drop lock immediately after read
            }
            Err(_) => {
                // Lock contention, sleep briefly and retry
                thread::sleep(Duration::from_millis(10));
            }
        }

        // Small sleep to prevent busy looping
        thread::sleep(Duration::from_millis(1));
    }
}

#[tauri::command]
async fn write_to_pty(
    input: PtyInput,
    state: tauri::State<'_, PtyManager>,
) -> Result<(), String> {
    let sessions = state.sessions.read().await;
    let session = sessions
        .get(&input.id)
        .ok_or_else(|| format!("Session {} not found", input.id))?;

    // Acquire writer lock (should be quick)
    let mut writer = session.writer.try_lock()
        .map_err(|_| "Writer busy, try again")?;

    writer.write_all(input.data.as_bytes())
        .map_err(|e| format!("Write failed: {}", e))?;

    Ok(())
}

#[tauri::command]
async fn resize_pty(
    id: u32,
    cols: u16,
    rows: u16,
    state: tauri::State<'_, PtyManager>,
) -> Result<(), String> {
    let sessions = state.sessions.read().await;
    let session = sessions
        .get(&id)
        .ok_or_else(|| format!("Session {} not found", id))?;

    let mut process = session.process.lock().await;
    process.resize(cols, rows)
        .map_err(|e| format!("Resize failed: {}", e))?;

    Ok(())
}

#[tauri::command]
async fn kill_pty(
    id: u32,
    state: tauri::State<'_, PtyManager>,
) -> Result<(), String> {
    let mut sessions = state.sessions.write().await;
    if let Some(session) = sessions.remove(&id) {
        session.running.store(false, Ordering::SeqCst);

        // Send SIGTERM then SIGKILL
        if let Ok(mut process) = session.process.try_lock() {
            let _ = process.send_control(ControlCode::EndOfText); // Ctrl+C

            // Give process time to terminate
            thread::sleep(Duration::from_millis(100));

            let _ = process.kill();
        }

        // Notify frontend
        let _ = session.window.emit(
            "pty-exit",
            PtyExit { id, status: 0 },
        );
    }

    Ok(())
}

fn main() {
    tauri::Builder::default()
        .setup(|app| {
            // Create PTY manager
            let manager = PtyManager {
                sessions: RwLock::new(HashMap::new()),
                next_id: Mutex::new(1),
            };

            app.manage(manager);

            // Cleanup on app exit
            let app_handle = app.handle();
            app_handle.on_window_event(move |event| {
                if let tauri::WindowEvent::Destroyed = event.event() {
                    // Kill all PTY sessions when window closes
                    let app_handle = app_handle.clone();
                    tauri::async_runtime::spawn(async move {
                        if let Some(manager) = app_handle.try_state::<PtyManager>() {
                            let sessions = manager.sessions.read().await;
                            let ids: Vec<u32> = sessions.keys().copied().collect();
                            drop(sessions);

                            for id in ids {
