impl MetadataFilter for DictWordMetadata {
    fn matches(&self, filter: &DictWordMetadata) -> bool {
        // Check each field in the filter
        // If the filter has Some(value), then self must match that value
        // If the filter has None, we don't care about that field

        // Helper function for comparing optional fields
        fn check_opt<T: PartialEq>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => a == b, // Both must be Some and equal
                None => true, // Filter doesn't care about this field
            }
        }

        // Helper function for comparing optional structs recursively
        fn check_opt_struct<T: MetadataFilter>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => {
                    match a {
                        Some(a_val) => a_val.matches(filter_val),
                        None => false, // Filter wants Some but we have None
                    }
                }
                None => true, // Filter doesn't care
            }
        }

        // Check each field
        if !check_opt_struct(&self.noun, &filter.noun) {
            return false;
        }

        if !check_opt(&self.pronoun, &filter.pronoun) {
            return false;
        }

        if !check_opt_struct(&self.verb, &filter.verb) {
            return false;
        }

        if !check_opt_struct(&self.adjective, &filter.adjective) {
            return false;
        }

        if !check_opt(&self.adverb, &filter.adverb) {
            return false;
        }

        if !check_opt(&self.conjunction, &filter.conjunction) {
            return false;
        }

        if !check_opt(&self.swear, &filter.swear) {
            return false;
        }

        // For non-Option fields with defaults, we need to check if filter has non-default
        // Since we can't know if filter's value is "intentional" or just default,
        // we assume any value in filter is intentional
        if filter.dialects != DialectFlags::default() && self.dialects != filter.dialects {
            return false;
        }

        if filter.orth_info != OrthFlags::empty() && self.orth_info != filter.orth_info {
            return false;
        }

        if !check_opt_struct(&self.determiner, &filter.determiner) {
            return false;
        }

        // For bool fields with defaults
        if filter.preposition != default_false() && self.preposition != filter.preposition {
            return false;
        }

        if filter.common != default_false() && self.common != filter.common {
            return false;
        }

        if !check_opt(&self.derived_from, &filter.derived_from) {
            return false;
        }

        if !check_opt(&self.np_member, &filter.np_member) {
            return false;
        }

        if !check_opt(&self.pos_tag, &filter.pos_tag) {
            return false;
        }

        if !check_opt(&self.stress, &filter.stress) {
            return false;
        }

        if !check_opt(&self.gender, &filter.gender) {
            return false;
        }

        true
    }
}

// Implement MetadataFilter for nested structs
impl MetadataFilter for NounData {
    fn matches(&self, filter: &NounData) -> bool {
        fn check_opt<T: PartialEq>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => a == b,
                None => true,
            }
        }

        check_opt(&self.plural, &filter.plural) && check_opt(&self.proper, &filter.proper)
    }
}

impl MetadataFilter for VerbData {
    fn matches(&self, filter: &VerbData) -> bool {
        fn check_opt<T: PartialEq>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => a == b,
                None => true,
            }
        }

        check_opt(&self.transitive, &filter.transitive) && check_opt(&self.irregular, &filter.irregular)
    }
}

impl MetadataFilter for AdjectiveData {
    fn matches(&self, filter: &AdjectiveData) -> bool {
        fn check_opt<T: PartialEq>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => a == b,
                None => true,
            }
        }

        check_opt(&self.comparative, &filter.comparative) && check_opt(&self.superlative, &filter.superlative)
    }
}

impl MetadataFilter for DeterminerData {
