        fn check_opt<T: PartialEq>(a: &Option<T>, b: &Option<T>) -> bool {
            match b {
                Some(filter_val) => a == b,
                None => true,
            }
        }

        check_opt(&self.definite, &filter.definite)
    }
}

// Alternative approach: Using a visitor pattern for more complex filtering
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum FilterCondition {
    // Exact match
    Exact(serde_json::Value),
    // Nested conditions for structs
    Nested(HashMap<String, FilterCondition>),
    // For comparing against multiple values
    In(Vec<serde_json::Value>),
    // Custom operations could be added here
}

impl FilterCondition {
    pub fn matches(&self, data: &DictWordMetadata) -> bool {
        self.matches_value(serde_json::to_value(data).unwrap())
    }

    fn matches_value(&self, value: serde_json::Value) -> bool {
        match self {
            FilterCondition::Exact(expected) => &value == expected,
            FilterCondition::Nested(nested) => {
                if let serde_json::Value::Object(map) = value {
                    for (key, condition) in nested {
                        if let Some(data_val) = map.get(key) {
                            if !condition.matches_value(data_val.clone()) {
                                return false;
                            }
                        } else {
                            // Field doesn't exist in data
                            return false;
                        }
                    }
                    true
                } else {
                    false
                }
            }
            FilterCondition::In(values) => {
                values.iter().any(|v| v == &value)
            }
        }
    }
}

