use std::fmt;

use chumsky::prelude::*;

// Define a simple token type for demonstration
#[derive(Debug, Clone, PartialEq)]
pub enum Token {
    Number(i64),
    Plus,
    Minus,
}

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Token::Number(n) => write!(f, "{}", n),
            Token::Plus => write!(f, "+"),
            Token::Minus => write!(f, "-"),
        }
    }
}

// Helper type alias
pub type Span = SimpleSpan<usize>;

pub trait BaseParser: for<'src> BaseParserForLifetime<'src> {
    type Output;

    /// Parse from an owned vector of tokens
    fn parse_owned(input: Vec<Self::Token>) -> Result<Self::Output, Vec<String>> {
        let slice: &[Self::Token] = &input;
        Self::parse(slice)
    }
}

pub trait BaseParserForLifetime<'src> {
    type Token: PartialEq + fmt::Display + 'src;
    type Input: Input<'src, Token = Self::Token, Span = SimpleSpan>;

    fn parser() -> impl Parser<'src, Self::Input, Self::OutputOf<Self::Token>, extra::Err<Rich<'src, Self::Token, SimpleSpan>>>;

    /// Perform the parsing within this layer
    fn parse(input: Self::Input) -> Result<Self::OutputOf<Self::Token>, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

// Helper trait to get the output type
pub trait OutputType<T> {
    type Output;
}

impl<P, T> OutputType<T> for P
where
