        fn handle_request(&self) -> String;
        fn process_data(&self, data: &str) -> String;
        // ... 18 more methods
    }

    // Bridge enum that can hold any Rest implementer
    // This is defined in al and can be used in bl
    #[derive(Debug)]
    pub enum RestEnum {
        Foo(crate::il::Foo),
        Boo(crate::il::Boo),
        // Can be extended with other variants
    }

    impl Rest for RestEnum {
        fn handle_request(&self) -> String {
            match self {
                RestEnum::Foo(f) => f.handle_request(),
                RestEnum::Boo(b) => b.handle_request(),
            }
        }

        fn process_data(&self, data: &str) -> String {
            match self {
                RestEnum::Foo(f) => f.process_data(data),
                RestEnum::Boo(b) => b.process_data(data),
