use std::pin::Pin;
use std::task::{Context, Poll, Waker};
use std::time::Duration;
use tokio::runtime::Runtime;

// Result enum as specified
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// The core function - tries to poll a future synchronously
fn try_poll<F>(future: Pin<&mut F>) -> TryPollResult<F::Output>
where
    F: Future,
{
    // Create a no-op waker that does nothing when woken
    let noop_waker = noop_waker();
    let mut cx = Context::from_waker(&noop_waker);

    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Helper to create a no-op waker
fn noop_waker() -> Waker {
    use std::task::RawWaker;

    // Define the vtable for our no-op waker
    static VTABLE: std::task::RawWakerVTable = std::task::RawWakerVTable::new(
        |_| RawWaker::new(std::ptr::null(), &VTABLE), // clone
        |_| {}, // wake (no-op)
        |_| {}, // wake_by_ref (no-op)
        |_| {}, // drop
    );

    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

// Example 1: A future that completes immediately
async fn immediate_future() -> String {
    "immediate result".to_string()
}

// Example 2: A future that needs some async work (sleep)
async fn delayed_future() -> String {
    tokio::time::sleep(Duration::from_millis(10)).await;
    "delayed result".to_string()
}

// Example 3: A future with multiple awaits
async fn complex_future() -> usize {
    tokio::time::sleep(Duration::from_millis(5)).await;
    42
}

fn main() {
    // Create a runtime
    let rt = Runtime::new().unwrap();

    rt.block_on(async {
        println!("=== Example 1: Immediate future ===");
        example1().await;

        println!("\n=== Example 2: Delayed future ===");
        example2().await;

        println!("\n=== Example 3: Complex future ===");
        example3().await;
    });
}

async fn example1() {
    let mut future = immediate_future();
    let mut pinned_future = unsafe { Pin::new_unchecked(&mut future) };

    match try_poll(pinned_future) {
        TryPollResult::Ready(value) => {
            println!("Future was ready immediately: {}", value);
        }
        TryPollResult::Pending => {
            println!("Future was pending - spawning task...");
            let handle = tokio::spawn(async move { future.await });
            let result = handle.await.unwrap();
            println!("Task completed with: {}", result);
        }
    }
}

async fn example2() {
    let mut future = delayed_future();
    let mut pinned_future = unsafe { Pin::new_unchecked(&mut future) };

    match try_poll(pinned_future) {
        TryPollResult::Ready(value) => {
            println!("Future was ready immediately: {}", value);
