    let mut future = complex_future();
    let mut pinned_future = unsafe { Pin::new_unchecked(&mut future) };

    // First try
    match try_poll(pinned_future) {
        TryPollResult::Ready(value) => {
            println!("Future was ready on first try: {}", value);
            return;
        }
        TryPollResult::Pending => {
            println!("Future was pending on first try");
        }
    }

    // Give it a tiny bit of time (but not enough for it to complete)
    tokio::time::sleep(Duration::from_millis(1)).await;

    // Try again with the same future (still pinned)
    match try_poll(pinned_future) {
        TryPollResult::Ready(value) => {
            println!("Future became ready after short wait: {}", value);
        }
        TryPollResult::Pending => {
