edition = "2021"

[dependencies]
clap = { version = "4.4", features = ["derive", "cargo"] }

[profile.release]
opt-level = 3
lto = true
codegen-units = 1",
  "main.rs": "use clap::{Parser, Subcommand, Args};

#[derive(Parser)]
#[command(name = "cli")]
#[command(about = "Node management CLI", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Node operations
    Node(NodeArgs),
}

#[derive(Args)]
#[command(args_conflicts_with_subcommands = true)]
struct NodeArgs {
    #[command(subcommand)]
    action: Option<NodeSubcommand>,

    /// Node name for operations that follow the name
    #[arg(help = "Node name for operations like link, unlink, status")]
    name: Option<String>,

    #[command(subcommand)]
    node_operation: Option<NodeOperation>,
}

#[derive(Subcommand)]
enum NodeSubcommand {
    /// Create a new node
    Create {
        /// Name of the node to create
        name: String,
    },
    /// Get information about a node
    Get {
        /// Name of the node to get
        name: String,
    },
}

#[derive(Subcommand)]
enum NodeOperation {
    /// Link this node to a target
    Link {
        /// Target node to link to
        target: String,
    },
    /// Unlink this node from a target
    Unlink {
        /// Target node to unlink from
        target: String,
    },
    /// Show status of this node
    Status,
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Node(node_args) => {
            match (&node_args.action, &node_args.name, &node_args.node_operation) {
                // Handle: cli node create <NAME>
                (Some(NodeSubcommand::Create { name }), _, _) => {
                    println!("Creating node: {}", name);
                }

                // Handle: cli node get <NAME>
                (Some(NodeSubcommand::Get { name }), _, _) => {
                    println!("Getting node: {}", name);
                }

                // Handle: cli node <NAME> link <TARGET>
                (None, Some(name), Some(NodeOperation::Link { target })) => {
                    println!("Linking node '{}' to target '{}'", name, target);
                }

                // Handle: cli node <NAME> unlink <TARGET>
                (None, Some(name), Some(NodeOperation::Unlink { target })) => {
                    println!("Unlinking node '{}' from target '{}'", name, target);
                }

                // Handle: cli node <NAME> status
                (None, Some(name), Some(NodeOperation::Status)) => {
                    println!("Showing status for node '{}'", name);
                }

                // Show help if no valid combination
                _ => {
                    // If we have a name but no operation, show node-specific help
                    if node_args.name.is_some() && node_args.node_operation.is_none() {
                        eprintln!("Error: Missing operation for node. Available operations: link, unlink, status");
                        eprintln!("Example: cli node <NAME> link <TARGET>");
                    } else {
                        // Otherwise, show general help
                        let mut cmd = Cli::command();
                        cmd.print_help().unwrap();
                    }
                    std::process::exit(1);
                }
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use clap::CommandFactory;

    #[test]
    fn verify_cli() {
        Cli::command().debug_assert();
    }

    #[test]
    fn test_node_create() {
        let args = vec!["cli", "node", "create", "my-node"];
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
            Commands::Node(node_args) => {
                match node_args.action.unwrap() {
                    NodeSubcommand::Create { name } => assert_eq!(name, "my-node"),
                    _ => panic!("Wrong command"),
                }
            }
        }
    }

    #[test]
    fn test_node_get() {
        let args = vec!["cli", "node", "get", "my-node"];
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
            Commands::Node(node_args) => {
                match node_args.action.unwrap() {
                    NodeSubcommand::Get { name } => assert_eq!(name, "my-node"),
                    _ => panic!("Wrong command"),
                }
            }
        }
    }

    #[test]
    fn test_node_link() {
        let args = vec!["cli", "node", "my-node", "link", "target-node"];
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
            Commands::Node(node_args) => {
                assert_eq!(node_args.name.unwrap(), "my-node");
                match node_args.node_operation.unwrap() {
                    NodeOperation::Link { target } => assert_eq!(target, "target-node"),
                    _ => panic!("Wrong operation"),
                }
            }
        }
    }

    #[test]
    fn test_node_status() {
        let args = vec!["cli", "node", "my-node", "status"];
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
