{
  "Cargo.toml": "[package]
name = "async-wrap-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::sync::mpsc::{channel, Sender};
use tokio::runtime::Runtime;

pub struct Context(i32);

// The core trait object that can be sent between threads
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context,
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

// Helper to wrap an async closure into the trait object
pub fn with_context_async<F, Fut>(work_sender: &Sender<InnerAsyncEvent>, block: F)
where
    F: for<'a> FnOnce(&'a mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    // We need to wrap the FnOnce in a Fn that can be called multiple times
    // by storing it in an Option and taking it out when called
    let block = Box::new(move |ctx: &mut Context| {
        let mut block = Some(block);
        Box::pin(async move {
            if let Some(block) = block.take() {
                block(ctx).await;
            }
        }) as Pin<Box<dyn Future<Output = ()> + Send>>
    });

    let _ = work_sender.send(InnerAsyncEvent::DoWithContext { block });
}

// Even nicer wrapper using a macro for better syntax
#[macro_export]
macro_rules! async_work {
    ($sender:expr, |$ctx:ident| $body:expr) => {
        $crate::with_context_async($sender, |$ctx| async move { $body })
    };
    ($sender:expr, |$ctx:ident: &mut Context| $body:expr) => {
        $crate::with_context_async($sender, |$ctx| async move { $body })
    };
}

fn main() {
    let (tx, rx) = channel();
    let rt = Runtime::new().unwrap();

    // Spawn worker thread
    let handle = std::thread::spawn(move || {
        let rt = Runtime::new().unwrap();
        rt.block_on(async {
            let mut ctx = Context(0);

            while let Ok(event) = rx.recv() {
                match event {
                    InnerAsyncEvent::DoWithContext { block } => {
                        let fut = block(&mut ctx);
                        fut.await;
                        println!("Context value: {}", ctx.0);
                    }
                }
            }
        });
    });

    // Send some async work from the main thread
    for i in 1..=5 {
        with_context_async(&tx, |ctx| async move {
            ctx.0 += i;
            println!("Added {} to context", i);
        });
    }

    // Alternative using the macro for cleaner syntax
    async_work!(&tx, |ctx| {
        ctx.0 *= 2;
        println!("Doubled the context value");
    });

    // Drop the sender to signal completion
    drop(tx);

    handle.join().unwrap();
}

// Additional example showing the Send bound is satisfied
#[allow(dead_code)]
fn test_send() {
    let (tx, _) = channel();

    // This should compile - demonstrating Send requirement
    let work = |ctx: &mut Context| async move {
        ctx.0 += 1;
    };

    with_context_async(&tx, work);

    // This demonstrates capturing Send data
    let send_data = vec![1, 2, 3];
    with_context_async(&tx, move |ctx| async move {
        ctx.0 += send_data.len() as i32;
        println!("Captured vector of length: {}", send_data.len());
    });
}"
}
