fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create the child process (Python REPL as example)
    let mut child_proc = ChildProcess::new("python3", &["-u", "-i"])?;

    // Get stdout and stderr from child
    let stdout = child_proc.child.stdout.take().expect("Failed to open stdout");
    let stderr = child_proc.child.stderr.take().expect("Failed to open stderr");

    // Create rustyline editor
    let mut rl = Editor::<()>::new()?;

    // Create external printer for async output
    let printer = rl.create_external_printer()?;

    // Arc/Mutex for thread-safe output
    let output_buffer = Arc::new(Mutex::new(Vec::new()));
    let output_buffer_clone = output_buffer.clone();

    // Spawn thread to read child's output
    thread::spawn(move || {
        let stdout_reader = BufReader::new(stdout);
        let stderr_reader = BufReader::new(stderr);

        // Combine stdout and stderr reading
        let mut lines = stdout_reader.lines().chain(stderr_reader.lines());

        while let Some(Ok(line)) = lines.next() {
            // Store in buffer and notify via printer
            output_buffer_clone.lock().unwrap().push(line.clone());
            printer.print(line).unwrap();
        }
    });

    println!("Hosting Python REPL. Type 'exit()' to quit or Ctrl-D to exit.");

    // Main read-eval-print loop
    loop {
        // Check for any buffered output first
        {
            let mut buffer = output_buffer.lock().unwrap();
            if !buffer.is_empty() {
                for line in buffer.drain(..) {
                    println!("{}", line);
                }
            }
        }

        // Read line from user with timeout to allow output processing
        let readline = rl.readline_with_timeout(">>> ", Duration::from_millis(100));

        match readline {
            Ok(line) => {
                // Add to history and send to child process
                rl.add_history_entry(line.as_str());

                // Send command to child process
                writeln!(child_proc.stdin, "{}", line)?;
                child_proc.stdin.flush()?;

                // Check for exit condition
                if line.trim() == "exit()" || line.trim() == "quit()" {
                    break;
                }
            }
            Err(ReadlineError::Timeout) => {
                // Timeout occurred, just continue to check for output
                continue;
            }
            Err(ReadlineError::Eof) => {
                // Ctrl-D pressed
                println!("Exiting...");
                break;
            }
            Err(ReadlineError::Interrupted) => {
                // Ctrl-C pressed - send interrupt to child
                writeln!(child_proc.stdin, "\x03")?; // Send Ctrl-C equivalent
                child_proc.stdin.flush()?;
                continue;
            }
            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    // Clean up
    drop(child_proc.stdin);
    child_proc.child.wait()?;

    Ok(())
}

