    /// Set the caller module path for the current thread
    pub fn set_caller_module(module: &'static str) {
        let mutex = CALLER_MODULE.get_or_init(|| std::sync::Mutex::new(None));
        let mut guard = mutex.lock().unwrap();
        *guard = Some(module);
    }

    /// Clear the caller module path for the current thread
    pub fn clear_caller_module() {
        let mutex = CALLER_MODULE.get_or_init(|| std::sync::Mutex::new(None));
