  "main.rs": "use ouroboros::self_referencing;
use serde::{Deserialize, Serialize};
use std::sync::Arc;

#[derive(Deserialize, Serialize, Debug, Clone)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// Self-referential struct that holds the String and the borrowed MyData
#[self_referencing]
struct BorrowedData {
    json_string: String,
    #[borrows(json_string)]
    #[covariant]
    parsed: MyData<'this>,
}

impl BorrowedData {
    fn from_json(json: String) -> anyhow::Result<Self> {
        BorrowedDataTryBuilder {
            json_string: json,
            parsed_builder: |json_string: &String| {
                serde_json::from_str::<MyData>(json_string)
                    .map_err(|e| anyhow::anyhow!(e))
            },
        }
        .try_build()
    }

    fn get(&self) -> &MyData {
        self.borrow_parsed()
    }
}

// Make it Send + Sync for tokio
unsafe impl Send for BorrowedData {}
unsafe impl Sync for BorrowedData {}

// Alternative approach using Arc + Boxed static lifetime
struct ArcBorrowedData {
    _json_string: Arc<String>, // Keep alive
    parsed: MyData<'static>,
}

impl ArcBorrowedData {
    fn from_json(json: String) -> anyhow::Result<Self> {
        let arc_string = Arc::new(json);
        let parsed: MyData = serde_json::from_str(arc_string.as_str())?;

        // SAFETY: We're extending the lifetime to 'static because:
        // 1. The data is stored in an Arc<String> that will live as long as this struct
        // 2. The struct owns the Arc, keeping the data alive
        // 3. We're not exposing the raw string beyond this abstraction
        let parsed_static = unsafe {
            std::mem::transmute::<MyData, MyData<'static>>(parsed)
        };

        Ok(Self {
            _json_string: arc_string,
            parsed: parsed_static,
        })
    }

    fn get(&self) -> &MyData<'static> {
        &self.parsed
    }
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    println!("=== Example 1: Using ouroboros (self-referential struct) ===");
    example1().await?;

    println!("\n=== Example 2: Using Arc + transmute ===");
    example2().await?;

    Ok(())
}

async fn example1() -> anyhow::Result<()> {
    let json_data = r#"{"data": "hello", "more_data": "world"}"#.to_string();

    // Deserialize once
    let borrowed_data = BorrowedData::from_json(json_data)?;

    // Create a channel to pass data between tasks
    let (tx, mut rx) = tokio::sync::mpsc::channel::<BorrowedData>(10);

    // Spawn receiver task
    let receiver_handle = tokio::spawn(async move {
        while let Some(data) = rx.recv().await {
            let parsed = data.get();
            println!("Receiver task got: {:?}", parsed);
            println!("  data: {}, more_data: {}", parsed.data, parsed.more_data);
        }
    });

    // Spawn multiple sender tasks
    let mut handles = vec![];

    for i in 0..3 {
        let tx_clone = tx.clone();
        let data_clone = borrowed_data.clone(); // Clones the self-referential struct, not the underlying string

        handles.push(tokio::spawn(async move {
            tx_clone.send(data_clone).await.unwrap();
            println!("Sender task {} sent data", i);
        }));
    }

    // Wait for senders
    for handle in handles {
        handle.await?;
    }

    // Close channel
    drop(tx);

    // Wait for receiver
    receiver_handle.await?;

    Ok(())
}

async fn example2() -> anyhow::Result<()> {
