// Handler WITHOUT origin check - websocket connections from anywhere will be accepted
async fn public_websocket_handler(
    ws: WebSocketUpgrade,
) -> impl IntoResponse {
    tracing::info!("Public WebSocket connection accepted from any origin");
    ws.on_upgrade(|socket| async move {
        handle_socket(socket).await;
    })
}

// Handler WITH origin check - only accepts connections from specific origins
async fn secure_websocket_handler(
    ws: WebSocketUpgrade,
    origin: Option<TypedHeader<Origin>>,
) -> Result<impl IntoResponse, StatusCode> {
    // Check if origin header is present
    let origin = match origin {
        Some(TypedHeader(origin)) => origin,
        None => {
            tracing::warn!("WebSocket connection rejected: No Origin header");
            return Err(StatusCode::BAD_REQUEST);
        }
    };

    // Extract the hostname from the origin
    let origin_host = origin.hostname();

    // Define allowed origins
    // In production, you might want to read this from configuration
    let allowed_origins = vec![
        "https://www.example.com",
        "https://example.com",
        "http://localhost:8080",  // For local development
    ];

    // Check if the origin is allowed
    if !allowed_origins.contains(&origin_host) {
        tracing::warn!(
            "WebSocket connection rejected: Origin '{}' not allowed",
            origin_host
        );
        return Err(StatusCode::FORBIDDEN);
    }

    tracing::info!("Secure WebSocket connection accepted from origin: {}", origin_host);

    Ok(ws.on_upgrade(|socket| async move {
        handle_socket(socket).await;
    }))
}

