    ) -> Result<(), StatusCode> {
        let origin = match origin {
            Some(TypedHeader(origin)) => origin,
            None => return Err(StatusCode::BAD_REQUEST),
        };

        let origin_host = origin.hostname();
        let allowed_origins = vec![
