        let line_up_to_cursor = &line[..pos];
        let mut last_non_ws = None;

        for (i, c) in line_up_to_cursor.char_indices().rev() {
            if !c.is_whitespace() {
                last_non_ws = Some((i, c));
                break;
            }
        }

        // If we found a non-whitespace character
        if let Some((last_non_ws_idx, _)) = last_non_ws {
