                        editor.delete_range(whitespace_start..whitespace_end)?;

                        // Update position after deletion
                        let new_pos = whitespace_start;
                        editor.set_pos(new_pos);

                        // Insert the character at the new position
                        editor.insert_str(new_pos, &insert_char.to_string())?;

                        // Move cursor right by 1 (after the inserted character)
