  "main.rs": "use rayon::prelude::*;

fn process_element(x: &usize) -> String {
    // Example transformation function
    // This could be any expensive computation you want to parallelize
    format!("Processed: {}", x * 2)
}

fn process_nested_parallel<T, F>(nested_vec: Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    T: Send + Sync,
    F: Fn(&usize) -> T + Sync + Send,
{
    nested_vec
        .into_par_iter()
        .map(|inner_vec| {
            inner_vec
                .par_iter()
                .map(|elem| f(elem))
                .collect::<Vec<T>>()
        })
        .collect()
}

fn process_with_index_info<T, F>(nested_vec: Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    T: Send + Sync,
    F: Fn(usize, usize, &usize) -> T + Sync + Send,
{
    nested_vec
        .into_par_iter()
        .enumerate()
        .map(|(i, inner_vec)| {
            inner_vec
                .par_iter()
                .enumerate()
                .map(|(j, elem)| f(i, j, elem))
                .collect::<Vec<T>>()
        })
        .collect()
}

fn flatten_and_process<T, F>(nested_vec: &[Vec<usize>], f: F) -> Vec<Vec<T>>
where
    T: Send + Sync + Default + Clone,
    F: Fn(&usize) -> T + Sync + Send,
{
    // Alternative approach: flatten, process, then reshape
    // Step 1: Collect lengths for reshaping
    let lengths: Vec<usize> = nested_vec.iter().map(|inner| inner.len()).collect();

    // Step 2: Flatten and process in parallel
    let flat_processed: Vec<T> = nested_vec
        .par_iter()
        .flat_map(|inner| inner.par_iter().map(&f))
        .collect();

    // Step 3: Reshape back to nested structure
    let mut result = Vec::with_capacity(lengths.len());
    let mut current_idx = 0;

    for &len in &lengths {
        let mut inner_vec = Vec::with_capacity(len);
        for _ in 0..len {
            inner_vec.push(flat_processed[current_idx].clone());
            current_idx += 1;
        }
        result.push(inner_vec);
    }

    result
}

fn main() {
    // Example nested vector with different inner sizes
    let nested_data = vec![
        vec![1, 2, 3],
        vec![4, 5],
        vec![6, 7, 8, 9],
        vec![10],
    ];

    println!("Original data:");
    for (i, inner) in nested_data.iter().enumerate() {
        println!("  Row {}: {:?}", i, inner);
    }

    println!("\n--- Method 1: Direct parallel processing ---");
    let result1 = process_nested_parallel(nested_data.clone(), process_element);

    for (i, inner) in result1.iter().enumerate() {
        println!("  Row {}: {:?}", i, inner);
    }

    println!("\n--- Method 2: With index information ---");
    let result2 = process_with_index_info(nested_data.clone(), |i, j, elem| {
        format!("[{},{}]: {}", i, j, elem * 3)
    });

    for (i, inner) in result2.iter().enumerate() {
        println!("  Row {}: {:?}", i, inner);
    }

    println!("\n--- Method 3: Flatten-process-reshape ---");
    let result3 = flatten_and_process(&nested_data, |x| {
        x.pow(2) // Square each element
    });

    for (i, inner) in result3.iter().enumerate() {
        println!("  Row {}: {:?}", i, inner);
    }

    // Performance comparison
    println!("\n--- Performance test with larger dataset ---");
    let large_nested: Vec<Vec<usize>> = (0..1000)
        .map(|i| (0..i % 100 + 1).collect::<Vec<usize>>())
        .collect();

    let start = std::time::Instant::now();
    let _ = process_nested_parallel(large_nested.clone(), |x| x * 2);
    let elapsed = start.elapsed();

    println!("Processed {} inner vectors in {:?}", large_nested.len(), elapsed);
}
"
}
