Looking at the error and the OpenSSL output, I can see the issue. The problem is likely that SCEP uses a slightly different structure than standard CMS. Specifically, the `eContent` field in SCEP messages often contains nested ASN.1 data that needs to be handled differently.

Here's a solution that properly handles the SCEP PKIOperation structure:

**Cargo.toml:**
```toml
[package]
name = "scep-decoder"
version = "0.1.0"
edition = "2021"

[dependencies]
cms = "0.5.2"
der = "0.7.8"
x509-cert = "1.1.0"
asn1-rs = "0.6.0"
hex = "0.4.3"
```

**main.rs:**
```rust
use cms::{
    builder::{SignedDataBuilder, SignerInfoBuilder},
    cert::x509::{CertificateChoices, IssuerAndSerialNumber},
    content_info::ContentInfo,
    signed_data::SignedData,
    EncapsulatedContentInfo,
};
use der::{
    asn1::{AnyRef, ObjectIdentifier, OctetStringRef},
    Decode, Encode, Tag,
};
use x509_cert::Certificate;
use hex;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Read the binary data from stdin or a file
    let data = std::fs::read("pkiopp.der")?;

    // Decode SCEP PKIOperation
    let result = decode_scep_pkioperation(&data);

    match result {
        Ok(_) => println!("Successfully decoded SCEP PKIOperation"),
        Err(e) => eprintln!("Error: {}", e),
    }

    Ok(())
}

fn decode_scep_pkioperation(data: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
    // Step 1: Decode outer ContentInfo (CMS)
    let ci = ContentInfo::from_der(data)?;
    println!("Outer Content Type: {}", ci.content_type);

    // Step 2: Decode SignedData
    let sd: SignedData = ci.content.decode_as()?;
    println!("SignedData version: {}", sd.version);
    println!("Number of signer infos: {}", sd.signer_infos.0.len());

    // Step 3: Get the encapsulated content
    let eci = &sd.encap_content_info;
    println!("Encapsulated Content Type: {}", eci.econtent_type);

    // Step 4: Handle SCEP-specific eContent (contains another CMS message)
    if let Some(ec) = &eci.econtent {
        // In SCEP, the eContent is an OCTET STRING containing another CMS structure
        let octet_str = OctetStringRef::from_der(ec.value())?;
        let inner_data = octet_str.as_bytes();

        println!("eContent length: {}", inner_data.len());

        // Step 5: Decode the inner CMS (which contains the actual PKI message)
        let inner_ci = ContentInfo::from_der(inner_data)?;
        println!("Inner Content Type: {}", inner_ci.content_type);

        // Step 6: The inner content should be Data (OCTET STRING) containing the actual PKI message
        let data_content = AnyRef::from_der(inner_ci.content.value())?;

        // Try to decode as OCTET STRING (for PKCSReq, CertRep, etc.)
        if data_content.tag() == Tag::OctetString {
            let pkcs_req_data = OctetStringRef::from_der(data_content.value())?;
            println!("PKI message data length: {}", pkcs_req_data.as_bytes().len());

            // This could be a PKCS#10 request, a CRMF request, etc.
            // You would typically parse this further based on the SCEP message type

            // For debugging, print hex of first 100 bytes
            if pkcs_req_data.as_bytes().len() > 100 {
                println!("First 100 bytes of PKI message: {}", 
                         hex::encode(&pkcs_req_data.as_bytes()[..100]));
            } else {
                println!("PKI message: {}", hex::encode(pkcs_req_data.as_bytes()));
            }
        }

        // Step 7: Print certificate information if present
        if let Some(certs) = &sd.certificates {
            for (i, cert_choice) in certs.0.iter().enumerate() {
                match cert_choice {
                    CertificateChoices::Certificate(cert) => {
                        println!("\nCertificate {}:", i + 1);
                        println!("  Serial: {}", cert.tbs_certificate.serial_number);
                        println!("  Subject: {}", cert.tbs_certificate.subject);
                        println!("  Issuer: {}", cert.tbs_certificate.issuer);
                    }
                    _ => println!("Certificate {}: Other certificate choice", i + 1),
                }
            }
        }

        // Step 8: Print signer information
        for (i, signer) in sd.signer_infos.0.iter().enumerate() {
            println!("\nSigner Info {}:", i + 1);
            match &signer.sid {
                cms::signed_data::SignerIdentifier::IssuerAndSerialNumber(iasn) => {
                    println!("  Issuer: {}", iasn.issuer);
                    println!("  Serial: {}", iasn.serial_number);
                }
                cms::signed_data::SignerIdentifier::SubjectKeyIdentifier(_) => {
                    println!("  Subject Key Identifier");
                }
            }

            println!("  Digest Algorithm: {}", signer.digest_alg.oid);

            // Check for signed attributes
            if let Some(signed_attrs) = &signer.signed_attrs {
                println!("  Signed Attributes:");
                for attr in &signed_attrs.0 {
                    println!("    OID: {}", attr.oid);
                    // Special handling for common SCEP attributes
                    if attr.oid == ObjectIdentifier::new_unwrap("1.2.840.113549.1.9.3") {
                        println!("      Content Type Attribute");
                    } else if attr.oid == ObjectIdentifier::new_unwrap("1.2.840.113549.1.9.5") {
                        println!("      Signing Time Attribute");
                    } else if attr.oid == ObjectIdentifier::new_unwrap("1.2.840.113549.1.9.4") {
                        println!("      Message Digest Attribute");
                    }
                }
            }
        }
    }

    Ok(())
}

// Alternative approach using lower-level ASN.1 parsing for debugging
fn decode_scep_debug(data: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
    use der::asn1::AnyRef;

    println!("\n=== Debug Decoding ===");

    // Parse as raw ASN.1 to understand structure
    let any = AnyRef::from_der(data)?;
    println!("Top-level tag: {:?}", any.tag());

    // Try to decode as sequence
    let seq = any.sequence()?;
    println!("Sequence items: {}", seq.len());

    for (i, item) in seq.iter().enumerate() {
        println!("Item {}: tag = {:?}, length = {}", i, item.tag(), item.value().len());

        // Try to decode common OIDs
        if item.tag() == Tag::ObjectIdentifier {
            if let Ok(oid) = ObjectIdentifier::from_der(item.value()) {
                println!("  OID: {}", oid);
            }
        }

        // Look for nested structures
        if item.tag() == Tag::OctetString {
            println!("  Found OCTET STRING (might contain nested CMS)");
        }
    }

    Ok(())
}
