use cms::content_info::ContentInfo;
use der::{Decode, Tag};
use der::asn1::{AnyRef, ObjectIdentifier, OctetStringRef};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Read your binary data
    let data = std::fs::read("pkiopp.der")?;

    // Try to decode
    match decode_scep_simple(&data) {
        Ok(_) => println!("Success!"),
        Err(e) => {
            eprintln!("Error: {}", e);
            // Try debug parsing
            decode_scep_debug(&data)?;
        }
    }

    Ok(())
}

fn decode_scep_simple(data: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
    // 1. Parse outer ContentInfo
    let ci = ContentInfo::from_der(data)?;
    println!("Outer OID: {}", ci.content_type);

    // 2. Parse as SignedData
    let sd_bytes = ci.content.value();

    // Manually parse SignedData to debug
    let any = AnyRef::from_der(sd_bytes)?;
    println!("SignedData tag: {:?}", any.tag());

    // The SignedData should be a SEQUENCE
    if any.tag() == Tag::Sequence {
        let seq = any.sequence()?;
        println!("SignedData has {} items in sequence", seq.len());

        // Item 0: version (INTEGER)
        if seq.len() > 0 {
            println!("Item 0 (version): tag = {:?}", seq[0].tag());
        }

        // Item 1: digestAlgorithms (SET OF)
        if seq.len() > 1 {
            println!("Item 1 (digestAlgorithms): tag = {:?}", seq[1].tag());
        }

        // Item 2: encapsulatedContentInfo (SEQUENCE)
        if seq.len() > 2 {
            println!("Item 2 (encapContentInfo): tag = {:?}", seq[2].tag());

            // Try to parse the encapsulated content info
            let eci_seq = seq[2].sequence()?;
            println!("eci_seq has {} items", eci_seq.len());

            if eci_seq.len() > 0 {
                if let Ok(oid) = ObjectIdentifier::from_der(eci_seq[0].value()) {
                    println!("  eContentType: {}", oid);
                }
            }

            if eci_seq.len() > 1 {
                println!("  eContent tag: {:?}", eci_seq[1].tag());

                // This should be [0] EXPLICIT OCTET STRING
                // Try to parse as OCTET STRING
                if eci_seq[1].tag() == Tag::OctetString {
                    let inner_octet = OctetStringRef::from_der(eci_seq[1].value())?;
                    println!("  eContent OCTET STRING length: {}", inner_octet.len());

                    // This OCTET STRING contains another ContentInfo
                    let inner_ci = ContentInfo::from_der(inner_octet.as_bytes())?;
                    println!("  Inner ContentInfo OID: {}", inner_ci.content_type);

                    // The inner content is Data (OCTET STRING with actual PKI message)
                    if inner_ci.content_type == ObjectIdentifier::new_unwrap("1.2.840.113549.1.7.1") {
                        let data_octet = OctetStringRef::from_der(inner_ci.content.value())?;
                        println!("  PKI Message Data length: {}", data_octet.len());
                    }
                }
            }
        }
    }

    Ok(())
}
```

**To use this code:**

1. Save the binary data from your SCEP request to a file named `pkiopp.der`
2. Run with `cargo run`

The key insight is that SCEP wraps the actual PKI message in multiple layers:
1. Outer SignedData CMS structure
2. Inner ContentInfo (Data type)
3. Actual PKCS#10 or CRMF message

The error you're seeing might be due to trying to parse the entire structure at once. The debug functions will help you understand the exact structure you're dealing with.

