use itertools::Itertools;

fn tokenize(s: &str) -> Vec<String> {
    s.split('\'')
        .enumerate()
        .map(|(i, s)| {
            if i % 2 == 0 {
                // Outside quotes - split on whitespace groups
                s.chars()
                    .group_by(|ch| *ch == ' ')
                    .into_iter()
                    .map(|(is_space, chars)| (is_space, chars.collect::<String>()))
                    .collect::<Vec<_>>()
            } else {
                // Inside quotes - treat as single token part
                vec![(false, s.to_string())]
            }
        })
        .flatten()
        .group_by(|(is_space, _)| *is_space)
        .into_iter()
        .filter_map(|(is_space_group, group)| {
            // Combine non-space items, drop pure-space groups
            let combined: String = group.map(|(_, s)| s).collect();
            if is_space_group {
                None
            } else {
                Some(combined)
            }
        })
        .collect()
}

fn main() {
