        let trimmed_content = content[..last_bracket_pos].trim();
        let needs_comma = !trimmed_content.is_empty() && trimmed_content != "[";

        // Create new todo with appropriate ID
        let existing_todos: Vec<TodoItem> = serde_json::from_str(&content).unwrap_or_default();
        let next_id = existing_todos.iter().map(|todo| todo.id).max().unwrap_or(0) + 1;

        let new_todo = TodoItem {
            id: next_id,
            title: title.to_string(),
            completed: false,
        };

        // Write comma if needed, new todo, and closing bracket
        if needs_comma {
            write!(file, ",\n  ")?;
        } else if trimmed_content != "[" {
            write!(file, "\n  ")?;
        }

        let todo_json = serde_json::to_string(&new_todo)?;
        write!(file, "{}\n]", todo_json)?;
    } else {
        // Malformed JSON, recreate the file
        let mut todos: Vec<TodoItem> = serde_json::from_str(&content).unwrap_or_default();
        let next_id = todos.iter().map(|todo| todo.id).max().unwrap_or(0) + 1;
        todos.push(TodoItem {
            id: next_id,
            title: title.to_string(),
            completed: false,
        });
        save_todos(&todos)?;
    }

    Ok(())
}

fn main() -> io::Result<()> {
    println!("Todo List Manager");
    println!("================");

    // Method 1: Load, modify, save (simplest and most robust)
    println!("\nMethod 1: Load, modify, save");
    let mut todos = load_or_create_todos();
    println!("Loaded {} existing todos", todos.len());

    // Add a new todo
    append_todo(&mut todos, "Learn Rust");
    append_todo(&mut todos, "Build a JSON todo app");

    // Save all todos
    save_todos(&todos)?;
    println!("Saved {} todos", todos.len());

    // Display current todos
    for todo in &todos {
        let status = if todo.completed { "✓" } else { " " };
        println!("{} [{}] {}", status, todo.id, todo.title);
    }

    // Method 2: Direct append (more complex)
    println!("\nMethod 2: Direct append");
    append_todo_directly("Test direct append")?;

    // Reload and show all todos
    let updated_todos = load_or_create_todos();
    println!("\nAll todos after updates:");
    for todo in &updated_todos {
        let status = if todo.completed { "✓" } else { " " };
        println!("{} [{}] {}", status, todo.id, todo.title);
    }

    Ok(())
}
"
