```rust
use azure_core::HttpClient;
use azure_identity::DefaultAzureCredential;
use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use dotenv::dotenv;
use futures::stream::{StreamExt, FuturesOrdered};
use serde::{Deserialize, Serialize};
use std::env;
use std::time::Instant;

#[derive(Debug, Deserialize, Serialize)]
struct TradeData {
    // Define your trade data structure here
    // Example fields:
    // symbol: String,
    // price: f64,
    // quantity: f64,
    // timestamp: String,
}

pub async fn fetch_trades_from_azure_optimized() -> Result<Vec<TradeData>, Box<dyn std::error::Error>> {
    let start = Instant::now();
    println!("[LOG] Starting optimized Azure download");

    // Load environment variables
    dotenv().ok();

    let account_name = env::var("AZURE_ACCOUNT_NAME")?;
    let container_name = env::var("AZURE_CONTAINER_NAME")?;

    // Get credentials - using DefaultAzureCredential which supports multiple auth methods
    let credential = DefaultAzureCredential::default();
    let credentials = StorageCredentials::token_credential(credential);

    // Create client
    let blob_service = BlobServiceClient::new(account_name, credentials);
    let container_client = blob_service.container_client(container_name);

    // Get prefixes from environment or use empty for all blobs
    let prefixes = vec![
        env::var("AZURE_PREFIX_OPT").unwrap_or_default(),
        env::var("AZURE_PREFIX_FUT").unwrap_or_default(),
    ];

    // Process each prefix
    let mut all_trades = Vec::new();

    for prefix in prefixes.into_iter().filter(|p| !p.is_empty()) {
        println!("[LOG] Processing prefix: {}", prefix);

        // List all blobs first
        let mut blob_names = Vec::new();
        let mut stream = container_client.list_blobs().prefix(prefix).into_stream();

        while let Some(response) = stream.next().await {
            let response = response?;
            for blob in response.blobs.blobs() {
                if blob.name.ends_with(".json") {
                    blob_names.push(blob.name.clone());
                }
            }
        }

        println!("[LOG] Found {} blobs for prefix {}", blob_names.len(), prefix);

        // Download and parse blobs in parallel with controlled concurrency
        let mut tasks = FuturesOrdered::new();
        let max_concurrent = 32; // Tune this based on your network/CPU

        for (i, blob_name) in blob_names.into_iter().enumerate() {
            let blob_client = container_client.blob_client(&blob_name);

            tasks.push_back(async move {
                match blob_client.get_content().await {
                    Ok(content) => {
                        match serde_json::from_slice::<TradeData>(&content) {
                            Ok(trade) => Some((blob_name, trade)),
                            Err(e) => {
                                eprintln!("Failed to parse JSON from {}: {}", blob_name, e);
                                None
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Failed to download {}: {}", blob_name, e);
                        None
                    }
                }
            });

            // Control concurrency
            if i % max_concurrent == 0 && i > 0 {
                while let Some(result) = tasks.next().await {
                    if let Some((name, trade)) = result {
                        all_trades.push(trade);
                    }
                }
            }
        }

        // Collect remaining results
        while let Some(result) = tasks.next().await {
            if let Some((_name, trade)) = result {
                all_trades.push(trade);
            }
        }
    }

    println!("[LOG] Total time: {:?}", start.elapsed());
    println!("[LOG] Total trades downloaded: {}", all_trades.len());

    Ok(all_trades)
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting Azure Blob download test...");

    match fetch_trades_from_azure_optimized().await {
        Ok(trades) => {
            println!("Successfully downloaded {} trades", trades.len());
            // Print first few trades as example
            for (i, trade) in trades.iter().take(3).enumerate() {
                println!("Trade {}: {:?}", i + 1, trade);
            }
        }
        Err(e) => {
            eprintln!("Error: {}", e);
            return Err(e);
        }
    }

    Ok(())
}
```

**Key optimizations:**

1. **Use `DefaultAzureCredential`** - This handles authentication more efficiently and supports multiple auth methods (environment variables, managed identity, etc.)

2. **List all blobs first, then download in parallel** - Similar to the C# approach

3. **Controlled concurrency** - Uses `FuturesOrdered` with a concurrency limit (set to 32, but you should tune this based on your network and CPU)

4. **Efficient error handling** - Continues processing even if individual blobs fail

5. **Use `dotenv` for environment variables** - More idiomatic Rust approach

**To test:**
1. Save the files
2. Run `cargo run --release`
3. Make sure your environment variables are set:
   - `AZURE_ACCOUNT_NAME`
   - `AZURE_CONTAINER_NAME`
   - `AZURE_PREFIX_OPT` (optional)
   - `AZURE_PREFIX_FUT` (optional)

**Note:** You'll need to define your `TradeData` struct with the actual fields from your JSON files. The performance should now be much closer to C#, likely within 10-20% difference (Rust might even be faster in some cases). If you're still seeing significant differences, you might want to:
1. Adjust `max_concurrent` (try values between 16-64)
2. Check if you're hitting rate limits on Azure
3. Ensure you're running with `--release` flag
4. Consider using connection pooling with a custom HTTP client

