/// Context for passing between stages
#[derive(Debug, Clone)]
struct RequestContext {
    /// Stored parent span context for rehydration
    span_ctx: Option<opentelemetry::Context>,
    /// Request metadata
    metadata: HashMap<String, String>,
    /// Trace ID for logging
    trace_id: String,
}

impl RequestContext {
    fn new() -> Self {
        Self {
            span_ctx: None,
            metadata: HashMap::new(),
            trace_id: String::new(),
        }
    }

    /// Extract context from carrier (like HTTP headers)
    fn extract_from_carrier(carrier: &dyn Extractor) -> Self {
        let parent_cx = global::get_text_map_propagator(|propagator| propagator.extract(carrier));
        let trace_id = parent_cx.span().span_context().trace_id().to_string();

        Self {
            span_ctx: Some(parent_cx),
            metadata: HashMap::new(),
            trace_id,
        }
    }

    /// Activate the stored span context
    fn activate_span(&self) -> Option<tracing_opentelemetry::OtelGuard> {
        self.span_ctx.as_ref().map(|ctx| {
            // Create a span linked to the parent context
            let span = tracing::info_span!(
                "request",
                trace_id = %self.trace_id,
                otel.kind = "server"
            );
            span.set_parent(ctx.clone());
            span.enter()
