    async fn on_upstream(&self, ctx: Arc<RequestContext>) -> Result<(), StageError> {
        // Rehydrate span context even though we're in a different async task
        let _guard = ctx.activate_span();

        let stage_span = tracing::info_span!(
            "stage.upstream",
            stage = "upstream",
