    let mut tmin = 0.0;
    let mut tmax = f32::MAX;
    let mut normal = Vec3::ZERO;

    for i in 0..3 {
        let inv_d = 1.0 / ray_dir[i];
        let mut t0 = (aabb_min[i] - ray_origin[i]) * inv_d;
        let mut t1 = (aabb_max[i] - ray_origin[i]) * inv_d;

        if inv_d < 0.0 {
            std::mem::swap(&mut t0, &mut t1);
        }

        tmin = tmin.max(t0);
        tmax = tmax.min(t1);

        if tmin > tmax {
            return None;
        }

        if t0 > 0.0 && t0 == tmin {
            normal = Vec3::ZERO;
            normal[i] = if inv_d < 0.0 { 1.0 } else { -1.0 };
        }
    }

    if tmin > 0.0 && tmin < f32::MAX {
        Some((tmin, normal))
    } else {
        None
    }
