/// Generic function to subtract column means from a matrix
fn subtract_column_means<R, C, S>(matrix: &Matrix<f64, R, C, S>) -> DMatrix<f64>
where
    R: Dim,
    C: Dim,
    S: ViewStorage<'_, f64, R, C>,
{
    let mut result = matrix.clone_owned();

    for (col_idx, mut col) in result.column_iter_mut().enumerate() {
        let mean = col.mean();
        for val in col.iter_mut() {
            *val -= mean;
        }
    }

    result
