edition = "2021"

[dependencies]
actix-web = "4.0"
actix-rt = "2.0"
reqwest = { version = "0.11", features = ["json"] }
tokio = { version = "1.0", features = ["macros", "rt-multi-thread"] }
serde = { version = "1.0", features = ["derive"] }
thiserror = "1.0"

[dev-dependencies]
wiremock = "0.5"
",
  "main.rs": "use actix_web::{
    dev::{Payload, Service, ServiceResponse},
    error::Error as ActixError,
    web::{self, Data, Json},
    App, FromRequest, HttpMessage, HttpRequest, HttpResponse, HttpServer, Responder,
};
use futures_util::future::LocalBoxFuture;
use reqwest::{Client, header, Url};
use serde::{Deserialize, Serialize};
use std::{future::Future, pin::Pin, sync::Arc};
use thiserror::Error;

#[derive(Debug, Error)]
pub enum CustomError {
    #[error("Invalid header")]
    InvalidHeader,
    #[error("Request error: {0}")]
    RequestError(String),
    #[error("Other error: {0}")]
    Other(String),
}

impl actix_web::error::ResponseError for CustomError {
    fn error_response(&self) -> HttpResponse {
        match self {
            CustomError::InvalidHeader => HttpResponse::BadRequest().body("Invalid header"),
            CustomError::RequestError(_) => HttpResponse::InternalServerError().body("Request error"),
            CustomError::Other(_) => HttpResponse::InternalServerError().body("Internal error"),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AdditionalData {
    pub id: String,
    pub name: String,
}

#[derive(Clone)]
pub struct CustomServiceClient {
    client: Client,
    base_url: Url,
}

impl CustomServiceClient {
    pub fn new(base_url: &str) -> Result<Self, CustomError> {
        let client = Client::builder()
            .danger_accept_invalid_certs(true)
            .build()
            .map_err(|e| CustomError::Other(e.to_string()))?;

        let base_url = Url::parse(base_url)
            .map_err(|e| CustomError::Other(e.to_string()))?;

        Ok(Self { client, base_url })
    }

    pub async fn get_additional_data(
        &self,
        date_str: &str,
    ) -> Result<AdditionalData, CustomError> {
        let url = self.base_url.join("/api/data")
            .map_err(|e| CustomError::Other(e.to_string()))?;

        let response = self
            .client
            .get(url)
            .header(header::DATE, date_str)
            .send()
            .await
            .map_err(|e| CustomError::RequestError(e.to_string()))?;

        if !response.status().is_success() {
            return Err(CustomError::RequestError(format!(
                "HTTP {}: {}",
                response.status(),
                response.text().await.unwrap_or_default()
            )));
        }

        response
            .json()
            .await
            .map_err(|e| CustomError::Other(e.to_string()))
    }
}

pub struct AuthorizedHttpRequest {
    pub path: String,
    pub additional_data: Option<AdditionalData>,
}

impl AuthorizedHttpRequest {
    pub fn new(
        path: String,
        additional_data: Option<AdditionalData>,
    ) -> Self {
        Self {
            path,
            additional_data,
        }
    }
}

impl FromRequest for AuthorizedHttpRequest {
    type Error = CustomError;
    type Future = LocalBoxFuture<'static, Result<Self, Self::Error>>;

    fn from_request(req: &HttpRequest, _payload: &mut Payload) -> Self::Future {
        // Extract owned data from the request
        let path = req.path().to_string();

        // Extract header value and convert to owned String
        let date_header = req
            .headers()
            .get(header::DATE)
            .and_then(|v| v.to_str().ok())
            .map(|s| s.to_string());

        // Get client from app data
        let client = req.app_data::<Data<CustomServiceClient>>().cloned();

        Box::pin(async move {
            match (date_header, client) {
                (Some(date_str), Some(client)) => {
                    let additional_data = client.get_additional_data(&date_str).await.ok();
                    Ok(AuthorizedHttpRequest::new(path, additional_data))
                }
                _ => Ok(AuthorizedHttpRequest::new(path, None)),
            }
        })
    }
}

async fn handle_request(
    req: AuthorizedHttpRequest,
    client: Data<CustomServiceClient>,
) -> impl Responder {
    match req.additional_data {
        Some(data) => HttpResponse::Ok().body(format!(
            "Path: {}, Data: {} - {}",
            req.path, data.id, data.name
        )),
        None => HttpResponse::Ok().body(format!("Path: {}, No additional data", req.path)),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // Create the service client
    let client = CustomServiceClient::new("https://localhost:3000")
        .expect("Failed to create service client");

    println!("Server starting on http://127.0.0.1:8080");
    println!("Try: curl -H 'Date: 2024-01-01' http://127.0.0.1:8080/api/test");

    HttpServer::new(move || {
        App::new()
            .app_data(Data::new(client.clone()))
            .route("/api/test", web::get().to(handle_request))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

#[cfg(test)]
mod tests {
    use super::*;
    use actix_web::{test, web, App};
    use wiremock::{Mock, MockServer, ResponseTemplate};
    use wiremock::matchers::{method, header_exists};

    #[actix_rt::test]
    async fn test_extractor_with_valid_header() {
        // Start mock server
        let mock_server = MockServer::start().await;

        // Mock the response
        let mock_response = AdditionalData {
            id: "123".to_string(),
            name: "Test Data".to_string(),
        };

        Mock::given(method("GET"))
            .and(header_exists("Date"))
            .respond_with(ResponseTemplate::new(200).set_body_json(&mock_response))
            .mount(&mock_server)
            .await;

        // Create client with mock server URL
        let client = CustomServiceClient::new(&mock_server.uri()).unwrap();

        let app = test::init_service(
            App::new()
                .app_data(Data::new(client))
                .route("/test", web::get().to(|req: AuthorizedHttpRequest| async move {
                    match req.additional_data {
                        Some(data) => HttpResponse::Ok().body(format!("Found: {}", data.name)),
                        None => HttpResponse::Ok().body("No data"),
                    }
                }))
        ).await;

        // Create request with Date header
        let req = test::TestRequest::get()
            .uri("/test")
            .insert_header((header::DATE, "2024-01-01"))
            .to_request();

        let resp = test::call_service(&app, req).await;
        assert!(resp.status().is_success());
    }

    #[actix_rt::test]
    async fn test_extractor_without_header() {
        let client = CustomServiceClient::new("http://localhost:3000").unwrap();

        let app = test::init_service(
            App::new()
                .app_data(Data::new(client))
                .route("/test", web::get().to(|req: AuthorizedHttpRequest| async move {
                    match req.additional_data {
                        Some(_) => HttpResponse::Ok().body("Has data"),
                        None => HttpResponse::Ok().body("No data"),
                    }
                }))
        ).await;

        // Create request WITHOUT Date header
        let req = test::TestRequest::get().uri("/test").to_request();

        let resp = test::call_service(&app, req).await;
        assert!(resp.status().is_success());

        let body = test::read_body(resp).await;
        assert_eq!(body, "No data");
    }
}
"
}
