    sync::mpsc,
    task,
    time,
};

#[derive(thiserror::Error, Debug)]
pub enum PtyError {
    #[error("PTY process terminated")]
    ProcessTerminated,
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
}

pub struct Agent {
    tx: mpsc::UnboundedSender<String>,
    rx: mpsc::UnboundedReceiver<String>,
}

impl Agent {
    pub fn new(program: &str, args: &[&str]) -> Result<Self> {
        let (mut pty, mut cmd) = spawn(program)
            .args(args)
            .pty()
            .map_err(|e| anyhow::anyhow!("Failed to spawn PTY: {}", e))?;

        // Enable non-blocking reads
        pty.set_nonblocking(true)?;

        let (output_tx, mut output_rx) = mpsc::unbounded_channel();
        let (input_tx, input_rx) = mpsc::unbounded_channel();

        // Spawn read thread
        let read_pty = pty.try_clone().context("Failed to clone PTY for reading")?;
        task::spawn(async move {
            let mut session = Session::new(read_pty);
            let mut buffer = vec![0u8; 4096];

            loop {
                match session.read(&mut buffer) {
                    Ok(n) if n > 0 => {
                        let output = String::from_utf8_lossy(&buffer[..n]).to_string();
                        if output_tx.send(output).is_err() {
                            break;
                        }
                    }
                    Ok(_) => {
                        // No data available in non-blocking mode
                        time::sleep(Duration::from_millis(10)).await;
                    }
                    Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                        time::sleep(Duration::from_millis(10)).await;
                    }
                    Err(e) => {
                        eprintln!("Read error: {}", e);
                        break;
                    }
                }

                // Check if process is still alive
                match session.wait_status(Some(Duration::from_millis(0))) {
                    Ok(Some(WaitStatus::Exited(_, _))) => break,
                    Ok(Some(WaitStatus::Signaled(_, _))) => break,
                    _ => {}
                }
            }

            eprintln!("Read thread exiting");
        });

        // Spawn write thread
        let write_pty = pty.try_clone().context("Failed to clone PTY for writing")?;
        task::spawn(async move {
            let mut session = Session::new(write_pty);
            let mut input_rx = input_rx;

            while let Some(input) = input_rx.recv().await {
                if session.send(&input).is_err() {
                    break;
                }
                // Flush to ensure data is sent
                if session.flush().is_err() {
                    break;
