use std::task::{Context, Poll, Waker};
use std::sync::Arc;
use tokio::sync::oneshot;

/// Custom waker that does nothing when woken
/// Used for initial polling without waking the runtime
struct NoopWaker;

impl NoopWaker {
    fn waker() -> Waker {
        // SAFETY: The vtable functions are all no-ops
        unsafe {
            Waker::from_raw(Arc::new(NoopWaker).into_raw())
        }
    }
}

impl std::task::Wake for NoopWaker {
    fn wake(self: Arc<Self>) {
        // No-op
    }

    fn wake_by_ref(self: &Arc<Self>) {
        // No-op
    }
}

#[derive(Debug)]
pub enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Try to poll a future once. If it's ready, return the value.
/// If it's pending, return Pending without consuming the future.
/// 
/// IMPORTANT: This function should only be called from within a tokio runtime,
/// and the future should not be polled again after returning Pending
/// (it will be moved into the spawned task).
pub fn try_poll<F, X>(future: Pin<&mut F>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    let waker = NoopWaker::waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Helper function that demonstrates the complete workflow:
/// 1. Try to poll the future immediately
/// 2. If ready, use the value
/// 3. If pending, spawn a task to await it and handle the result
pub fn try_poll_or_spawn<F, X, Handler>(mut future: F, handler: Handler)
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static,
    Handler: FnOnce(X) + Send + 'static,
{
    // Pin the future on the stack
    let mut future = unsafe { Pin::new_unchecked(&mut future) };

    match try_poll(future.as_mut()) {
        TryPollResult::Ready(value) => {
            // Future completed immediately - use the value
            handler(value);
        }
        TryPollResult::Pending => {
            // Future needs more time - spawn a task to await it
            // Note: We need to move the future, so we can't use the pinned reference
            // This is why we take back ownership
            let mut future = unsafe { Pin::into_inner_unchecked(future) };

            tokio::spawn(async move {
                let value = future.await;
                handler(value);
            });
        }
    }
}

// Example usage
async fn async_operation_immediate() -> String {
    "Completed immediately".to_string()
}

async fn async_operation_delayed() -> String {
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    "Completed after delay".to_string()
}

#[tokio::main]
async fn main() {
    println!("Testing manual polling with Tokio\n");

    // Example 1: Immediate completion
    println!("Example 1: Immediate future");
    let immediate_future = async_operation_immediate();

    try_poll_or_spawn(immediate_future, |result| {
        println!("  Result: {}", result);
    });

    // Give the runtime a moment to process any spawned tasks
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    println!();

    // Example 2: Delayed completion
    println!("Example 2: Delayed future");
    let delayed_future = async_operation_delayed();

    // Use a oneshot channel to communicate between spawned task and main
    let (tx, rx) = oneshot::channel();

    try_poll_or_spawn(delayed_future, move |result| {
        println!("  Result from spawned task: {}", result);
        let _ = tx.send(result);
    });

    // Wait for the result from the spawned task
    match rx.await {
        Ok(result) => println!("  Main received: {}", result),
        Err(_) => println!("  Failed to receive result"),
    }

    // Example 3: Manual polling with direct use
    println!("\nExample 3: Manual polling without spawning");
    let mut another_immediate = async_operation_immediate();
    let mut pinned = unsafe { Pin::new_unchecked(&mut another_immediate) };

    match try_poll(pinned.as_mut()) {
        TryPollResult::Ready(result) => {
            println!("  Direct poll result: {}", result);
        }
        TryPollResult::Pending => {
            println!("  Future would need to be spawned");
        }
    }

