/// Main entry point that processes a Rust source file
pub fn rewrite_imports_in_file(source: &str) -> String {
    let parsed = ra_ap_syntax::SourceFile::parse(source);
    let syntax = parsed.tree().syntax().clone();

    // We'll collect all edits and apply them at the end
    let mut edits = Vec::new();

    for use_item in syntax.descendants().filter_map(ast::Use::cast) {
        process_use_item(use_item, &mut edits);
    }

    // Sort edits by start position (latest to earliest to avoid offset issues)
    edits.sort_by_key(|e| e.range.start());
    edits.reverse();

    // Apply all edits to the source
    let mut result = source.to_string();
    for edit in edits {
        result.replace_range(edit.range.start().into()..edit.range.end().into(), &edit.replacement);
    }

