struct Edit {
    range: TextRange,
    replacement: String,
}

/// Process a single use item and collect necessary edits
fn process_use_item(use_item: ast::Use, edits: &mut Vec<Edit>) {
    let Some(tree) = use_item.use_tree() else { return };

    // We'll process the tree recursively
    let mut new_tree = process_use_tree(&tree, Vec::new());

    // If the resulting tree is None, we need to remove the entire use statement
    if new_tree.is_none() {
