/// Recursively process a use tree, returning an Option since trees might be removed
fn process_use_tree(tree: &ast::UseTree, current_path: Vec<String>) -> Option<ast::UseTree> {
    let mut path_parts = current_path.clone();

    // If this tree has a path, add its segments to our current path
    if let Some(path) = tree.path() {
        for segment in path.segments() {
            if let Some(name) = segment.name_ref() {
