            } else {
                // Top-level tree without a path
                Some(make::use_tree_list_only(list))
            }
        } else if let Some(path) = path {
            if tree.star_token().is_some() {
                Some(make::use_tree_glob(path, tree.alias().as_ref().cloned()))
            } else {
                Some(make::use_tree(path, None, tree.alias().as_ref().cloned()))
            }
        } else {
            // Shouldn't happen in valid Rust
            None
        }
    }
}

/// Convert a processed UseTree back to string representation
fn tree_to_string(tree: &ast::UseTree) -> String {
    let mut result = String::new();

    if let Some(path) = tree.path() {
        result.push_str(&path.to_string());
    }

    if let Some(list) = tree.use_tree_list() {
        result.push_str("{");
        let children: Vec<String> = list.use_trees().map(|t| tree_to_string(&t)).collect();
        result.push_str(&children.join(", "));
        result.push_str("}");
    }

    if tree.star_token().is_some() {
        result.push_str("::*");
    }

    if let Some(alias) = tree.alias() {
        result.push_str(&format!(" as {}", alias.to_string()));
    }

    result
}

/// Helper function to create a path from text
fn make_path_from_text(text: &str) -> ast::Path {
    make::path_from_text(text)
}

