response:
Looking at your problem, the issue is that `log` macros use `module_path!()` which captures the compile-time module path where the macro is expanded. When you call it from a helper function, it will always show that helper function's module.

Here's a solution that creates a custom logging macro that captures the caller's location and passes it along, allowing you to get the calling code's module in the logs:

```json
{
  "Cargo.toml": "[package]
name = "custom-logger-demo"
version = "0.1.0"
edition = "2024"

[dependencies]
dotenvy = "0.15.7"
env_logger = "0.11.8"
log = "0.4.27"
thiserror = "2.0.14"
",
  "main.rs": "use std::fmt::{Display, Debug};

// Custom macro that captures caller location
#[macro_export]
macro_rules! log_with_caller {
    ($level:expr, $module:expr, $file:expr, $line:expr, $($arg:tt)*) => {
        log::log!(
            $level,
            target: $module,
            "[{}:{}] {}",
            $file,
            $line,
            format_args!($($arg)*)
        )
    };
}

// Convenience macros
#[macro_export]
macro_rules! info_caller {
    ($($arg:tt)*) => {
        $crate::log_with_caller!(
            log::Level::Info,
            module_path!(),
            std::panic::Location::caller().file(),
            std::panic::Location::caller().line(),
            $($arg)*
        )
    };
}

#[macro_export]
macro_rules! warn_caller {
    ($($arg:tt)*) => {
        $crate::log_with_caller!(
            log::Level::Warn,
            module_path!(),
            std::panic::Location::caller().file(),
            std::panic::Location::caller().line(),
            $($arg)*
        )
    };
}

#[macro_export]
macro_rules! error_caller {
    ($($arg:tt)*) => {
        $crate::log_with_caller!(
            log::Level::Error,
            module_path!(),
            std::panic::Location::caller().file(),
            std::panic::Location::caller().line(),
            $($arg)*
        )
    };
}

#[derive(Debug, thiserror::Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(Box<dyn std::error::Error>),
}

pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;

            pub trait LogChangeErrForRespExt {
                type R;

                #[track_caller]
                fn log_and_explain_400(self) -> Self::R;
            }

            impl<T, E: std::error::Error + 'static> LogChangeErrForRespExt for Result<T, E> {
                type R = Result<T, FrameworkError>;

                /// Logs the client error using our custom logger and returns the Display string
                /// of the original error to the client
                #[track_caller]
                fn log_and_explain_400(self) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            let loc = std::panic::Location::caller();

                            // Use our custom logger that includes the actual caller's info
                            crate::warn_caller!(
                                "Error at {}:{}: {err:?}",
                                loc.file(),
                                loc.line(),
                            );

                            Err(FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }
            }
        }
    }
}

use my_library::extensions::logging::LogChangeErrForRespExt;

pub mod my_application_code {
    pub mod routes_example {
        use crate::LogChangeErrForRespExt;

        fn failing_function() -> Result<u32, std::num::ParseIntError> {
            "abc".parse()
        }

        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            // This will show the correct module
            crate::warn_caller!("This log call is from the correct module");

            // Regular log for comparison
            log::warn!("Regular log - shows helper module");

            let long_chain = failing_function().log_and_explain_400()? + 42;
            Ok(long_chain)
        }
    }
}

fn main() {
    let _ = dotenvy::dotenv();
    env_logger::builder()
        .filter_level(log::LevelFilter::Info)
        .format_module_path(true) // Show module paths in logs
        .init();

    println!("=== Using custom logger with caller info ===");
    let failure = my_application_code::routes_example::some_route();
    println!("Result: {failure:?}\n");

    // Additional example to show the difference
    println!("=== Direct comparison ===");
    direct_log_example();
}

fn direct_log_example() {
    crate::info_caller!("This shows the calling function's module");
    log::info!("This shows helper::module's module");
}
"
}
```

This solution provides:

1. **`log_with_caller!`**: A base macro that takes explicit module, file, and line parameters
2. **Convenience macros** (`info_caller!`, `warn_caller!`, `error_caller!`): Macros that capture the caller's location and module automatically
3. **Integration with your helper functions**: The macros can be called from anywhere and will show the actual calling code's module in the logs

The key insights:
- We create custom macros that capture `module_path!()` at the **call site**, not at the helper function definition site
- We use `#[track_caller]` to get the file and line, but we need to capture the module separately
- The custom macros format the log message to include both the module path (as the log target) and the file/line in the message

When you run this, you'll see:
- Custom logs show `custom-logger-demo::my_application_code::routes_example` as the module
- Regular `log::warn!` calls from helper functions still show `custom-logger-demo::my_library::extensions::logging`

You can use `*_caller!` macros throughout your codebase for consistent logging with accurate caller information.

