    "OK"
}

// WebSocket handler with origin validation
async fn websocket_handler(
    ws: WebSocketUpgrade,
    origin: Option<TypedHeader<Origin>>,
) -> impl IntoResponse {
    // Define allowed origins
    let allowed_origins = [
        "https://www.example.com",
        "https://example.com",
        // Add more allowed origins as needed
    ];

    // Check if origin is present and valid
    let origin_valid = match origin {
        Some(TypedHeader(origin)) => {
            let origin_str = origin.to_string();
            allowed_origins
                .iter()
                .any(|allowed| origin_str == *allowed)
        }
        None => {
            // No origin header - this could be a same-origin request or a non-browser client
            // You can choose to allow or deny these requests
            // For strict security, you might want to reject these
            false
        }
    };

    if !origin_valid {
        tracing::warn!("WebSocket connection rejected from invalid origin");
        return axum::http::StatusCode::FORBIDDEN.into_response();
    }

    // Origin is valid, proceed with WebSocket upgrade
    ws.on_upgrade(|socket| async move {
        handle_socket(socket).await;
    })
}

// Handler for WebSocket connections
async fn handle_socket(socket: axum::extract::ws::WebSocket) {
    tracing::info!("WebSocket connection established");

    // Split the socket into sender and receiver
    let (mut sender, mut receiver) = socket.split();

    // Simple echo handler
    while let Some(Ok(message)) = receiver.recv().await {
        if let axum::extract::ws::Message::Text(text) = message {
            tracing::info!("Received message: {}", text);

            // Echo the message back
            if sender
                .send(axum::extract::ws::Message::Text(text))
                .await
                .is_err()
            {
                break;
            }
        }
    }

    tracing::info!("WebSocket connection closed");
}
