use std::task::{Context, Poll};
use std::future::Future;

// This is the key wrapper that ties the lifetime of the deserialized data
// to the original String data, making it Send + 'static
struct BorrowedDataContainer {
    // Store the original string data in an Arc
    original_data: Arc<str>,
    // Store the deserialized struct with static lifetime.
    // We use ManuallyDrop to control when the deserialized struct is dropped.
    // The deserialized struct borrows from `original_data`.
    deserialized: std::mem::ManuallyDrop<MyData<'static>>,
}

// SAFETY: We ensure that:
// 1. The MyData<'static> actually borrows from the Arc<str> in original_data
// 2. The BorrowedDataContainer is not moved after the MyData is created
// 3. We properly clean up in Drop implementation
unsafe impl Send for BorrowedDataContainer {}
unsafe impl Sync for BorrowedDataContainer {}

impl BorrowedDataContainer {
    fn new(json_string: String) -> Result<Self, serde_json::Error> {
        // Convert to Arc<str> for cheap cloning and stable memory address
        let arc_str: Arc<str> = json_string.into();

        // Deserialize by borrowing from the Arc<str>
        // We extend the lifetime to 'static because we know the Arc will keep it alive
        let deserialized: MyData = serde_json::from_str(&arc_str)?;

        // SAFETY: We know deserialized borrows from arc_str, and arc_str will be kept alive
        // by self.original_data. We're extending the lifetime to 'static which is safe
        // as long as the container stays together.
        let deserialized_static: MyData<'static> = unsafe {
            std::mem::transmute(deserialized)
        };

        Ok(BorrowedDataContainer {
            original_data: arc_str,
            deserialized: std::mem::ManuallyDrop::new(deserialized_static),
        })
    }

    fn get_data(&self) -> &MyData {
        &self.deserialized
    }
}

impl Drop for BorrowedDataContainer {
    fn drop(&mut self) {
        // SAFETY: We need to manually drop the deserialized struct before
        // the original_data Arc is dropped. This ensures proper drop order.
        unsafe {
            std::mem::ManuallyDrop::drop(&mut self.deserialized);
        }
        // Now original_data Arc will be dropped normally
    }
}

#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

