    let data = container.get_data();
    println!("Processing in async task: data={}, more_data={}", 
             data.data, data.more_data);
}

// A custom future that allows spawning with non-static data
struct ProcessDataFuture {
    container: Arc<BorrowedDataContainer>,
}

impl Future for ProcessDataFuture {
    type Output = ();

    fn poll(self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
        let data = self.container.get_data();
        println!("Processing in custom future: data={}, more_data={}", 
                 data.data, data.more_data);
        Poll::Ready(())
    }
}

