    let json_string = r#"{"data": "hello", "more_data": "world"}"#.to_string();

    // Parse once into our container
    let container = BorrowedDataContainer::new(json_string)
        .expect("Failed to deserialize JSON");

    // Wrap in Arc for sharing across tasks
    let shared_container = Arc::new(container);

    println!("Original deserialized: {:?}", shared_container.get_data());

    // Method 1: Using tokio::spawn with the container inside an Arc
    let container_clone = shared_container.clone();
    tokio::spawn(async move {
