    let (tx, mut rx) = mpsc::channel::<Arc<BorrowedDataContainer>>(10);

    let sender_task = tokio::spawn(async move {
        let container_clone = shared_container.clone();
        tx.send(container_clone).await.expect("Failed to send");
    });

    let receiver_task = tokio::spawn(async move {
        if let Some(received) = rx.recv().await {
