use std::str::FromStr;

/// Parse LanceDB date strings which can come in two formats:
/// 1. Without fractional seconds: "1970-01-01T00:00:00"
/// 2. With fractional seconds: "2025-08-02T17:35:41.409"
/// 
/// Returns a DateTime<Utc> which can be converted to timestamp with `.timestamp()`
pub fn parse_lancedb_date(date_str: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // Try parsing as ISO8601 with fractional seconds first
    if let Ok(dt) = DateTime::parse_from_str(&format!("{date_str}Z"), "%Y-%m-%dT%H:%M:%S%.f%z") {
        return Ok(dt.with_timezone(&Utc));
    }

    // Try parsing without fractional seconds
    if let Ok(dt) = DateTime::parse_from_str(&format!("{date_str}Z"), "%Y-%m-%dT%H:%M:%S%z") {
        return Ok(dt.with_timezone(&Utc));
    }

    // Try parsing as NaiveDateTime (without timezone)
    if let Ok(ndt) = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S%.f") {
        return Ok(DateTime::from_naive_utc_and_offset(ndt, Utc));
    }

    // Try parsing as NaiveDateTime without fractional seconds
    if let Ok(ndt) = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S") {
        return Ok(DateTime::from_naive_utc_and_offset(ndt, Utc));
    }

    // As a last resort, try chrono's built-in DateTime parser
    DateTime::from_str(date_str).map(|dt| dt.with_timezone(&Utc))
}

/// Convert LanceDB date string to Unix timestamp (seconds since epoch)
pub fn date_string_to_timestamp(date_str: &str) -> Result<i64, chrono::ParseError> {
    parse_lancedb_date(date_str).map(|dt| dt.timestamp())
}

fn main() {
    let test_cases = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
        // Edge cases
        "2025-08-10T18:31:26",           // without fractional seconds
        "2025-08-10T18:31:26.1",         // 1 digit fractional
        "2025-08-10T18:31:26.12",        // 2 digits fractional
        "2025-08-10T18:31:26.123456789", // 9 digits fractional
    ];

    println!("Parsing LanceDB date strings:");
    println!("============================");

    for date_str in test_cases {
        match parse_lancedb_date(date_str) {
            Ok(datetime) => {
                let timestamp = datetime.timestamp();
                let formatted = datetime.format("%Y-%m-%d %H:%M:%S%.f UTC");
                println!("String: {:?}", date_str);
                println!("  -> DateTime: {}", formatted);
                println!("  -> Timestamp: {} seconds", timestamp);
                println!("  -> Timestamp (ms): {} milliseconds", datetime.timestamp_millis());
            }
            Err(e) => {
                println!("String: {:?}", date_str);
                println!("  -> ERROR: {}", e);
            }
        }
        println!();
    }

    // Example of converting back and forth
    println!("\nRound-trip example:");
    println!("===================");

    let original_timestamp = 1743615341; // Some timestamp
    let datetime = Utc.timestamp_opt(original_timestamp, 0).unwrap();
    println!("Original timestamp: {}", original_timestamp);
    println!("As DateTime: {}", datetime);

    // Convert to LanceDB-like string
