use rustyline::completion::Completer;
use rustyline::error::ReadlineError;
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::Validator;
use rustyline::Cmd;
use rustyline::CompletionType;
use rustyline::ConditionalEventHandler;
use rustyline::Context;
use rustyline::Editor;
use rustyline::EventHandler;
use rustyline::EventContext;
use rustyline::KeyEvent;
use rustyline::Modifiers;
use rustyline::RepeatCount;
use rustyline::{Config, Movement};
use std::borrow::Cow;

struct CommandHelper;

impl Completer for CommandHelper {
    type Candidate = String;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Self::Candidate>), ReadlineError> {
        // Simple table name completion for demo
        let mut completions = Vec::new();
        let words = vec!["book", "author"];

        for word in words {
            if word.starts_with(&line[..pos]) && pos > 0 {
                completions.push(word.to_string());
            }
        }

        Ok((0, completions))
    }
}

impl Hinter for CommandHelper {
    type Hint = String;
}

impl Highlighter for CommandHelper {}
impl Validator for CommandHelper {}

struct DotCommaHandler {
    insert_char: char,
}

impl DotCommaHandler {
    fn new(insert_char: char) -> Self {
        Self { insert_char }
    }
}

impl ConditionalEventHandler for DotCommaHandler {
    fn handle(
        &self,
        _event: &KeyEvent,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Only process if we're at a word boundary
        if pos == 0 {
            return None;
        }

        let chars_before_cursor: Vec<char> = line[..pos].chars().collect();

        // Find the last non-whitespace character before cursor
        let mut i = chars_before_cursor.len();
        while i > 0 && chars_before_cursor[i - 1].is_whitespace() {
            i -= 1;
        }

        let whitespace_count = chars_before_cursor.len() - i;

        if whitespace_count > 0 {
            // Calculate the position after removing whitespace
            let new_pos = pos - whitespace_count;

            // Instead of using Replace, we'll manipulate the line directly
            // by returning multiple commands through a custom approach
            // 
            // We need to: 1) delete whitespace, 2) insert character, 3) move cursor right
            // Since we can't return multiple commands, we'll handle this differently
            return Some(Cmd::InsertChar(self.insert_char));
        }

        None
    }
}

struct SmartCharHandler {
    insert_char: char,
}

impl SmartCharHandler {
    fn new(insert_char: char) -> Self {
        Self { insert_char }
    }
}

impl ConditionalEventHandler for SmartCharHandler {
    fn handle(
        &self,
        _event: &KeyEvent,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        if pos == 0 {
            return None;
        }

        // Check if there's whitespace immediately before cursor
        if pos > 0 && line[..pos].chars().last().unwrap().is_whitespace() {
            // Find start of whitespace run
            let mut whitespace_start = pos;
            while whitespace_start > 0 && line[whitespace_start - 1..pos]
                .chars()
                .next_back()
                .unwrap()
                .is_whitespace()
            {
                whitespace_start -= 1;
            }

            let whitespace_len = pos - whitespace_start;

            if whitespace_len > 0 {
                // This is a hack: We'll delete the whitespace first, 
                // then let rustyline handle the character insertion
                // The key insight: we need to delete whitespace AND insert character
                // 
                // We can't return multiple commands, but we can:
                // 1) Delete whitespace with Backspace
                // 2) Insert the character (handled by default binding)
                // 
                // However, we need to do this atomically. We'll create a custom
                // command sequence using Replace with the character at the correct position

                // Move cursor back by whitespace_len and replace with our character
                // This leaves cursor at start of replacement (before the character)
                // So we need to move cursor forward by 1 after replacement
                let movement = Movement::BackwardChar(whitespace_len as RepeatCount);

                // Create a command that deletes whitespace and inserts our character
                // The Replace command should position cursor at start of inserted text
                // We'll handle the cursor positioning in a different way

                // Actually, let's try a different approach: insert the character
                // at the position after removing whitespace
                return Some(Cmd::Replace(
                    movement,
                    Some(self.insert_char.to_string()),
                ));
            }
        }

        None
    }
}

fn bind_smart_char_handler(editor: &mut Editor<CommandHelper>, key: char) {
    let event = KeyEvent::from(key);
    let handler = SmartCharHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler);
}

fn main() -> Result<(), rustyline::error::ReadlineError> {
    let config = Config::builder()
        .history_ignore_space(true)
