//! concrete methods without infinite recursion.
//!
//! The key insight is to generate code in a separate module where the trait
//! is not in scope, ensuring that only the concrete method is called.

// ==================== LIBRARY (proc-macro) ====================
// This would normally be in src/lib.rs, but we're including it here
// for a self-contained example.

use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, DeriveInput, Generics, PathArguments, TypeParamBound};
use syn::punctuated::Punctuated;
use syn::Token;

#[proc_macro_derive(Foo)]
pub fn derive_foo(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);

    let name = &input.ident;
    let generics = &input.generics;

    // Generate the module name with a unique identifier
    let mod_name = syn::Ident::new(
        &format!("__foo_impl_for_{}", name),
        name.span(),
    );

    // Process generics for use in the module
    let (impl_generics, ty_generics, where_clause) = generics.split_for_impl();

    // Create generic parameters for the module function
    let module_generics = create_module_generics(generics);
    let (module_impl_generics, module_ty_generics, _) = module_generics.split_for_impl();

    let expanded = quote! {
        // Create a private module where the trait is not in scope
        mod #mod_name {
            // Bring the concrete type into scope
            use super::#name;

            // Bring all generic parameters into scope
            use super::*;

            // Helper function that calls the concrete method
            // This is in a module where the trait is not imported,
            // so it can only call the concrete method
            #[inline]
            pub fn go #module_impl_generics (inst: &#name #module_ty_generics) #where_clause {
                // The trait `Foo` is not in scope here, so this can only
                // call the concrete method on the type
                inst.go();
            }
        }

        // Implement the trait using our helper function
        impl #impl_generics ::foo::Foo for #name #ty_generics #where_clause {
            #[inline]
            fn go(&self) {
                // Call through the module function which ensures
                // we call the concrete implementation
                #mod_name::go #ty_generics (self);
            }
        }
    };

    expanded.into()
}

/// Creates a new set of generics for use in the module.
/// This ensures we don't accidentally bring trait bounds that might
/// conflict with our isolation strategy.
fn create_module_generics(original: &Generics) -> Generics {
    let mut generics = original.clone();

    // Clear all trait bounds from type parameters
    for param in &mut generics.params {
        if let syn::GenericParam::Type(type_param) = param {
            type_param.bounds = Punctuated::new();
        }
    }

    // Clear the where clause completely
    generics.where_clause = None;

    generics
}

