/// Method 1: Process while preserving nested structure
/// This is the most elegant approach as it directly maps to the problem
fn parallel_process_nested(a: &Vec<Vec<usize>>) -> Vec<Vec<String>> {
    a.par_iter()  // Parallel iteration over outer vector
        .map(|inner_vec| {
            inner_vec
                .par_iter()  // Parallel iteration over inner vector
                .map(|&x| process_element(x))
                .collect()
        })
        .collect()
}

/// Method 2: Flatten-process-reshape approach
/// This might be useful if you need to process all elements as a single batch
fn flatten_process_reshape(a: &Vec<Vec<usize>>) -> Vec<Vec<String>> {
    // Step 1: Record the structure (lengths of inner vectors)
    let structure: Vec<usize> = a.iter().map(|v| v.len()).collect();

    // Step 2: Flatten the nested vector
    let flat: Vec<usize> = a.iter().flat_map(|v| v.iter().copied()).collect();

    // Step 3: Process flattened vector in parallel
    let processed_flat: Vec<String> = flat
        .par_iter()
        .map(|&x| process_element(x))
        .collect();

    // Step 4: Reshape back to original structure
    let mut result = Vec::new();
    let mut current_index = 0;

    for &len in &structure {
        let end = current_index + len;
        result.push(processed_flat[current_index..end].to_vec());
        current_index = end;
    }

    result
}

/// Method 4: Single parallel pass using enumerate to track positions
fn parallel_single_pass(a: &Vec<Vec<usize>>) -> Vec<Vec<String>> {
    // First, create a flat structure with indices
    let flat_with_indices: Vec<(usize, usize, usize)> = a
        .iter()
        .enumerate()
        .flat_map(|(i, inner_vec)| {
            inner_vec
                .iter()
                .enumerate()
                .map(move |(j, &x)| (i, j, x))
        })
        .collect();

    // Process in parallel
    let processed: Vec<(usize, usize, String)> = flat_with_indices
        .par_iter()
        .map(|&(i, j, x)| (i, j, process_element(x)))
        .collect();

    // Reconstruct the nested structure
    let mut result: Vec<Vec<String>> = vec![Vec::new(); a.len()];

    for (i, j, value) in processed {
        // Ensure we have enough inner vectors
        while result.len() <= i {
            result.push(Vec::new());
        }
        // Ensure the inner vector has enough slots
        while result[i].len() <= j {
            result[i].push(String::new());
        }
        result[i][j] = value;
    }

    result
