async fn harness2<'a, T, Fut>(test: T)
where
    T: Fn(&'a mut String) -> Fut,
    Fut: Future<Output = ()> + 'a,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

// Solution 3: Use a trait object (simpler but involves boxing)
async fn harness_boxed<T>(test: T)
where
    T: for<'a> Fn(&'a mut String) -> std::pin::Pin<Box<dyn Future<Output = ()> + 'a>>,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

// Helper function to box the future
fn box_test<F, Fut>(f: F) -> impl for<'a> Fn(&'a mut String) -> std::pin::Pin<Box<dyn Future<Output = ()> + 'a>>
where
    F: for<'a> Fn(&'a mut String) -> Fut,
    Fut: Future<Output = ()> + 'a,
{
    move |s| Box::pin(f(s))
}

