// Custom helper to handle multiline validation and continuation prompt
#[derive(Default)]
struct MultilineValidator {
    prompt: String,
    continuation_prompt: String,
}

impl MultilineValidator {
    fn new(prompt: &str, continuation_prompt: &str) -> Self {
        Self {
            prompt: prompt.to_string(),
            continuation_prompt: continuation_prompt.to_string(),
        }
    }
