        .completion_type(CompletionType::List)
        .edit_mode(rustyline::EditMode::Emacs)
        .multiline(true)  // Enable multiline mode
        .build();

    let helper = MultilineValidator::new(">> ", ".. ");

    let mut rl = Editor::with_config(config)?;
    rl.set_helper(Some(helper));

    // Bind Ctrl+J to insert newline
    rl.bind_sequence(
        KeyEvent::new('j', Modifiers::CTRL),
        EventHandler::Conditional(Box::new(MultilineValidator::new(">> ", ".. "))),
    );

    println!("Multiline REPL. Type your input and press Ctrl+J for newline. End with ';' and press Enter to submit.");
    println!("Press Ctrl+C or type 'exit' to quit.");

    loop {
        // Get the current helper to access prompts
        let helper = rl.helper().unwrap();

        // Read line with main prompt
        let readline = rl.readline(&helper.prompt);

        match readline {
            Ok(line) => {
                let trimmed = line.trim();

                // Check for exit command
                if trimmed == "exit" || trimmed == "quit" {
                    println!("Goodbye!");
                    break;
                }

                // If line doesn't end with semicolon, we're in multiline mode
                if !trimmed.ends_with(';') && !trimmed.is_empty() {
                    // Add the line to buffer and continue with continuation prompt
                    rl.add_history_entry(&line)?;

                    // Set continuation prompt for next line
                    // Note: rustyline's multiline mode handles this automatically
                    // when validation returns Invalid
                } else {
                    // Complete input
                    println!("Processing: {}", line);
                    rl.add_history_entry(&line)?;
                    // Reset to main prompt for next input
                }
