use std::sync::Arc;

/// Custom operator: square root of absolute value plus 1
/// sqrt(abs(x)) + 1
#[derive(Debug, Clone)]
struct SqrtPlusOne;

impl Operation for SqrtPlusOne {
    /// Execute the operation on given inputs
    fn execute(&self, inputs: &[f32]) -> f32 {
        if inputs.is_empty() {
            return 1.0;
        }
        let val = inputs[0].abs(); // Take absolute value
        val.sqrt() + 1.0 // sqrt(|x|) + 1
    }

    /// Get the string representation of this operation
    fn display(&self) -> String {
        "sqrt_plus_one".to_string()
    }

    /// Get the symbol for this operation
    fn symbol(&self) -> String {
        "√|x|+1".to_string()
    }

    /// Get the arity (number of arguments) this operation takes
    fn arity(&self) -> usize {
        1 // Takes one argument
    }
}

/// Another custom operator: safe division with minimum threshold
/// x / max(y, 0.001) to avoid division by zero
#[derive(Debug, Clone)]
struct SafeDiv;

impl Operation for SafeDiv {
    fn execute(&self, inputs: &[f32]) -> f32 {
        if inputs.len() < 2 {
            return 1.0;
        }
        let numerator = inputs[0];
        let denominator = inputs[1].abs();

        // Avoid division by zero by using a minimum threshold
        if denominator < 0.001 {
            numerator / 0.001
        } else {
            numerator / denominator
        }
    }

    fn display(&self) -> String {
        "safe_div".to_string()
    }

    fn symbol(&self) -> String {
        "÷".to_string()
    }

    fn arity(&self) -> usize {
        2 // Takes two arguments
    }
}

/// A wrapper to create Op enum variants from custom operations
struct CustomOps;

impl CustomOps {
    /// Create an Op enum variant for the SqrtPlusOne operation
    fn sqrt_plus_one() -> Op {
        Op::Custom(Arc::new(SqrtPlusOne))
    }

    /// Create an Op enum variant for the SafeDiv operation
    fn safe_div() -> Op {
        Op::Custom(Arc::new(SafeDiv))
    }
}

/// Simple problem to evolve a function that approximates f(x) = sqrt(|x|) + 1
#[derive(Debug, Clone)]
struct RobotLogicProblem {
    inputs: Vec<Vec<f32>>,
    targets: Vec<f32>,
}

impl Problem<Tree> for RobotLogicProblem {
    fn empty(&self) -> Tree {
        Tree::new()
    }

    fn solve(&self, tree: &mut Tree) -> f32 {
        let mut total_error = 0.0;

        for (input, &target) in self.inputs.iter().zip(self.targets.iter()) {
            let output = tree.eval(input).unwrap_or(0.0);
            let error = (output - target).abs();
            total_error += error;
        }

        // Lower error is better, so we return negative error
        // (radiate maximizes fitness, so we want to maximize negative error)
        -total_error
    }
}

fn main() {
    // Create training data: f(x) = sqrt(|x|) + 1
    let mut inputs = Vec::new();
    let mut targets = Vec::new();

    for i in -5..=5 {
        let x = i as f32;
        inputs.push(vec![x]);
        targets.push(x.abs().sqrt() + 1.0);
    }

    let problem = RobotLogicProblem { inputs, targets };

    // Define the function set with both built-in and custom operators
    let function_set = vec![
        // Built-in operations
        Op::add(),
        Op::sub(),
        Op::mul(),
        // Custom operations
        CustomOps::sqrt_plus_one(),
        CustomOps::safe_div(),
    ];

    // Define the terminal set (input variables and constants)
    let terminal_set = vec![
        Op::var(0), // x
        Op::cons(1.0),
        Op::cons(2.0),
        Op::cons(0.5),
    ];

    // Create the tree builder configuration
    let config = TreeBuilder::new()
        .set_max_depth(4)
        .set_min_depth(1)
        .set_function_set(function_set)
        .set_terminal_set(terminal_set)
        .set_float_const_range(-5.0, 5.0);

    // Create the evolution environment
    let mut environment = Environment::new()
        .set_population_size(100)
        .set_tree_builder(config)
        .set_max_generations(50)
        .set_crossover_rate(0.9)
        .set_mutation_rate(0.1)
        .set_problem(problem)
        .configure_par_builder();

    // Run the evolution
    let (solution, fitness) = environment.evolve();

    // Display results
    println!("Best solution found with fitness: {}", fitness);
    println!("Tree representation: {}", solution);

    // Test the evolved solution
    println!("\nTesting the evolved function:");
    println!("x\tTarget\tPredicted");

    for i in -5..=5 {
        let x = i as f32;
        let target = x.abs().sqrt() + 1.0;
        let predicted = solution.eval(&[x]).unwrap_or(0.0);

        println!("{:.1}\t{:.3}\t{:.3}", x, target, predicted);
    }

    // Demonstrate custom operators directly
    println!("\nDemonstrating custom operators:");

    // Create a simple tree with custom operators
    let sqrt_node = TreeNode::new(CustomOps::sqrt_plus_one());
    let var_node = TreeNode::new(Op::var(0));

    // Build tree: sqrt_plus_one(x)
    let mut custom_tree = Tree::new();
    custom_tree.set_root(Some(sqrt_node.clone()));
    custom_tree.add_child(&sqrt_node, var_node).unwrap();

    println!("Custom tree: {}", custom_tree);

    // Test the custom tree
    for &x in &[-4.0, -1.0, 0.0, 1.0, 4.0, 9.0] {
        let result = custom_tree.eval(&[x]).unwrap_or(0.0);
        println!("sqrt_plus_one({}) = {:.3}", x, result);
    }
}
"
