  "main.rs": "use std::fs;
use std::path::{Path, PathBuf};
use serde::Deserialize;
use serde_json::Value;
use std::collections::HashMap;

#[derive(Deserialize, Debug)]
struct A {
    path_list: JsonRefOrPaths,
}

#[derive(Debug)]
enum JsonRefOrPaths {
    Direct(Vec<PathBuf>),
    Reference { file: String, pointer: String },
}

impl<'de> serde::Deserialize<'de> for JsonRefOrPaths {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        let value = Value::deserialize(deserializer)?;

        // Check if it's a $ref object
        if let Value::Object(map) = &value {
            if let Some(Value::String(ref_str)) = map.get("$ref") {
                // Parse the reference string (format: "file.json#/json/pointer")
                let parts: Vec<&str> = ref_str.split('#').collect();
                if parts.len() != 2 {
                    return Err(serde::de::Error::custom(
                        format!("Invalid $ref format: {}", ref_str)
                    ));
                }

                let file = parts[0].to_string();
                let pointer = parts[1].to_string();

                return Ok(JsonRefOrPaths::Reference { file, pointer });
            }
        }

        // Otherwise, try to deserialize as a direct array of paths
        let paths: Vec<PathBuf> = serde::Deserialize::deserialize(value)
            .map_err(serde::de::Error::custom)?;
        Ok(JsonRefOrPaths::Direct(paths))
    }
}

fn resolve_json_pointer<'a>(value: &'a Value, pointer: &str) -> Result<&'a Value, String> {
    if pointer.is_empty() || pointer == "/" {
        return Ok(value);
    }

    // Simple JSON pointer implementation
    let path_segments: Vec<&str> = pointer.trim_start_matches('/').split('/').collect();

    let mut current = value;
    for segment in path_segments {
        let decoded_segment = segment.replace("~1", "/").replace("~0", "~");

        if let Value::Object(map) = current {
            current = map.get(&decoded_segment)
                .ok_or_else(|| format!("Key '{}' not found in JSON", decoded_segment))?;
        } else if let Value::Array(arr) = current {
            let index: usize = decoded_segment.parse()
                .map_err(|_| format!("Invalid array index: {}", decoded_segment))?;

            if index >= arr.len() {
                return Err(format!("Array index {} out of bounds (length: {})", index, arr.len()));
            }

            current = &arr[index];
        } else {
            return Err(format!("Cannot traverse into non-container type at segment: {}", decoded_segment));
        }
    }

    Ok(current)
}

fn load_referenced_paths(base_dir: &Path, reference: &JsonRefOrPaths) -> Result<Vec<PathBuf>, String> {
    match reference {
        JsonRefOrPaths::Direct(paths) => Ok(paths.clone()),
        JsonRefOrPaths::Reference { file, pointer } => {
            // Build the full path to the referenced file
            let referenced_file_path = if file.starts_with('./') || file.starts_with('../') {
                base_dir.join(file)
            } else {
                PathBuf::from(file)
            };

            // Read and parse the referenced JSON file
            let json_content = fs::read_to_string(&referenced_file_path)
                .map_err(|e| format!("Failed to read {}: {}", referenced_file_path.display(), e))?;

            let json_value: Value = serde_json::from_str(&json_content)
                .map_err(|e| format!("Failed to parse {}: {}", referenced_file_path.display(), e))?;

            // Resolve the JSON pointer
            let target_value = resolve_json_pointer(&json_value, pointer)?;

            // Convert the JSON value to Vec<PathBuf>
            if let Value::Array(arr) = target_value {
                let mut paths = Vec::new();
                for val in arr {
                    if let Value::String(s) = val {
                        paths.push(PathBuf::from(s));
                    } else {
                        return Err(format!("Expected string in array, found: {:?}", val));
                    }
                }
                Ok(paths)
            } else {
                Err(format!("Expected array at JSON pointer {}, found: {:?}", pointer, target_value))
            }
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let b_json_path = PathBuf::from("b.json");
    let base_dir = b_json_path.parent().unwrap_or_else(|| Path::new("."));

    // Read and deserialize b.json
    let json_data = fs::read_to_string(&b_json_path)
        .map_err(|e| format!("failed to read {}: {}", b_json_path.display(), e))?;

    let a_obj: A = serde_json::from_str(&json_data)
        .map_err(|e| format!("deserialization failed: {}", e))?;

    // Resolve the paths (either directly or from reference)
    let paths = load_referenced_paths(base_dir, &a_obj.path_list)
        .map_err(|e| format!("failed to resolve paths: {}", e))?;

    // Print the resolved paths
    for p in &paths {
        println!("{}", p.display());
    }

    Ok(())
}
"
}
