use anyhow::{Context, Result};
use azure_core::auth::TokenCredential;
use azure_identity::ClientSecretCredential;
use azure_storage::prelude::StorageCredentials;
use azure_storage_blobs::prelude::{BlobServiceClient, ContainerClient};
use futures::stream::{FuturesOrdered, StreamExt};
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use std::time::Instant;
use tokio::sync::Semaphore;

#[derive(Debug, Serialize, Deserialize)]
struct TradeData {
    // Define your TradeData fields here
    // Example:
    id: String,
    timestamp: String,
    price: f64,
    quantity: f64,
    // Add other fields as needed
}

#[derive(Debug, thiserror::Error)]
enum AzureError {
    #[error("Environment variable error: {0}")]
    EnvVarError(String),
    #[error("Azure authentication error: {0}")]
    AuthError(#[from] azure_core::Error),
    #[error("Blob operation error: {0}")]
    BlobError(#[from] azure_storage_blobs::Error),
    #[error("JSON parsing error: {0}")]
    JsonError(#[from] serde_json::Error),
}

struct AzureBlobService {
    container_client: ContainerClient,
}

impl AzureBlobService {
    async fn new() -> Result<Self> {
        dotenv::dotenv().ok();

        let tenant_id = env::var("AZURE_TENANT_ID")
            .map_err(|_| AzureError::EnvVarError("AZURE_TENANT_ID".to_string()))?;
        let client_id = env::var("AZURE_CLIENT_ID")
            .map_err(|_| AzureError::EnvVarError("AZURE_CLIENT_ID".to_string()))?;
        let client_secret = env::var("AZURE_CLIENT_SECRET")
            .map_err(|_| AzureError::EnvVarError("AZURE_CLIENT_SECRET".to_string()))?;
        let account_name = env::var("AZURE_ACCOUNT_NAME")
            .map_err(|_| AzureError::EnvVarError("AZURE_ACCOUNT_NAME".to_string()))?;
        let container_name = env::var("AZURE_CONTAINER_NAME")
            .map_err(|_| AzureError::EnvVarError("AZURE_CONTAINER_NAME".to_string()))?;

        println!("[INFO] Initializing Azure Blob Service...");

        // Use azure_identity for proper credential handling
        let credential = Arc::new(ClientSecretCredential::new(
            tenant_id,
            client_id,
            client_secret,
            vec!["https://storage.azure.com/.default".to_string()],
        ));

        let storage_credentials = StorageCredentials::token_credential(credential);
        let blob_service_client =
            BlobServiceClient::new(&account_name, storage_credentials);

        let container_client = blob_service_client.container_client(&container_name);

        // Verify container exists
        container_client
            .get_properties()
            .await
            .context("Failed to connect to container")?;

        println!("[INFO] Connected to Azure Blob Container: {}", container_name);

        Ok(Self { container_client })
    }

    async fn load_trades_from_folder(&self, prefix: &str) -> Result<Vec<TradeData>> {
        println!("[INFO] Loading trades from prefix: {}", prefix);

        let start_time = Instant::now();

        // List all blobs
        let list_start = Instant::now();
        let mut blob_names = Vec::new();

        let mut stream = self.container_client
            .list_blobs()
            .prefix(prefix)
            .into_stream();

        while let Some(page) = stream.next().await {
            let page = page.context("Failed to list blobs")?;

            for blob in page.blobs.blobs() {
                if blob.name.ends_with(".json") {
                    blob_names.push(blob.name.clone());
                }
            }
        }

        println!("[INFO] Found {} blobs in {:.2}s", 
                 blob_names.len(), 
                 list_start.elapsed().as_secs_f32());

        if blob_names.is_empty() {
            return Ok(Vec::new());
        }

        // Download and parse blobs in parallel with controlled concurrency
        let download_start = Instant::now();

        // Use number of CPU cores for concurrency limit
        let num_cpus = num_cpus::get();
        let semaphore = Arc::new(Semaphore::new(num_cpus));

        let futures = FuturesOrdered::new();

        for blob_name in blob_names {
            let container_client = self.container_client.clone();
            let semaphore = Arc::clone(&semaphore);

            futures.push_back(tokio::spawn(async move {
                let _permit = semaphore.acquire().await.expect("Semaphore closed");

                match Self::download_and_parse_blob(&container_client, &blob_name).await {
                    Ok(trade) => Some(trade),
                    Err(e) => {
                        eprintln!("[WARN] Failed to process blob {}: {}", blob_name, e);
                        None
                    }
                }
            }));
        }

        // Collect results
        let results: Vec<TradeData> = futures
            .filter_map(|result| async {
                match result {
                    Ok(Some(trade)) => Some(trade),
                    Ok(None) => None,
                    Err(e) => {
                        eprintln!("[ERROR] Task failed: {}", e);
                        None
                    }
                }
            })
            .collect()
            .await;

        println!("[INFO] Downloaded and parsed {} trades in {:.2}s", 
                 results.len(), 
                 download_start.elapsed().as_secs_f32());
        println!("[INFO] Total time for prefix '{}': {:.2}s", 
                 prefix, 
                 start_time.elapsed().as_secs_f32());

        Ok(results)
    }

    async fn download_and_parse_blob(
        container_client: &ContainerClient,
        blob_name: &str,
    ) -> Result<TradeData> {
        let blob_client = container_client.blob_client(blob_name);

        // Download blob content
        let response = blob_client
            .get_content()
            .await
            .with_context(|| format!("Failed to download blob: {}", blob_name))?;

        // Parse JSON
        let trade: TradeData = serde_json::from_slice(&response)
            .with_context(|| format!("Failed to parse JSON from blob: {}", blob_name))?;

        Ok(trade)
    }

    async fn fetch_all_trades(&self, prefixes: &[&str]) -> Result<Vec<TradeData>> {
        println!("[INFO] Fetching trades from {} prefixes", prefixes.len());
        let start_time = Instant::now();

        // Process prefixes in parallel
        let mut futures = Vec::new();

        for &prefix in prefixes {
            if !prefix.is_empty() {
                let service = self.clone();
                futures.push(tokio::spawn(async move {
                    service.load_trades_from_folder(prefix).await
                }));
            }
        }

        // Collect results from all prefixes
        let mut all_trades = Vec::new();
        for future in futures {
            match future.await {
                Ok(Ok(trades)) => all_trades.extend(trades),
                Ok(Err(e)) => eprintln!("[ERROR] Failed to load prefix: {}", e),
                Err(e) => eprintln!("[ERROR] Task panicked: {}", e),
            }
        }

        println!("[INFO] Fetched {} total trades in {:.2}s", 
                 all_trades.len(), 
                 start_time.elapsed().as_secs_f32());

        Ok(all_trades)
    }
}

impl Clone for AzureBlobService {
    fn clone(&self) -> Self {
        Self {
            container_client: self.container_client.clone(),
        }
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    // Initialize logging
    tracing_subscriber::fmt::init();

    println!("[INFO] Starting Azure Blob download benchmark...");

    let start_time = Instant::now();

    // Initialize service
    let service = AzureBlobService::new().await
        .context("Failed to initialize Azure Blob Service")?;

    // Read prefixes from environment or use defaults
    let prefix_opt = env::var("AZURE_PREFIX_OPT").unwrap_or_else(|_| "options/".to_string());
    let prefix_fut = env::var("AZURE_PREFIX_FUT").unwrap_or_else(|_| "futures/".to_string());

