    println!("[STATS] Total time: {:.2} seconds", start_time.elapsed().as_secs_f32());

    // Optional: Display first few trades
    if !trades.is_empty() {
        println!("\n[DEBUG] Sample trade (first of {}):", trades.len());
        println!("{:#?}", trades[0]);
    }

