//! to replace atomic fetch_add on thumbv6m-none-eabi

#![no_std]
#![no_main]

use core::sync::atomic::{AtomicUsize, Ordering};

// For embedded targets, we need a critical section implementation
#[cfg(all(target_arch = "arm", target_os = "none"))]
use cortex_m::interrupt;

struct Channel {
    channel_index: AtomicUsize,
    max_channels: usize,
}

impl Channel {
    fn new(max_channels: usize) -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
            max_channels,
        }
    }

    /// Gets the next available channel index, wrapping around when reaching max_channels
    /// This is the correct implementation using critical sections with proper ordering
    fn get_next_index(&self) -> usize {
        critical_section::with(|_| {
            // Load with Acquire ordering to ensure all previous writes from other
            // critical sections are visible before we read the value
            let old_val = self.channel_index.load(Ordering::Acquire);

            // Calculate new value with wrap-around
            let new_val = if old_val + 1 >= self.max_channels {
                0
            } else {
                old_val + 1
            };

            // Store with Release ordering to ensure our write is visible to
            // subsequent critical sections before we exit
            self.channel_index.store(new_val, Ordering::Release);

            old_val
        })
    }

    /// ALTERNATIVE: If you need sequential consistency (strongest ordering)
    /// This provides the same guarantees as the original fetch_add(1, Ordering::SeqCst)
    fn get_next_index_seqcst(&self) -> usize {
        critical_section::with(|_| {
            let old_val = self.channel_index.load(Ordering::SeqCst);

            let new_val = if old_val + 1 >= self.max_channels {
                0
            } else {
                old_val + 1
            };

            self.channel_index.store(new_val, Ordering::SeqCst);

            old_val
        })
    }
}

