// --- Validated Json Extractor ---
#[derive(Debug)]
pub struct ValidatedJson<T>(pub T);

impl<S, T> FromRequestParts<S> for ValidatedJson<T>
where
    T: for<'de> Deserialize<'de> + Validate,
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        // Extract Json<T> from request body
        let Json(value) = Json::<T>::from_request_parts(parts, state).await
            .map_err(|_| AppError::InvalidInput)?;

        // Validate the extracted value
        value.validate().map_err(|e| AppError::Validation(e.to_string()))?;

        Ok(ValidatedJson(value))
    }
}

// --- ApiVersionHeader Extractor ---
#[derive(Debug, Clone)]
pub struct ApiVersionHeader(pub String);

impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let version = parts
            .headers
            .get("x-api-version")
            .ok_or(AppError::MissingHeader)?
            .to_str()
            .map_err(|_| AppError::InvalidHeader)?
            .to_string();

        Ok(ApiVersionHeader(version))
    }
}

// --- AccessClaims Extractor ---
#[derive(Debug, Clone)]
pub struct AccessClaims {
    pub sub: String,
    pub admin: bool,
}

impl<S> FromRequestParts<S> for AccessClaims
where
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // In a real app, you'd decode JWT from headers
        let token = parts
            .headers
            .get("authorization")
            .ok_or(AppError::MissingAuth)?
            .to_str()
            .map_err(|_| AppError::InvalidAuth)?;

        // Simplified: just parse user from "Bearer {user_id}"
        let user_id = token.replace("Bearer ", "");

        Ok(AccessClaims {
            sub: user_id.clone(),
            admin: user_id == "admin",
        })
    }
}

impl AccessClaims {
    pub fn validate_role_admin(&self) -> Result<(), AppError> {
        if !self.admin {
            return Err(AppError::Unauthorized);
        }
        Ok(())
    }
}

// --- Error Handling ---
#[derive(Debug)]
enum AppError {
    InvalidInput,
    Validation(String),
    MissingHeader,
    InvalidHeader,
    MissingAuth,
    InvalidAuth,
    Unauthorized,
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            AppError::InvalidInput => (StatusCode::BAD_REQUEST, "Invalid input".to_string()),
            AppError::Validation(msg) => (StatusCode::BAD_REQUEST, msg),
            AppError::MissingHeader => (StatusCode::BAD_REQUEST, "Missing x-api-version header".to_string()),
            AppError::InvalidHeader => (StatusCode::BAD_REQUEST, "Invalid x-api-version header".to_string()),
            AppError::MissingAuth => (StatusCode::UNAUTHORIZED, "Missing authorization header".to_string()),
            AppError::InvalidAuth => (StatusCode::UNAUTHORIZED, "Invalid authorization header".to_string()),
            AppError::Unauthorized => (StatusCode::FORBIDDEN, "Insufficient permissions".to_string()),
        };

        (status, Json(serde_json::json!({ "error": message }))).into_response()
    }
}

// --- Handler ---
#[axum::debug_handler]
async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(_state): State<SharedState>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> Result<impl IntoResponse, AppError> {
    tracing::debug!("api version: {}", api_version);

    if access_claims.sub != revoke_user.user_id {
        // only admin can revoke tokens of other users
        access_claims.validate_role_admin()?;
