#[derive(Error, Debug)]
pub enum MetricsError {
    #[error("Failed to connect to statsd socket after {retries} retries: {cause}")]
    ConnectionFailed { retries: usize, cause: String },
    #[error("Failed to send metric: {0}")]
    SendError(#[from] cadence::MetricError),
