pub fn create_statsd_client(socket_path: &str) -> Result<Arc<StatsdClient>, MetricsError> {
    let mut retries: usize = 0;

    let socket_path = socket_path.to_string();
    let unix_sink = loop {
        match std::os::unix::net::UnixDatagram::unbound() {
            Ok(sock) => {
                match sock.connect(&socket_path) {
                    Ok(_) => {
                        tracing::info!("Connected to Datadog socket at {}", socket_path);
                        break BufferedUnixMetricSink::from(&socket_path, sock);
                    }
                    Err(e) => {
                        tracing::warn!(
                            "Datadog socket not ready at {}: {}, retrying...",
                            socket_path,
                            e
                        );
                        std::thread::sleep(Duration::from_secs(2));
                        retries += 1;
                    }
                }
            }
            Err(e) => {
                tracing::error!("Failed to create Unix datagram: {}", e);
                retries += 1;
                std::thread::sleep(Duration::from_secs(2));
            }
        }

        if retries >= MAX_RETRIES {
            return Err(MetricsError::ConnectionFailed {
                retries,
                cause: format!("Failed to connect to socket at {}", socket_path),
            });
        }
    };

    // Use a reasonable queue size (default is 1024)
    let queuing_sink = QueuingMetricSink::with_capacity(unix_sink, 2048);

    let client = StatsdClient::builder(METRIC_PREFIX, queuing_sink)
        .with_error_handler(|e| {
