use std::marker::PhantomData;
use thiserror::Error;
use winnow::stream::Located;
use winnow::Partial;

// Simplified versions of your types
#[derive(Debug)]
struct SymbolInterner;

#[derive(Debug)]
struct Filename<'e> {
    name: &'e str,
}

impl<'e> Filename<'e> {
    fn new(name: &'e str) -> Self {
        Self { name }
    }
}

#[derive(Debug)]
struct State<'e> {
    filename: Filename<'e>,
    symbol_interner: &'e SymbolInterner,
}

// Use Located instead of LocatingSlice for simplicity
type SStream<'i, 'e> = Partial<Located<&'i str, State<'e>>>;

// Your Cons type
#[derive(Debug, PartialEq)]
struct Cons<'e> {
    value: &'e str,
}

// Error type
#[derive(Error, Debug)]
enum ContextError {
    #[error("Parse error")]
    ParseError,
}

type ModalResult<'e, T> = Result<T, ContextError>;

// Simplified ModalParser trait
pub trait ModalParser<I, O, E> {
    fn parse(&self, input: I) -> Result<O, E>;
}

// Parser function
fn parse_cons<'i, 'e>(input: &mut SStream<'i, 'e>) -> ModalResult<'e, Cons<'e>> {
    // Simplified parsing logic
    let remaining = input.checkpoint();
    if let Some(chunk) = input.next_slice(1) {
        Ok(Cons { value: chunk })
    } else {
        *input = remaining;
        Err(ContextError::ParseError)
    }
}

// Implement ModalParser for function pointers
impl<'i, 'e, F, O, E> ModalParser<&mut SStream<'i, 'e>, O, E> for F
where
    F: Fn(&mut SStream<'i, 'e>) -> Result<O, E>,
{
    fn parse(&self, input: &mut SStream<'i, 'e>) -> Result<O, E> {
        self(input)
    }
}

// Test helper function - Fixed version
pub fn test_input_output<'i, ExOut, P, POut, E>(
    input: &'i str,
    expected_output: &ExOut,
    parser: P,
) where
    ExOut: Debug,
    POut: PartialEq<ExOut> + Debug + 'static, // Added 'static bound
    E: Debug,
    // Key fix: Use higher-ranked trait bound correctly
    for<'e> P: ModalParser<&mut SStream<'i, 'e>, POut, E>,
{
    let symbol_interner = SymbolInterner;
    let filename = Filename::new("<test>");

    let state = State {
        filename,
        symbol_interner: &symbol_interner,
    };

    // Create the stream with the state
    let located = Located::new(input, state);
    let mut stream = Partial::new(located);

    match parser.parse(&mut stream) {
        Ok(parsed) => {
            println!("Testing:\n\tinput: {:?}\n\texpected output: {:?}\n\tactual output: {:?}", 
                     input, expected_output, parsed);
            assert_eq!(&parsed, expected_output);
        }
        Err(e) => {
            panic!(
                "Failed on:\n\tinput: {:?}\n\texpected output: {:?}\n\terror: {:?}",
                input, expected_output, e
            )
        }
    }
}

// Test function
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_cons_parser() {
        let expected_output = Cons { value: "a" };

        // The key insight: we need to use a function that can work with any lifetime 'e
        // parse_cons already has the right signature: fn(&mut SStream<'i, 'e>) -> Result<Cons<'e>, ContextError>
        // The HRTB in test_input_output ensures it works for any 'e we create inside the function
        test_input_output("abc", &expected_output, parse_cons);
    }

    // Another example with a different output type
    #[test]
    fn test_string_parser() {
        // Create a parser that returns a String (which doesn't depend on 'e)
        fn parse_string<'i, 'e>(input: &mut SStream<'i, 'e>) -> Result<String, ContextError> {
            if let Some(chunk) = input.next_slice(3) {
                Ok(chunk.to_string())
            } else {
                Err(ContextError::ParseError)
            }
        }

        let expected_output = "abc";
        test_input_output("abcdef", &expected_output, parse_string);
    }
}

fn main() {
    println!("Running parser tests...");

    // Demonstrate the fix
    let symbol_interner = SymbolInterner;
    let filename = Filename::new("<test>");
    let state = State {
        filename,
        symbol_interner: &symbol_interner,
    };

    let located = Located::new("test input", state);
    let mut stream = Partial::new(located);

    match parse_cons(&mut stream) {
        Ok(cons) => println!("Parsed: {:?}", cons),
        Err(e) => println!("Error: {:?}", e),
    }
}"
}
