/// A wrapper that keeps the connection alive as long as the Client is alive
struct ConnectionKeeper {
    // The Client is what we actually use
    client: Client,
    // The connection future must be kept alive
    // We pin it and drive it in the background
    _connection: Pin<Box<dyn std::future::Future<Output = ()> + Send>>,
}

impl ConnectionKeeper {
    pub async fn new(conn_str: &str) -> Result<Self, tokio_postgres::Error> {
        let (client, connection) = tokio_postgres::connect(conn_str, NoTls).await?;

        // Create a future that drives the connection
        let connection_future = async move {
            if let Err(e) = connection.await {
                eprintln!("Connection error: {e}");
            }
        };

        Ok(Self {
            client,
            _connection: Box::pin(connection_future),
        })
    }

    pub fn client(&self) -> &Client {
        &self.client
    }
}

