        if new_path_text.is_empty() {
            None
        } else {
            Some(ast::make::path_from_text(&new_path_text))
        }
    }

    fn reconstruct_use_tree(&self, new_path: ast::Path, inner_tree: Option<ast::UseTree>) -> Option<SyntaxNode> {
        match inner_tree {
            Some(inner) => {
                // We have a nested use tree (e.g., `vexide::devices::{smart, adi}`)
                match inner {
                    ast::UseTree::Group(group) => {
                        // Handle nested groups
                        let new_group = ast::make::use_tree_group(
                            new_path,
                            group.use_trees().collect(),
                        );
                        Some(new_group.syntax().clone())
                    }
                    _ => {
                        // For other nested trees, create a path use tree
                        let new_use_tree_path = ast::make::use_tree_path(new_path, Some(inner));
                        Some(new_use_tree_path.syntax().clone())
                    }
                }
            }
            None => {
                // Simple path or glob
                let new_use_tree = ast::make::use_tree_path(new_path, None);
                Some(new_use_tree.syntax().clone())
            }
        }
    }
}

// Helper functions to work with the AST
mod ast {
    pub use ra_ap_syntax::ast::*;

    pub mod make {
        use ra_ap_syntax::{ast, AstNode};

        pub fn path_from_text(text: &str) -> ast::Path {
            ast::Path::parse(text).unwrap().syntax().clone().try_into().unwrap()
        }

        pub fn use_tree_path(path: ast::Path, use_tree: Option<ast::UseTree>) -> ast::UseTree {
            let mut text = path.to_string();
            if let Some(inner) = use_tree {
                text.push_str("::");
                text.push_str(&inner.to_string());
            }
            ast::UseTree::parse(&text).unwrap().syntax().clone().try_into().unwrap()
        }

        pub fn use_tree_group(path: ast::Path, use_trees: Vec<ast::UseTree>) -> ast::UseTree {
            let mut text = path.to_string();
            text.push_str("::{");
            for (i, tree) in use_trees.iter().enumerate() {
                if i > 0 {
                    text.push_str(", ");
                }
                text.push_str(&tree.to_string());
            }
            text.push('}');
            ast::UseTree::parse(&text).unwrap().syntax().clone().try_into().unwrap()
        }
    }
}"
