async fn handle_request(req: Request<hyper::body::Incoming>) -> Result<Response<impl Body>, hyper::StatusCode> {
    // Get the file path from the request URI
    let path = req.uri().path();
    let mut file_path = PathBuf::from(".").join(&path[1..]); // Remove leading '/'

    // Security: Prevent directory traversal
    if file_path.components().any(|c| matches!(c, std::path::Component::ParentDir)) {
        return Err(StatusCode::FORBIDDEN);
