/// Helper function to create a no-op waker
fn noop_waker() -> Waker {
    // Define the vtable for a waker that does nothing
    static VTABLE: RawWakerVTable = RawWakerVTable::new(
        |clone_ptr| RawWaker::new(clone_ptr, &VTABLE), // clone
        |_| {}, // wake
        |_| {}, // wake_by_ref
        |_| {}, // drop
    );

    unsafe {
        Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE))
    }
}

/// Attempts to poll a future synchronously
/// Returns Ready if the future completes immediately, Pending otherwise
fn try_poll<F, X>(future: &mut Pin<Box<F>>) -> TryPollResult<X>
where
    F: Future<Output = X> + ?Sized,
{
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

