fn process_signed_data(signed_data: &SignedData) -> Result<(), Box<dyn std::error::Error>> {
    println!("Processing SignedData...");

    // Check for encapsulated content
    if let Some(content) = &signed_data.encap_content_info.econtent {
        println!("  Has encapsulated content ({} bytes)", content.len());

