                    }
                }
            }
            Err(_) => {
                println!("  Content is not an OCTET STRING");
            }
        }
    }

    Ok(())
}

// Helper function to decode from base64 string
fn decode_from_base64(base64_str: &str) -> Result<Vec<u8>, Box<dyn std::error::Error>> {
