#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::fmt::init();

    // Build our application with routes and middleware
    let app = Router::new()
        .route("/", get(root))
        .route("/websocket", get(websocket_handler))
        // Apply CORS for regular HTTP requests
        .layer(
            CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
                .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        )
        // Apply custom WebSocket origin middleware to specific routes
        .layer(middleware::from_fn(websocket_origin_middleware));

    // Run the server
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    info!("listening on {}", addr);
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}

// Root handler
async fn root() -> Html<&'static str> {
    Html("<h1>WebSocket Origin Test Server</h1>")
}

// WebSocket handler with manual origin check
async fn websocket_handler(
    ws: WebSocketUpgrade,
    // Extract Origin header manually
    TypedHeader(origin): TypedHeader<headers::Origin>,
) -> Result<Response, StatusCode> {
    // Convert origin to string for comparison
    let origin_str = origin.to_string();

    // Check if the origin matches our allowed origin
    if !is_allowed_origin(&origin_str) {
        return Err(StatusCode::FORBIDDEN);
    }

    info!("WebSocket connection from allowed origin: {}", origin_str);

    // Proceed with WebSocket upgrade
    Ok(ws.on_upgrade(|socket| handle_socket(socket)))
}

// Middleware that filters WebSocket requests by origin
async fn websocket_origin_middleware<B>(
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode> {
    // Only apply origin check to WebSocket upgrade requests
    if is_websocket_upgrade(&req) {
        // Get the Origin header
        let origin = req.headers().get(header::ORIGIN);

        match origin {
            Some(origin_value) => {
                // Convert to string for comparison
                let origin_str = origin_value.to_str().map_err(|_| StatusCode::BAD_REQUEST)?;

                // Check if the origin is allowed
                if !is_allowed_origin(origin_str) {
                    info!("Blocking WebSocket connection from origin: {}", origin_str);
                    return Err(StatusCode::FORBIDDEN);
                }
                info!("Allowing WebSocket connection from origin: {}", origin_str);
            }
            None => {
                // No Origin header present
                info!("Blocking WebSocket connection without Origin header");
                return Err(StatusCode::FORBIDDEN);
            }
        }
    }

    // Continue with the request
    Ok(next.run(req).await)
}

// Helper function to check if a request is a WebSocket upgrade
fn is_websocket_upgrade<B>(req: &Request<B>) -> bool {
    req.headers()
        .get(header::UPGRADE)
        .and_then(|value| value.to_str().ok())
        .map(|value| value.to_lowercase() == "websocket")
        .unwrap_or(false)
}

// Helper function to check if an origin is allowed
fn is_allowed_origin(origin: &str) -> bool {
    // List of allowed origins (can be extended)
    let allowed_origins = [
        "https://www.example.com",
        "https://example.com",
        // Add localhost for testing
        "http://localhost:8080",
        "http://127.0.0.1:8080",
    ];

    allowed_origins.contains(&origin)
}

// Handle WebSocket connection
async fn handle_socket(socket: axum::extract::ws::WebSocket) {
    let (mut sender, mut receiver) = socket.split();

    while let Some(Ok(message)) = receiver.next().await {
        if let axum::extract::ws::Message::Text(text) = message {
            info!("Received message: {}", text);

            // Echo the message back
            if sender.send(axum::extract::ws::Message::Text(text)).await.is_err() {
                break;
            }
        }
    }
}

// Optional: Example of using a custom extractor for cleaner handler code
#[derive(Debug)]
struct AllowedOrigin;

impl<S> axum::extract::FromRequestParts<S> for AllowedOrigin
where
    S: Send + Sync,
{
    type Rejection = StatusCode;

    async fn from_request_parts(
        parts: &mut axum::http::request::Parts,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        if is_websocket_upgrade(&Request::from_parts(parts.clone(), ())) {
            let origin = parts.headers.get(header::ORIGIN);

            match origin {
                Some(origin_value) => {
                    let origin_str = origin_value.to_str().map_err(|_| StatusCode::BAD_REQUEST)?;

                    if is_allowed_origin(origin_str) {
                        Ok(AllowedOrigin)
                    } else {
                        Err(StatusCode::FORBIDDEN)
                    }
                }
                None => Err(StatusCode::FORBIDDEN),
            }
        } else {
            // Not a WebSocket request, allow it
            Ok(AllowedOrigin)
        }
    }
}

// Alternative handler using the custom extractor
async fn websocket_handler_with_extractor(
    ws: WebSocketUpgrade,
    _allowed: AllowedOrigin, // This extractor will reject if origin is not allowed
) -> Response {
    ws.on_upgrade(|socket| handle_socket(socket))
}"
