fn main() -> io::Result<()> {
    // Spawn child process (using bash as example REPL)
    let mut child = Command::new("bash")
        .arg("--norc")
        .arg("--noprofile")
        .arg("-i")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    let child_stdin = child.stdin.take().unwrap();
    let child_stdout = child.stdout.take().unwrap();
    let child_stderr = child.stderr.take().unwrap();

    // Shared state between threads
    let shared = Arc::new(Mutex::new(SharedState {
        child_output: String::new(),
        prompt: "> ".to_string(),
    }));

    // Channel for sending commands to child process
    let (tx, mut rx) = mpsc::channel::<String>(100);
    let shared_clone = shared.clone();
    let tx_clone = tx.clone();

    // Thread to handle child process output
    thread::spawn(move || {
        let rt = Runtime::new().unwrap();
        rt.block_on(async {
            let stdout_reader = BufReader::new(child_stdout);
            let mut stdout_lines = FramedRead::new(stdout_reader, LinesCodec::new());
            let stderr_reader = BufReader::new(child_stderr);
            let mut stderr_lines = FramedRead::new(stderr_reader, LinesCodec::new());

