                    line = stdout_lines.next() => {
                        if let Some(Ok(line)) = line {
                            let mut state = shared_clone.lock().unwrap();
                            state.child_output.push_str(&line);
                            state.child_output.push('\n');
                            // Update prompt based on child output (simple heuristic)
                            if line.ends_with('>') || line.ends_with('$') || line.ends_with('#') {
                                state.prompt = line.clone();
                            }
                        } else {
                            break;
                        }
                    }
                    line = stderr_lines.next() => {
                        if let Some(Ok(line)) = line {
                            let mut state = shared_clone.lock().unwrap();
                            state.child_output.push_str(&format!("[stderr] {}\n", line));
                        } else {
                            break;
                        }
                    }
                }
            }
        });
    });

    // Thread to send commands to child process
    let mut child_stdin = child_stdin;
    thread::spawn(move || {
        let rt = Runtime::new().unwrap();
        rt.block_on(async {
            while let Some(cmd) = rx.recv().await {
                writeln!(child_stdin, "{}", cmd).ok();
            }
        });
    });

    // Main thread with async event handling
    let rt = Runtime::new().unwrap();
    rt.block_on(async {
        let mut rl = Editor::<()>::new();
        let mut events = EventStream::new();
        let mut input = String::new();
        let mut cursor_pos = 0;

        terminal::enable_raw_mode().unwrap();

        print_prompt(&shared);
        print_input_line(&input, cursor_pos, &shared);

