                    match event {
                        Event::Key(KeyEvent { code, modifiers, .. }) => {
                            match code {
                                KeyCode::Char('c') if modifiers == KeyModifiers::CONTROL => {
                                    tx_clone.send("\x03".to_string()).await.ok();
                                    break;
                                }
                                KeyCode::Enter => {
                                    if !input.is_empty() {
                                        tx_clone.send(input.clone()).await.ok();
                                        rl.add_history_entry(&input);
                                        input.clear();
                                        cursor_pos = 0;
                                        print_prompt(&shared);
                                    }
                                }
                                KeyCode::Char(c) => {
                                    input.insert(cursor_pos, c);
                                    cursor_pos += 1;
                                    print_input_line(&input, cursor_pos, &shared);
                                }
                                KeyCode::Backspace => {
                                    if cursor_pos > 0 {
                                        input.remove(cursor_pos - 1);
                                        cursor_pos -= 1;
                                        print_input_line(&input, cursor_pos, &shared);
                                    }
                                }
                                KeyCode::Delete => {
                                    if cursor_pos < input.len() {
                                        input.remove(cursor_pos);
                                        print_input_line(&input, cursor_pos, &shared);
                                    }
                                }
                                KeyCode::Left => {
