    print!("\r\x1b[K");

    // Print accumulated child output
    if !state.child_output.is_empty() {
        print!("{}", state.child_output);
        state.child_output.clear();
    }

    // Print prompt and current input
    print!("{}{}", state.prompt, input);

    // Position cursor correctly
    let total_len = state.prompt.len() + cursor_pos;
    print!("\r\x1b[{}C", total_len);

    io::stdout().flush().unwrap();
}

fn refresh_display(input: &str, cursor_pos: usize, shared: &Arc<Mutex<SharedState>>) {
    let state = shared.lock().unwrap();
    if state.child_output.is_empty() {
        return;
    }

    // Clear from cursor to end of screen
    print!("\x1b[J");

    // Print new child output
    print!("{}", state.child_output);

    // Reprint prompt and input
    print!("{}{}", state.prompt, input);

    // Reposition cursor
    let total_len = state.prompt.len() + cursor_pos;
    print!("\r\x1b[{}C", total_len);

    io::stdout().flush().unwrap();

    // Clear the stored output after printing
    unsafe {
        // We need mutable access but we already have a lock
        let state = &mut *Arc::as_ptr(&shared) as *mut SharedState;
        (*state).child_output.clear();
    }
}

fn move_cursor(delta: i32) {
    if delta > 0 {
        print!("\x1b[{}C", delta);
    } else {
        print!("\x1b[{}D", -delta);
