fn ray_from_cursor(
    cursor_pos: Vec2,
    camera: &Camera,
    camera_transform: &GlobalTransform,
    window: &Window,
) -> Ray {
    // Convert cursor position to normalized device coordinates (NDC)
    let window_size = Vec2::new(window.width(), window.height());
    let ndc = (cursor_pos / window_size) * 2.0 - Vec2::ONE;
    let ndc = Vec3::new(ndc.x, ndc.y, 0.0);

    // Get camera view and projection matrices
    let view_matrix = camera_transform.compute_matrix();
    let projection_matrix = camera.projection_matrix();

    // Convert NDC to world space
    let ndc_to_world = view_matrix.inverse() * projection_matrix.inverse();
    let world_near = ndc_to_world.project_point3(ndc);

    // For direction, use a point further along the ray
    let ndc_far = Vec3::new(ndc.x, ndc.y, 1.0);
    let world_far = ndc_to_world.project_point3(ndc_far);

    Ray {
        origin: world_near,
        direction: (world_far - world_near).normalize(),
    }
}

fn ray_intersects_cube(ray: &Ray, cube_transform: &GlobalTransform) -> Option<HitInfo> {
    let cube_rotation = cube_transform.rotation();
    let cube_position = cube_transform.translation();
    let cube_half_size = Vec3::splat(0.5);

    // Transform ray to cube's local space
    let inv_rotation = cube_rotation.inverse();
    let local_ray_origin = inv_rotation * (ray.origin - cube_position);
    let local_ray_direction = inv_rotation * ray.direction;

    // Ray-AABB intersection in local space (cube is centered at origin, size 1x1x1)
    let inv_dir = Vec3::new(
        1.0 / local_ray_direction.x,
        1.0 / local_ray_direction.y,
        1.0 / local_ray_direction.z,
    );

    let t1 = (-cube_half_size.x - local_ray_origin.x) * inv_dir.x;
    let t2 = (cube_half_size.x - local_ray_origin.x) * inv_dir.x;
    let t3 = (-cube_half_size.y - local_ray_origin.y) * inv_dir.y;
    let t4 = (cube_half_size.y - local_ray_origin.y) * inv_dir.y;
    let t5 = (-cube_half_size.z - local_ray_origin.z) * inv_dir.z;
    let t6 = (cube_half_size.z - local_ray_origin.z) * inv_dir.z;

    let tmin = t1.min(t2).max(t3.min(t4)).max(t5.min(t6));
    let tmax = t1.max(t2).min(t3.max(t4)).min(t5.max(t6));

    if tmax < 0.0 || tmin > tmax {
        return None;
    }

    let t = if tmin < 0.0 { tmax } else { tmin };

    if t < 0.0 {
        return None;
    }

    // Calculate hit point in local space
    let local_hit_point = local_ray_origin + local_ray_direction * t;

    // Calculate normal in local space (which face was hit)
    let eps = 0.001;
    let local_normal = if (local_hit_point.x - cube_half_size.x).abs() < eps {
        Vec3::X
    } else if (local_hit_point.x + cube_half_size.x).abs() < eps {
        Vec3::NEG_X
    } else if (local_hit_point.y - cube_half_size.y).abs() < eps {
        Vec3::Y
    } else if (local_hit_point.y + cube_half_size.y).abs() < eps {
        Vec3::NEG_Y
    } else if (local_hit_point.z - cube_half_size.z).abs() < eps {
        Vec3::Z
    } else {
        Vec3::NEG_Z
    };

    // Transform back to world space
    let world_hit_point = cube_position + cube_rotation * local_hit_point;
    let world_normal = cube_rotation * local_normal;

    Some(HitInfo {
        position: world_hit_point,
        normal: world_normal,
        distance: t,
    })
}
